import React, { useState } from 'react'
import { useSelector } from 'react-redux'
import { motion, AnimatePresence } from 'framer-motion'
import { Mail, Lock, User, Eye, EyeOff, ArrowRight, Sparkles } from 'lucide-react'
import { useAuth } from '../../hooks/useAuth'
import { Button } from '../ui/Button'
import { Input } from '../ui/Input'
import toast from 'react-hot-toast'

const ROLE_OPTIONS = [
  { value: 'user',             label: 'Tenant',           emoji: '🎓' },
  { value: 'landlord',         label: 'Landlord',         emoji: '🏠' },
  { value: 'service_provider', label: 'Service Provider', emoji: '🍱' },
]

export const AuthGateModal = () => {
  const { user, signIn, signUp, signInWithGoogle } = useAuth()
  const { loading } = useSelector(s => s.auth)

  const [tab, setTab] = useState('login')
  const [formLoading, setFormLoading] = useState(false)
  const [googleLoading, setGoogleLoading] = useState(false)
  const [showPass, setShowPass] = useState(false)
  const [selectedRole, setSelectedRole] = useState('user')
  const [form, setForm] = useState({ name: '', email: '', password: '' })
  const [errors, setErrors] = useState({})

  if (user || loading) return null

  const validate = () => {
    const e = {}
    if (tab === 'signup' && !form.name.trim()) e.name = 'Name required'
    if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) e.email = 'Valid email required'
    if (form.password.length < 8) e.password = 'Min 8 characters'
    setErrors(e)
    return !Object.keys(e).length
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!validate()) return
    setFormLoading(true)
    try {
      if (tab === 'login') {
        await signIn({ email: form.email, password: form.password })
        toast.success('Welcome back!')
      } else {
        await signUp({ email: form.email, password: form.password, name: form.name, role: selectedRole })
        toast.success('Account created!')
      }
    } catch (err) {
      toast.error(err.message || 'Something went wrong')
    } finally {
      setFormLoading(false)
    }
  }

  const handleGoogle = async () => {
    setGoogleLoading(true)
    try {
      await signInWithGoogle()
    } catch (err) {
      toast.error(err.message || 'Google sign-in failed')
      setGoogleLoading(false)
    }
  }

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center">
      {/* Backdrop */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.1 }}
        className="absolute inset-0 bg-black/50 backdrop-blur-md" 
      />

      {/* Modal */}
      <motion.div
        initial={{ opacity: 0, scale: 0.96, y: 12 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        transition={{ duration: 0.35, ease: 'easeOut' }}
        className="relative w-full max-w-sm mx-4 bg-white rounded-xl shadow-2xl overflow-hidden"
      >
        {/* Top gradient bar */}
        <div className="h-1 w-full bg-gradient-to-r from-[#CA3433] to-rose-400" />

        <div className="px-6 pt-5 pb-5">
          {/* Logo row */}
          <div className="flex items-center gap-2 mb-4">
            <div className="w-8 h-8 rounded-lg bg-white border-2 border-[#CA3433] shadow-md flex items-center justify-center font-bold rotate-3 overflow-hidden">
                <div className="-rotate-3 flex items-center justify-center translate-y-0.5">
                  <span className="text-[#CA3433] text-[16px] font-black leading-none">G</span>
                  <span className="text-[#CA3433] text-[11px] font-black leading-none -ml-0.5 mb-1.5">E</span>
                </div>
            </div>
            <span className="text-base font-black text-gray-900 tracking-tight">GoEazy<span className="text-[#CA3433]">.</span></span>
            <span className="ml-auto text-[9px] font-bold text-gray-400 uppercase tracking-widest bg-gray-100 px-2 py-0.5 rounded-full">Members Only</span>
          </div>

          {/* Tabs */}
          <div className="flex gap-1 p-0.5 bg-gray-100 rounded-lg mb-4">
            {['login', 'signup'].map(t => (
              <button
                key={t}
                onClick={() => { setTab(t); setErrors({}) }}
                className={`flex-1 py-1.5 rounded-md text-xs font-bold transition-all ${
                  tab === t ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-400 hover:text-gray-600'
                }`}
              >
                {t === 'login' ? 'Sign In' : 'Sign Up'}
              </button>
            ))}
          </div>

          <form onSubmit={handleSubmit}>
            <AnimatePresence mode="wait">
              <motion.div
                key={tab}
                initial={{ opacity: 0, x: 8 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -8 }}
                transition={{ duration: 0.15 }}
                className="space-y-2.5"
              >
                {tab === 'signup' && (
                  <Input
                    placeholder="Full Name"
                    leftIcon={<User size={13} />}
                    value={form.name}
                    onChange={e => { setForm(f => ({ ...f, name: e.target.value })); setErrors(v => ({ ...v, name: '' })) }}
                    error={errors.name}
                    className="text-sm py-2"
                  />
                )}

                <Input
                  type="email"
                  placeholder="Email address"
                  leftIcon={<Mail size={13} />}
                  value={form.email}
                  onChange={e => { setForm(f => ({ ...f, email: e.target.value })); setErrors(v => ({ ...v, email: '' })) }}
                  error={errors.email}
                  className="text-sm py-2"
                />

                <Input
                  type={showPass ? 'text' : 'password'}
                  placeholder="Password (min 8 chars)"
                  leftIcon={<Lock size={13} />}
                  rightIcon={
                    <button type="button" onClick={() => setShowPass(!showPass)} className="cursor-pointer text-gray-400">
                      {showPass ? <EyeOff size={13} /> : <Eye size={13} />}
                    </button>
                  }
                  value={form.password}
                  onChange={e => { setForm(f => ({ ...f, password: e.target.value })); setErrors(v => ({ ...v, password: '' })) }}
                  error={errors.password}
                  className="text-sm py-2"
                />

                {/* Role Selector — compact pill row for signup */}
                {tab === 'signup' && (
                  <div>
                    <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">I am a...</p>
                    <div className="flex gap-1.5">
                      {ROLE_OPTIONS.map(opt => (
                        <button
                          key={opt.value}
                          type="button"
                          onClick={() => setSelectedRole(opt.value)}
                          className={`flex-1 flex flex-col items-center gap-0.5 py-1 px-1 rounded-lg border-2 text-center transition-all ${
                            selectedRole === opt.value
                              ? 'border-[#CA3433] bg-red-50'
                              : 'border-gray-100 hover:border-gray-200'
                          }`}
                        >
                          <span className="text-base leading-none">{opt.emoji}</span>
                          <span className={`text-[9px] font-bold leading-tight ${selectedRole === opt.value ? 'text-[#CA3433]' : 'text-gray-500'}`}>
                            {opt.label}
                          </span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </motion.div>
            </AnimatePresence>

            <Button
              type="submit"
              variant="primary"
              className="w-full mt-3 bg-[#CA3433] shadow-lg shadow-red-500/20 rounded-lg py-2.5 text-sm font-bold group"
              loading={formLoading}
            >
              <span className="flex items-center justify-center gap-1.5">
                {tab === 'login' ? 'Sign In' : 'Create Account'}
                <ArrowRight size={15} className="group-hover:translate-x-0.5 transition-transform" />
              </span>
            </Button>
          </form>

          {/* Divider */}
          <div className="relative flex items-center gap-2 my-3">
            <div className="flex-1 h-px bg-gray-100" />
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">or</span>
            <div className="flex-1 h-px bg-gray-100" />
          </div>

          {/* Google */}
          <button
            onClick={handleGoogle}
            disabled={googleLoading}
            className="w-full flex items-center justify-center gap-2.5 py-2.5 border border-gray-200 rounded-lg text-sm font-semibold text-gray-700 hover:bg-gray-50 transition-all"
          >
            {googleLoading ? (
              <div className="w-4 h-4 border-2 border-gray-300 border-t-[#CA3433] rounded-full animate-spin" />
            ) : (
              <svg width="16" height="16" viewBox="0 0 24 24">
                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="#FBBC05" d="M5.84 14.1c-.22-.66-.35-1.36-.35-2.1s.13-1.44.35-2.1V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.83z"/>
                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.83c.87-2.6 3.3-4.52 6.16-4.52z"/>
              </svg>
            )}
            Continue with Google
          </button>

          <p className="text-center text-[10px] text-gray-400 mt-3 leading-relaxed">
            By continuing, you agree to our <span className="text-[#CA3433] font-semibold">Terms</span> & <span className="text-[#CA3433] font-semibold">Privacy Policy</span>
          </p>
        </div>
      </motion.div>
    </div>
  )
}

import React, { useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { useNavigate } from 'react-router-dom'
import { Mail, Lock, User, Eye, EyeOff, Home, GraduationCap, Utensils } from 'lucide-react'
import { Modal } from '../ui/Modal'
import { Button } from '../ui/Button'
import { Input } from '../ui/Input'
import { closeAuthModal } from '../../store/authSlice'
import { useAuth } from '../../hooks/useAuth'
import toast from 'react-hot-toast'

const ROLE_OPTIONS = [
  { value: 'user',             label: 'Student / Professional', icon: <GraduationCap size={20} className="text-brand-500" /> },
  { value: 'landlord',         label: 'Landlord / Owner',        icon: <Home size={20} className="text-brand-500" /> },
  { value: 'service_provider', label: 'Service Provider 🍱',    icon: <Utensils size={20} className="text-brand-500" /> },
]

export const AuthModal = () => {
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const { authModalOpen, authModalTab } = useSelector(s => s.auth)
  const { signIn, signUp, signInWithGoogle } = useAuth()

  const [tab, setTab] = useState(authModalTab)
  const [loading, setLoading] = useState(false)
  const [googleLoading, setGoogleLoading] = useState(false)
  const [showPass, setShowPass] = useState(false)
  const [selectedRole, setSelectedRole] = useState('user')
  const [form, setForm] = useState({ name: '', email: '', password: '' })
  const [errors, setErrors] = useState({})

  React.useEffect(() => { setTab(authModalTab) }, [authModalTab])

  const validate = () => {
    const e = {}
    if (tab === 'signup' && !form.name.trim()) e.name = 'Name is required'
    if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) e.email = 'Valid email required'
    if (form.password.length < 8) e.password = 'Min 8 characters'
    setErrors(e)
    return !Object.keys(e).length
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!validate()) return
    setLoading(true)
    try {
      if (tab === 'login') {
        await signIn({ email: form.email, password: form.password })
        toast.success('Welcome back!')
        dispatch(closeAuthModal())
        
        const returnTo = localStorage.getItem('sb_return_to')
        if (returnTo) {
          navigate(returnTo)
          localStorage.removeItem('sb_return_to')
        }
      } else {
        await signUp({ email: form.email, password: form.password, name: form.name, role: selectedRole })
        toast.success('Account created! Check your email to confirm.')
        const returnTo = localStorage.getItem('sb_return_to')
        dispatch(closeAuthModal())
        if (selectedRole === 'landlord') {
          navigate('/landlord')
        } else if (selectedRole === 'service_provider') {
          navigate('/service-provider')
        } else if (returnTo) {
          navigate(returnTo)
          localStorage.removeItem('sb_return_to')
        } else {
          navigate('/dashboard')
        }
      }
    } catch (err) {
      toast.error(err.message || 'Something went wrong')
    } finally {
      setLoading(false)
    }
  }

  const handleGoogle = async () => {
    // Save current path to return back after OAuth redirect
    localStorage.setItem('sb_return_to', window.location.pathname + window.location.search)
    
    setGoogleLoading(true)
    try {
      await signInWithGoogle()
    } catch (err) {
      toast.error(err.message || 'Google sign-in failed')
      setGoogleLoading(false)
    }
  }

  return (
    <Modal open={authModalOpen} onClose={() => dispatch(closeAuthModal())} size="sm">
      {/* Tabs */}
      <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-4">
        {['login', 'signup'].map(t => (
          <button
            key={t}
            onClick={() => { setTab(t); setErrors({}) }}
            className={`flex-1 py-2 rounded-lg text-sm font-semibold capitalize transition-all ${
              tab === t ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {t === 'login' ? 'Sign In' : 'Sign Up'}
          </button>
        ))}
      </div>

      {/* Google OAuth */}
      <Button
        variant="secondary"
        size="lg"
        className="w-full mb-3"
        loading={googleLoading}
        onClick={handleGoogle}
        leftIcon={
          <svg width="20" height="20" viewBox="0 0 24 24">
            <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
            <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
            <path fill="#FBBC05" d="M5.84 14.1c-.22-.66-.35-1.36-.35-2.1s.13-1.44.35-2.1V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.83z"/>
            <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.83c.87-2.6 3.3-4.52 6.16-4.52z"/>
          </svg>
        }
      >
        Continue with Google
      </Button>

      <div className="relative flex items-center gap-3 mb-3">
        <div className="flex-1 h-px bg-gray-200" />
        <span className="text-xs text-gray-400 font-medium">or continue with email</span>
        <div className="flex-1 h-px bg-gray-200" />
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        {tab === 'signup' && (
          <Input
            id="signup-name"
            name="name"
            label="Full Name"
            placeholder="Priya Sharma"
            leftIcon={<User size={16} />}
            value={form.name}
            onChange={e => { setForm(f => ({ ...f, name: e.target.value })); setErrors(v => ({ ...v, name: '' })) }}
            error={errors.name}
            autoComplete="name"
          />
        )}

        <Input
          id={`${tab}-email`}
          name="email"
          label="Email"
          type="email"
          placeholder="you@example.com"
          leftIcon={<Mail size={16} />}
          value={form.email}
          onChange={e => { setForm(f => ({ ...f, email: e.target.value })); setErrors(v => ({ ...v, email: '' })) }}
          error={errors.email}
          autoComplete="email"
        />

        <Input
          id={`${tab}-password`}
          name="password"
          label="Password"
          type={showPass ? 'text' : 'password'}
          placeholder={tab === 'signup' ? 'Min 8 characters' : '••••••••'}
          leftIcon={<Lock size={16} />}
          rightIcon={
            <button type="button" onClick={() => setShowPass(v => !v)} className="cursor-pointer">
              {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          }
          value={form.password}
          onChange={e => { setForm(f => ({ ...f, password: e.target.value })); setErrors(v => ({ ...v, password: '' })) }}
          error={errors.password}
          autoComplete={tab === 'signup' ? 'new-password' : 'current-password'}
        />

        {/* Role Selector (Sign Up only) */}
        {tab === 'signup' && (
          <div>
            <p className="text-sm font-semibold text-gray-700 mb-2">I am a...</p>
            <div className="grid grid-cols-1 gap-2">
              {ROLE_OPTIONS.map(opt => (
                <button
                  key={opt.value}
                  type="button"
                  onClick={() => setSelectedRole(opt.value)}
                  className={`px-4 py-2.5 rounded-xl border-2 text-left transition-all flex items-center gap-3 ${
                    selectedRole === opt.value
                      ? 'border-[#CA3433] bg-red-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <span className="text-lg">{opt.icon}</span>
                  <p className="text-sm font-semibold text-gray-900">{opt.label}</p>
                </button>
              ))}
            </div>
          </div>
        )}

        <Button type="submit" variant="primary" size="lg" className="w-full shadow-lg shadow-[#CA3433]/20" loading={loading}>
          {tab === 'login' ? 'Sign In' : 'Create Account'}
        </Button>
      </form>

    </Modal>
  )
}

import React, { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { 
  ChevronRight, User, Briefcase, 
  Home, Building2, School, Hotel,
  Check, Sparkles, MapPin, IndianRupee
} from 'lucide-react'
import { PROPERTY_TYPES, CITIES } from '../../utils/constants'
import { Button } from '../ui/Button'
import { useAuth } from '../../hooks/useAuth'
import toast from 'react-hot-toast'

const QUIZ_STEPS = [
  {
    id: 'persona',
    title: 'Welcome to GoEazy!',
    subtitle: 'Who are you?',
    options: [
      { id: 'student', label: 'Student', icon: School, desc: 'Looking for budget-friendly PGs or Hostels near campus.' },
      { id: 'professional', label: 'Professional', icon: Briefcase, desc: 'Searching for peaceful flats or rooms near work.' }
    ]
  },
  {
    id: 'type',
    title: 'Your Vibe',
    subtitle: 'What kind of stay do you prefer?',
    options: PROPERTY_TYPES.map(t => ({ 
      id: t, 
      label: t, 
      icon: t === 'Room' ? Home : t === 'Flat' ? Building2 : t === 'Hostel' ? Hotel : User 
    }))
  },
  {
    id: 'city',
    title: 'The Where',
    subtitle: 'Which city are you moving to?',
    cities: CITIES
  },
  {
    id: 'budget',
    title: 'The Budget',
    subtitle: 'What is your monthly budget?',
    ranges: [
      { id: 'budget', label: 'Budget Friendly', range: [0, 8000], desc: 'Below ₹8,000' },
      { id: 'mid', label: 'Mid-Range', range: [8000, 15000], desc: '₹8,000 - ₹15,000' },
      { id: 'premium', label: 'Premium', range: [15000, 25000], desc: '₹15,000 - ₹25,000' },
      { id: 'luxury', label: 'Luxury', range: [25000, 100000], desc: '₹25,000+' }
    ]
  }
]

export const OnboardingQuiz = () => {
  const { user, profile, updateProfile } = useAuth()
  const [isOpen, setIsOpen] = useState(false)
  const [step, setStep] = useState(0)
  const [saving, setSaving] = useState(false)
  const [selections, setSelections] = useState({
    persona: '',
    type: '',
    city: '',
    budget: null
  })

  // Open quiz only for Tenant (role='user') who haven't completed onboarding
  useEffect(() => {
    const isNewTenantUser = user && profile && profile.role === 'user' && !profile.onboarding_data
    if (isNewTenantUser) {
      setStep(0)
      setSelections({ persona: '', type: '', city: '', budget: null })
      setIsOpen(true)
    } else {
      setIsOpen(false)
    }
  }, [user, profile])

  // Listen for manual reset (from Search page Reset button)
  useEffect(() => {
    const handleReset = () => {
      setStep(0)
      setSelections({ persona: '', type: '', city: '', budget: null })
      setIsOpen(true)
    }
    window.addEventListener('goeazy_quiz_reset', handleReset)
    return () => window.removeEventListener('goeazy_quiz_reset', handleReset)
  }, [])

  const handleNext = () => {
    if (step < QUIZ_STEPS.length - 1) {
      setStep(s => s + 1)
    } else {
      finishQuiz()
    }
  }

  const finishQuiz = async () => {
    setSaving(true)
    try {
      await updateProfile({ onboarding_data: selections })
      setIsOpen(false)
      window.dispatchEvent(new Event('goeazy_recommendations_updated'))
      toast.success('Preferences saved! Here are your matches. 🎯')
    } catch (err) {
      console.error(err)
      toast.error('Failed to save preferences. Please try again.')
    } finally {
      setSaving(false)
    }
  }

  if (!isOpen) return null

  const currentStep = QUIZ_STEPS[step]

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
      {/* Backdrop — non-clickable, mandatory */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        className="absolute inset-0 bg-black/75 backdrop-blur-lg"
      />

      {/* Quiz Card */}
      <motion.div 
        initial={{ scale: 0.9, opacity: 0, y: 20 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        transition={{ type: 'spring', stiffness: 300, damping: 25 }}
        className="relative w-full max-w-lg bg-white rounded-2xl shadow-2xl overflow-hidden"
      >
        {/* Progress Bar */}
        <div className="absolute top-0 left-0 right-0 h-1.5 flex gap-0.5 bg-gray-100">
          {QUIZ_STEPS.map((_, i) => (
            <motion.div 
              key={i} 
              className="h-full bg-[#CA3433]"
              initial={{ width: 0 }}
              animate={{ width: i <= step ? `${100 / QUIZ_STEPS.length}%` : 0 }}
              transition={{ duration: 0.4 }}
            />
          ))}
        </div>

        <div className="p-8 sm:p-10 pt-10">
          <AnimatePresence mode="wait">
            <motion.div
              key={step}
              initial={{ x: 24, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: -24, opacity: 0 }}
              transition={{ duration: 0.25 }}
              className="space-y-6"
            >
              <div className="space-y-1">
                <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-red-50 text-[#CA3433] text-[10px] font-bold uppercase tracking-widest">
                  <Sparkles size={11} /> Step {step + 1} of {QUIZ_STEPS.length}
                </span>
                <h2 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight pt-1">{currentStep.title}</h2>
                <p className="text-gray-500 font-medium text-sm">{currentStep.subtitle}</p>
              </div>

              {/* Persona Step */}
              {currentStep.id === 'persona' && (
                <div className="grid grid-cols-1 gap-3">
                  {currentStep.options.map(opt => {
                    const Icon = opt.icon
                    const active = selections.persona === opt.id
                    return (
                      <button
                        key={opt.id}
                        onClick={() => setSelections(s => ({ ...s, persona: opt.id }))}
                        className={`group flex items-center gap-4 p-4 rounded-2xl border-2 transition-all text-left ${active ? 'border-[#CA3433] bg-red-50/50' : 'border-gray-100 hover:border-gray-200'}`}
                      >
                        <div className={`w-11 h-11 rounded-xl flex items-center justify-center ${active ? 'bg-[#CA3433] text-white' : 'bg-gray-50 text-gray-400 group-hover:bg-gray-100'}`}>
                          <Icon size={22} />
                        </div>
                        <div className="flex-1">
                          <h4 className={`font-bold ${active ? 'text-[#CA3433]' : 'text-gray-900'}`}>{opt.label}</h4>
                          <p className="text-xs text-gray-400">{opt.desc}</p>
                        </div>
                        {active && <Check size={18} className="text-[#CA3433]" />}
                      </button>
                    )
                  })}
                </div>
              )}

              {/* Property Type */}
              {currentStep.id === 'type' && (
                <div className="grid grid-cols-2 gap-3">
                  {currentStep.options.map(opt => {
                    const Icon = opt.icon
                    const active = selections.type === opt.id
                    return (
                      <button
                        key={opt.id}
                        onClick={() => setSelections(s => ({ ...s, type: opt.id }))}
                        className={`flex flex-col items-start gap-3 p-4 rounded-2xl border-2 transition-all ${active ? 'border-[#CA3433] bg-red-50/50' : 'border-gray-100 hover:border-gray-200'}`}
                      >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${active ? 'bg-[#CA3433] text-white' : 'bg-gray-50 text-gray-400'}`}>
                          <Icon size={20} />
                        </div>
                        <h4 className={`font-bold text-sm ${active ? 'text-[#CA3433]' : 'text-gray-900'}`}>{opt.label}</h4>
                      </button>
                    )
                  })}
                </div>
              )}

              {/* City */}
              {currentStep.id === 'city' && (
                <div className="grid grid-cols-2 gap-2 max-h-[220px] overflow-y-auto pr-1">
                  {currentStep.cities.map(city => {
                    const active = selections.city === city
                    return (
                      <button
                        key={city}
                        onClick={() => setSelections(s => ({ ...s, city }))}
                        className={`flex items-center gap-2 p-3 rounded-xl border text-sm font-bold transition-all ${active ? 'border-[#CA3433] bg-red-50 text-[#CA3433]' : 'border-gray-100 hover:border-gray-200 text-gray-600'}`}
                      >
                        <MapPin size={14} className={active ? 'text-[#CA3433]' : 'text-gray-300'} />
                        {city}
                      </button>
                    )
                  })}
                </div>
              )}

              {/* Budget */}
              {currentStep.id === 'budget' && (
                <div className="space-y-2.5">
                  {currentStep.ranges.map(r => {
                    const active = selections.budget?.id === r.id
                    return (
                      <button
                        key={r.id}
                        onClick={() => setSelections(s => ({ ...s, budget: r }))}
                        className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all ${active ? 'border-[#CA3433] bg-red-50' : 'border-gray-100 hover:border-gray-200'}`}
                      >
                        <div className="flex items-center gap-3">
                          <IndianRupee size={15} className={active ? 'text-[#CA3433]' : 'text-gray-400'} />
                          <div className="text-left">
                            <p className={`text-sm font-bold ${active ? 'text-gray-900' : 'text-gray-600'}`}>{r.label}</p>
                            <p className="text-[10px] text-gray-400">{r.desc}</p>
                          </div>
                        </div>
                        {active && <div className="w-5 h-5 rounded-full bg-[#CA3433] flex items-center justify-center"><Check size={11} className="text-white" /></div>}
                      </button>
                    )
                  })}
                </div>
              )}
            </motion.div>
          </AnimatePresence>

          <div className="mt-8 flex items-center justify-between pt-5 border-t border-gray-100">
            <p className="text-xs text-gray-400">
              {step + 1} / {QUIZ_STEPS.length} — {Math.round(((step + 1) / QUIZ_STEPS.length) * 100)}% done
            </p>
            <Button 
              disabled={!selections[currentStep.id] || saving}
              onClick={handleNext}
              variant="primary" 
              className="rounded-full px-7 py-2.5 bg-[#CA3433] hover:bg-[#ac2d2c] shadow-lg shadow-red-500/20 group"
              loading={saving && step === QUIZ_STEPS.length - 1}
            >
              <span className="flex items-center gap-2 text-sm">
                {step === QUIZ_STEPS.length - 1 ? 'Find My Match' : 'Next'}
                <ChevronRight size={16} className="group-hover:translate-x-1 transition-transform" />
              </span>
            </Button>
          </div>
        </div>
      </motion.div>
    </div>
  )
}

import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

const ScrollToTop = () => {
  const { pathname, search } = useLocation();

  useEffect(() => {
    if ('scrollRestoration' in window.history) {
      window.history.scrollRestoration = 'manual';
    }
    // Only scroll to top when the actual page (pathname) changes.
    // This prevents jumping when just switching filters/categories on the search page.
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

export default ScrollToTop;

