import React, { useEffect, useState } from 'react'
import { ChevronRight, Flame } from 'lucide-react'
import { Link, useNavigate } from 'react-router-dom'
import { useDispatch } from 'react-redux'
import { PropertyCard } from '../property/PropertyCard'
import { useProperties } from '../../hooks/useProperties'
import { setFilters } from '../../store/propertySlice'
import { MOCK_PROPERTIES } from '../../utils/constants'

import { Skeleton } from '../ui/Skeleton'

const SectionSkeleton = () => (
  <div className="flex gap-5 overflow-x-auto pb-4 scrollbar-hide">
    {[1,2,3,4].map(i => (
      <div key={i} className="flex-shrink-0 w-64 rounded-xl bg-white border border-gray-100 overflow-hidden p-3 space-y-3">
        <Skeleton className="h-44 w-full rounded-xl" />
        <div className="space-y-2 px-1">
          <Skeleton className="h-5 w-4/5" />
          <Skeleton className="h-4 w-3/5" />
          <div className="pt-1 flex gap-2">
            <Skeleton className="h-3 w-1/4 rounded-full" />
            <Skeleton className="h-3 w-1/4 rounded-full" />
          </div>
        </div>
      </div>
    ))}
  </div>
)

export const PropertySection = ({ title, type, icon, viewAllPath }) => {
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const { fetchByType } = useProperties()
  const [items, setItems] = useState([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const loadData = async () => {
      const data = await fetchByType(type)
      setItems(data?.length ? data : MOCK_PROPERTIES.filter(p => p.type === type))
      setLoading(false)
    }
    
    loadData()
  }, [type, fetchByType])

  if (!loading && items.length === 0) return null

  return (
    <section className="mb-12">
      <div className="flex items-center justify-between mb-5">
        <div className="flex items-center gap-2">
          {icon}
          <h2 className="font-display font-bold text-xl text-gray-900">{title}</h2>
          {!loading && (
            <span className="text-sm text-gray-400 font-medium ml-1">({items.length})</span>
          )}
        </div>
        <button
          onClick={() => {
            dispatch(setFilters({ type: type === 'all' ? '' : type }))
            navigate(viewAllPath || '/search')
          }}
          className="flex items-center gap-1 text-sm font-semibold text-brand-500 hover:text-brand-700 transition-colors"
        >
          View all <ChevronRight size={16} />
        </button>
      </div>

      {loading ? (
        <SectionSkeleton />
      ) : (
        <div className="scroll-row">
          {items.map(property => (
            <div key={property.id} className="flex-shrink-0">
              <PropertyCard property={property} compact />
            </div>
          ))}
        </div>
      )}
    </section>
  )
}

export const FeaturedSection = () => {
  const { featured, fetchFeatured, loading } = useProperties()
  const items = featured.length ? featured : MOCK_PROPERTIES.sort((a,b) => b.views - a.views).slice(0,6)

  useEffect(() => { fetchFeatured() }, [])

  return (
    <section className="mb-12">
      <div className="flex items-center justify-between mb-5">
        <div className="flex items-center gap-2">
          <Flame size={24} className="text-orange-500" />
          <h2 className="font-display font-bold text-xl text-gray-900">Most Popular</h2>
        </div>
        <Link to="/search" className="flex items-center gap-1 text-sm font-semibold text-brand-500 hover:text-brand-700 transition-colors">
          View all <ChevronRight size={16} />
        </Link>
      </div>
      {loading ? (
        <SectionSkeleton />
      ) : (
        <div className="scroll-row">
          {items.map(property => (
            <div key={property.id} className="flex-shrink-0">
              <PropertyCard property={property} compact />
            </div>
          ))}
        </div>
      )}
    </section>
  )
}

import React from 'react'
import { useLocation } from 'react-router-dom'
import { Navbar } from '../layout/Navbar'
import { Footer } from '../layout/Footer'
import { AuthModal } from '../auth/AuthModal'
import { AuthGateModal } from '../auth/AuthGateModal'
import { Toaster } from 'react-hot-toast'
import { motion, AnimatePresence } from 'framer-motion'

export const Layout = ({ children }) => {
  const location = useLocation()
  
  return (
    <>
      <Toaster
        position="top-center"
        toastOptions={{
          style: { borderRadius: '12px', fontFamily: 'Plus Jakarta Sans, sans-serif', fontSize: '14px' },
          success: { iconTheme: { primary: '#CA3433', secondary: '#fff' } },
        }}
      />
      
      {/* Forced Auth Gate for Search page */}
      {location.pathname === '/search' && <AuthGateModal />}
      
      {location.pathname !== '/systemadmin' && <Navbar />}
      <AnimatePresence mode="wait">
        <motion.main
          key={location.pathname}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          transition={{ duration: 0.2, ease: "easeOut" }}
          className={location.pathname === '/systemadmin' ? "" : "min-h-screen"}
        >
          {children}
        </motion.main>
      </AnimatePresence>
      {location.pathname === '/search' && <Footer />}
      <AuthModal />
    </>
  )
}

import React, { useState, useMemo, memo } from 'react'
import { useNavigate } from 'react-router-dom'
import { useDispatch, useSelector } from 'react-redux'
import { Heart, Star, Home, Eye } from 'lucide-react'
import { motion } from 'framer-motion'
import { openAuthModal } from '../../store/authSlice'
import { useProperties } from '../../hooks/useProperties'
import { cn } from '../../utils/helpers'
import { useTranslation } from 'react-i18next'

const PropertyCardComponent = ({ property, layout = 'grid', compact = false, condensed = false, badge = null }) => {
  const navigate = useNavigate()
  const { t } = useTranslation()
  const dispatch = useDispatch()
  const { user } = useSelector(s => s.auth)
  const { favorites, toggleFavorite } = useProperties()
  const [imgLoaded, setImgLoaded] = useState(false)

  const isFav = favorites.includes(property.id)
  const images = property.images || []
  const mainImage = images[0]

  const handleFav = (e) => {
    e.stopPropagation()
    toggleFavorite(property.id)
  }

  // Memoize values with deterministic calculation
  const { rating, numBeds } = useMemo(() => {
    return {
      rating: property.rating || '0.0',
      numBeds: property.bedrooms || 0,
    }
  }, [property.rating, property.bedrooms])

  const formatPrice = (p) => {
    if (!p) return '0'
    const num = Number(p)
    return num.toLocaleString('en-IN')
  }

  // List Layout (Matches Image 2)
  if (layout === 'list') {
    return (
      <div 
        className="group bg-white rounded-2xl border border-gray-100 flex gap-4 cursor-pointer shadow-md hover:shadow-xl hover:-translate-y-0.5 transition-all duration-300 overflow-hidden"
        onClick={() => navigate(`/property/${property.id}`)}
      >
        <div className="relative w-32 h-32 sm:w-40 sm:h-40 flex-shrink-0 overflow-hidden bg-gray-50 rounded-r-2xl shadow-sm">
          <img 
            src={mainImage} 
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" 
            onLoad={() => setImgLoaded(true)}
            loading="lazy"
          />
          {!imgLoaded && <div className="skeleton absolute inset-0" />}
          {badge && <div className="absolute bottom-2 left-2 z-20">{badge}</div>}
          <motion.button
            onClick={handleFav}
            aria-label={isFav ? "Remove from favorites" : "Add to favorites"}
            whileHover={{ scale: 1.15 }}
            whileTap={{ scale: 0.85 }}
            className={cn(
              "absolute top-2 right-2 w-8 h-8 rounded-full flex items-center justify-center z-10 transition-all focus:outline-none focus:ring-2 focus:ring-brand-500/50",
              isFav ? "bg-brand-500 text-white shadow-lg" : "bg-white/80 backdrop-blur-sm text-gray-600 hover:bg-white"
            )}
          >
            <motion.div
              animate={isFav ? { scale: [1, 1.3, 1] } : { scale: 1 }}
              transition={{ duration: 0.3 }}
            >
              <Heart size={14} fill={isFav ? "currentColor" : "none"} className={isFav ? "text-white" : "text-gray-600"} />
