        <div className="mt-auto pt-1.5 border-t border-gray-50 flex items-center justify-between">
          <p className="flex flex-col">
            <span className="text-[8px] font-bold text-gray-400 uppercase leading-none">{t('property.labels.from')}</span>
            <span className={cn(
              "font-black text-gray-900 leading-tight",
              condensed ? "text-sm" : "text-base"
            )}>₹{formatPrice(property.price)}</span>
          </p>
          <button className="text-[#CA3433] hover:text-brand-800 transition-colors">
            <Eye size={condensed ? 14 : 18} />
          </button>
        </div>
      </div>
    </div>
  )
}



export const PropertyCard = memo(PropertyCardComponent)

import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Plus, X, Image as ImageIcon, Zap, CheckCircle2, ChevronRight, ChevronLeft } from 'lucide-react'
import { Input, Textarea, Select } from '../ui/Input'
import { Button } from '../ui/Button'
import { PROPERTY_TYPES, AMENITIES } from '../../utils/constants'
import { useProperties } from '../../hooks/useProperties'
import { useSelector } from 'react-redux'
import { supabase } from '../../lib/supabase'
import toast from 'react-hot-toast'
import { LocationPicker } from '../map/LocationPicker'

// ── Success Overlay ───────────────────────────────────────────────────────────
const ListingSuccessOverlay = () => (
  <div className="fixed inset-0 z-[99] flex flex-col items-center justify-center bg-white/95 backdrop-blur-md animate-in fade-in duration-300">
    <div className="relative flex flex-col items-center gap-6">
      <div className="relative w-36 h-36">
        <svg viewBox="0 0 100 100" className="w-full h-full">
          <circle cx="50" cy="50" r="46" fill="none" stroke="#fce8e8" strokeWidth="4" />
          <circle cx="50" cy="50" r="46" fill="none" stroke="#CA3433" strokeWidth="4"
            strokeLinecap="round" strokeDasharray="289" strokeDashoffset="289"
            style={{ animation: 'drawCircle 0.5s ease-out forwards', transformOrigin: 'center', transform: 'rotate(-90deg)' }}
          />
          <polyline points="28,52 44,66 72,36" fill="none" stroke="#CA3433" strokeWidth="6"
            strokeLinecap="round" strokeLinejoin="round" strokeDasharray="70" strokeDashoffset="70"
            style={{ animation: 'drawTick 0.4s ease-out 0.45s forwards' }}
          />
        </svg>
        <div className="absolute inset-0 rounded-full border-4 border-[#CA3433]/20"
          style={{ animation: 'pulseRing 1s ease-out 0.6s infinite' }}
        />
      </div>
      <div className="text-center" style={{ animation: 'fadeInUp 0.5s ease-out 0.8s both' }}>
        <h2 className="text-3xl font-black text-gray-900 font-display mb-2">Listing Live! 🎉</h2>
        <p className="text-gray-500 font-medium">Your property is now visible to renters across Uttarakhand.</p>
      </div>
    </div>
    <style>{`
      @keyframes drawCircle { to { stroke-dashoffset: 0; } }
      @keyframes drawTick { to { stroke-dashoffset: 0; } }
      @keyframes pulseRing { 0% { transform: scale(1); opacity: 0.6; } 100% { transform: scale(1.5); opacity: 0; } }
      @keyframes fadeInUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
    `}</style>
  </div>
)

// ── Step Config ───────────────────────────────────────────────────────────────
const STEPS = [
  { id: 1, label: 'Basics',   short: '1' },
  { id: 2, label: 'Location', short: '2' },
  { id: 3, label: 'Map',      short: '3' },
  { id: 4, label: 'Contact',  short: '4' },
  { id: 5, label: 'Amenities',short: '5' },
  { id: 6, label: 'Photos',   short: '6' },
]

// ── Timeline Progress Bar ─────────────────────────────────────────────────────
const StepTimeline = ({ current }) => (
  <div className="flex items-center justify-between mb-8 px-1">
    {STEPS.map((step, i) => {
      const done = current > step.id
      const active = current === step.id
      return (
        <React.Fragment key={step.id}>
          <div className="flex flex-col items-center gap-1 min-w-0">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-black transition-all duration-300 border-2 ${
              done    ? 'bg-[#CA3433] border-[#CA3433] text-white'
              : active ? 'bg-white border-[#CA3433] text-[#CA3433] shadow-md shadow-red-100'
              : 'bg-white border-gray-200 text-gray-400'
            }`}>
              {done ? <CheckCircle2 size={16} /> : step.short}
            </div>
            <span className={`text-[9px] font-bold uppercase tracking-wider hidden sm:block transition-colors ${
              active ? 'text-[#CA3433]' : done ? 'text-gray-500' : 'text-gray-300'
            }`}>{step.label}</span>
          </div>
          {i < STEPS.length - 1 && (
            <div className={`flex-1 h-[2px] mx-1 rounded transition-all duration-500 ${
              done ? 'bg-[#CA3433]' : 'bg-gray-200'
            }`} />
          )}
        </React.Fragment>
      )
    })}
  </div>
)

// ── Main Form ─────────────────────────────────────────────────────────────────
export const PropertyForm = ({ initialData, isEdit = false }) => {
  const navigate = useNavigate()
  const { updateProperty } = useProperties()
  const { user } = useSelector(s => s.auth)
  const [loading, setLoading] = useState(false)
  const [showSuccess, setShowSuccess] = useState(false)
  const [step, setStep] = useState(1)
  const [images, setImages] = useState([])
  const [previewUrls, setPreviewUrls] = useState(initialData?.images || [])

  const [form, setForm] = useState({
    title:             initialData?.title || '',
    description:       initialData?.description || '',
    price:             initialData?.price || '',
    city:              initialData?.city || '',
    area:              initialData?.area || '',
    pincode:           initialData?.pincode || '',
    type:              initialData?.type || PROPERTY_TYPES[0],
    amenities:         initialData?.amenities || [],
    nearby_landmarks:  initialData?.nearby_landmarks || '',
    exact_location:    initialData?.exact_location || '',
    contact_phone:     initialData?.contact_phone || '',
    contact_email:     initialData?.contact_email || '',
    availability:      initialData?.availability ?? true,
    latitude:          initialData?.latitude || null,
    longitude:         initialData?.longitude || null,
    map_address:       initialData?.map_address || '',
  })

  const set = (key, val) => setForm(f => ({ ...f, [key]: val }))

  const handleLocationChange = ({ latitude, longitude, map_address }) => {
    setForm(f => ({ ...f, latitude, longitude, map_address: map_address || '' }))
  }

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files)
    if (files.length + previewUrls.length > 3) { toast.error('Maximum 3 images allowed'); return }
    for (const file of files) {
      if (file.size > 7 * 1024 * 1024) { toast.error(`Image ${file.name} exceeds 7MB limit`); return }
    }
    setImages(prev => [...prev, ...files])
    setPreviewUrls(prev => [...prev, ...files.map(f => URL.createObjectURL(f))])
  }

  const removeImage = (index) => {
    setPreviewUrls(prev => prev.filter((_, i) => i !== index))
    if (index >= (initialData?.images?.length || 0)) {
      setImages(prev => prev.filter((_, i) => i !== index - (initialData?.images?.length || 0)))
    }
  }

  const toggleAmenity = (id) => {
    setForm(f => ({
      ...f,
      amenities: f.amenities.includes(id) ? f.amenities.filter(a => a !== id) : [...f.amenities, id]
    }))
  }

  // ── Per-step validation ────────────────────────────────────────────────────
  const validateStep = (s) => {
    if (s === 1 && (!form.title || !form.price)) { toast.error('Title and Rent are required'); return false }
    if (s === 2 && (!form.city || !form.area))   { toast.error('City and Area are required'); return false }
    if (s === 6 && previewUrls.length < 1)        { toast.error('Please upload at least 1 photo'); return false }
    return true
  }

  const next = () => { if (validateStep(step)) setStep(s => Math.min(s + 1, 6)) }
  const back = () => setStep(s => Math.max(s - 1, 1))

  // ── Final submit ──────────────────────────────────────────────────────────
  const validateForm = () => {
    if (!form.title || !form.price || !form.city || !form.area) { toast.error('Please fill all required fields'); return false }
    if (previewUrls.length < 1 || previewUrls.length > 3) { toast.error('Please upload between 1 and 3 images'); return false }
    return true
  }

  const handleEditSubmit = async (e) => {
    e.preventDefault()
    if (!validateForm()) return
    setLoading(true)
    try {
      await updateProperty(initialData.id, { ...form, images: previewUrls.filter(u => !u.startsWith('blob:')) }, images)
      toast.success('Property updated successfully!')
      navigate('/landlord')
    } catch (err) {
      toast.error(err.message || 'Failed to save property')
    } finally { setLoading(false) }
  }

  const handlePayToGoLive = async () => {
    if (!validateForm()) return
    if (loading) return
    setLoading(true)
    try {
      const { data: { session } } = await supabase.auth.getSession()
      const token = session?.access_token
      if (!token) { toast.error('Session expired — please log in again'); setLoading(false); return }

      const uploadedUrls = []
      for (const file of images) {
        const ext = file.name.split('.').pop()
        const fileName = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}.${ext}`
        const { data: uploadData, error: uploadError } = await supabase.storage
          .from('property-images').upload(`${session.user.id}/${fileName}`, file, { upsert: false })
        if (uploadError) throw new Error('Image upload failed: ' + uploadError.message)
        const { data: { publicUrl } } = supabase.storage.from('property-images').getPublicUrl(uploadData.path)
        uploadedUrls.push(publicUrl)
      }

      const loadRazorpay = () => new Promise(resolve => {
        if (window.Razorpay) return resolve(true)
        const s = document.createElement('script')
        s.src = 'https://checkout.razorpay.com/v1/checkout.js'
        s.onload = () => resolve(true); s.onerror = () => resolve(false)
        document.body.appendChild(s)
      })
      if (!await loadRazorpay()) throw new Error('Razorpay SDK failed to load')

      const orderResp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-listing-order`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`, 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY }
      })
      if (!orderResp.ok) {
        const errText = await orderResp.text()
        let errJson = {}; try { errJson = JSON.parse(errText) } catch(e) {}
        const msg = [errJson.error, errJson.detail, `HTTP ${orderResp.status}`].filter(Boolean).join(' | ')
        toast.error(msg, { duration: 8000 }); throw new Error(msg)
      }
      const orderData = await orderResp.json()

      const rzp = new window.Razorpay({
        key: import.meta.env.VITE_RAZORPAY_KEY_ID,
        order_id: orderData.id, currency: 'INR',
        name: 'GoEazy', description: 'List Your Property — Go Live', image: '/favicon.svg',
        handler: async function(response) {
          try {
            setLoading(true)
            const { data: { session: s2 } } = await supabase.auth.getSession()
            const verifyResp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/verify-listing-payment`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${s2?.access_token}`, 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY },
              body: JSON.stringify({ ...response, property_data: { ...form, images: uploadedUrls } })
            })
            if (!verifyResp.ok) { const e = await verifyResp.json().catch(() => ({})); throw new Error(e.error || 'Payment verification failed') }
            setShowSuccess(true)
            setTimeout(() => navigate('/landlord'), 2800)
          } catch (vErr) { toast.error('Payment verification failed: ' + vErr.message) }
          finally { setLoading(false) }
        },
        prefill: { name: user?.user_metadata?.full_name || 'Landlord', email: user?.email || '' },
        theme: { color: '#CA3433' },
        modal: { ondismiss: () => setLoading(false) }
      })
      rzp.on('payment.failed', resp => { toast.error('Payment failed: ' + (resp.error?.description || '')); setLoading(false) })
      rzp.open()
    } catch (err) { toast.error(err.message || 'Something went wrong'); setLoading(false) }
  }

  // ── Render Steps ──────────────────────────────────────────────────────────
  const renderStep = () => {
    switch (step) {

      case 1: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Basic Details</h3>
            <p className="text-sm text-gray-400">Start with the most important information about your property.</p>
          </div>
          <Input id="property-title" label="Property Title *" placeholder="e.g. Spacious 1BHK in Rajpur Road"
            value={form.title} onChange={e => set('title', e.target.value)} required />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input id="property-price" label="Rent (₹/month) *" type="number" placeholder="e.g. 12000"
              rightIcon={<span className="text-sm font-bold text-gray-400">/ mo</span>}
              value={form.price} onChange={e => set('price', Number(e.target.value))} required />
            <Select id="property-type" label="Property Type *" value={form.type} onChange={e => set('type', e.target.value)}>
              {PROPERTY_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
            </Select>
          </div>
          <Textarea id="property-description" label="Description" placeholder="Tell renters what makes this place special..."
            rows={4} value={form.description} onChange={e => set('description', e.target.value)} />
        </div>
      )

      case 2: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Location</h3>
            <p className="text-sm text-gray-400">Where is your property located?</p>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <Select id="property-city" label="City *" value={form.city} onChange={e => set('city', e.target.value)} required>
              <option value="" disabled>Select city</option>
              {['Dehradun','Srinagar','Rishikesh','Haldwani','Nainital','Haridwar','Roorkee','Rudrapur'].map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </Select>
            <Input id="property-area" label="Area / Locality *" placeholder="e.g. Rajpur Road"
              value={form.area} onChange={e => set('area', e.target.value)} required />
            <Input id="property-pincode" label="Pincode" placeholder="e.g. 248001"
              value={form.pincode} onChange={e => set('pincode', e.target.value)} />
          </div>
          <Input id="property-landmarks" label="Nearby Landmarks" placeholder="e.g. 500m from Clock Tower, Near FRI"
            value={form.nearby_landmarks} onChange={e => set('nearby_landmarks', e.target.value)} />
        </div>
      )

      case 3: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Pin on Map</h3>
            <p className="text-sm text-gray-400">Drop a pin on your exact property location. This helps renters find you easily.</p>
          </div>
          <div className="border border-gray-100 rounded-2xl p-4 bg-gray-50/50">
            <LocationPicker
              value={{ latitude: form.latitude, longitude: form.longitude, map_address: form.map_address }}
              onChange={handleLocationChange}
              label="Pin Property on Map"
            />
          </div>
        </div>
      )

      case 4: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Premium Contact Details</h3>
            <p className="text-sm text-gray-400">These details are only visible to tenants who unlock your listing. Keep them accurate.</p>
          </div>
          <Input id="property-address" label="Exact Property Address"
            placeholder="e.g. Flat 402, Building B, XYZ Apartments, Near Metro"
            value={form.exact_location} onChange={e => set('exact_location', e.target.value)} />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input id="property-phone" label="Contact Phone" placeholder="+91 9876543210"
              value={form.contact_phone} onChange={e => set('contact_phone', e.target.value)} />
            <Input id="property-email" label="Contact Email" type="email" placeholder="owner@email.com"
              value={form.contact_email} onChange={e => set('contact_email', e.target.value)} />
          </div>
          <div className="flex items-center gap-3 p-3 bg-amber-50 rounded-xl border border-amber-100">
            <span className="text-amber-500 text-lg">🔒</span>
            <p className="text-xs text-amber-700 font-medium">These details are hidden from public view. Only unlocked tenants (who pay ₹49) can see them.</p>
          </div>
        </div>
      )

      case 5: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Amenities</h3>
            <p className="text-sm text-gray-400">Select all amenities your property offers. More = better visibility.</p>
          </div>
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
            {AMENITIES.map(a => {
              const isActive = form.amenities.includes(a.id)
              return (
                <button key={a.id} type="button" onClick={() => toggleAmenity(a.id)}
                  className={`flex flex-col items-center gap-2 p-3 rounded-xl border-2 transition-all ${
                    isActive ? 'border-[#CA3433] bg-red-50 text-[#CA3433]' : 'border-gray-100 bg-white text-gray-500 hover:border-red-200'
                  }`}
                >
                  <span className="text-2xl">{a.icon}</span>
                  <span className="text-[10px] font-semibold leading-tight text-center">{a.label}</span>
                </button>
              )
            })}
          </div>
          {form.amenities.length > 0 && (
            <p className="text-xs font-bold text-[#CA3433]">{form.amenities.length} amenities selected ✓</p>
          )}
        </div>
      )

      case 6: return (
        <div className="space-y-5 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <h3 className="text-xl font-black text-gray-900 mb-1">Photos & Go Live</h3>
            <p className="text-sm text-gray-400">Upload up to 3 photos. Better photos = more inquiries. (Max 7MB each)</p>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {previewUrls.map((url, i) => (
              <div key={i} className="relative aspect-video rounded-xl overflow-hidden group border border-gray-100">
                <img src={url} alt={`Preview ${i}`} className="w-full h-full object-cover" />
                <button type="button" onClick={() => removeImage(i)}
                  className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                  <X size={14} />
                </button>
              </div>
            ))}
            {previewUrls.length < 3 && (
              <label className="aspect-video rounded-xl border-2 border-dashed border-gray-300 bg-gray-50 flex flex-col items-center justify-center cursor-pointer hover:border-[#CA3433] hover:bg-red-50/30 transition-colors text-gray-500">
                <ImageIcon size={24} className="mb-2" />
                <span className="text-sm font-semibold">Add Photo</span>
                <input id="property-images" type="file" multiple accept="image/*" className="hidden" onChange={handleImageChange} />
              </label>
            )}
          </div>

          {/* Availability toggle */}
          <label htmlFor="property-availability" className="flex items-center gap-3 cursor-pointer p-3 rounded-xl bg-gray-50 border border-gray-100">
            <input id="property-availability" type="checkbox" className="w-5 h-5 rounded border-gray-300 text-[#CA3433] focus:ring-[#CA3433] accent-[#CA3433]"
              checked={form.availability} onChange={e => set('availability', e.target.checked)} />
            <span className="text-sm font-semibold text-gray-900">Mark as Available to Rent</span>
          </label>

        </div>
      )

      default: return null
    }
  }

  // ── Layout ────────────────────────────────────────────────────────────────
  return (
    <>
      {showSuccess && <ListingSuccessOverlay />}

      <div className="w-full bg-white rounded-3xl border border-gray-100 shadow-sm p-6 sm:p-8">
        <StepTimeline current={step} />

        <form onSubmit={isEdit ? handleEditSubmit : e => e.preventDefault()}>
          {/* Step Content */}
          <div>
            {renderStep()}
          </div>

          {/* Navigation Buttons */}
          <div className="flex gap-3 mt-4 pt-4 border-t border-gray-100">
            {step > 1 ? (
              <button type="button" onClick={back}
                className="flex items-center gap-1.5 px-5 py-3 rounded-xl border border-gray-200 text-gray-700 font-bold text-sm hover:bg-gray-50 transition-colors">
                <ChevronLeft size={16} /> Back
              </button>
            ) : (
              <button type="button" onClick={() => navigate(-1)}
                className="flex items-center gap-1.5 px-5 py-3 rounded-xl border border-gray-200 text-gray-700 font-bold text-sm hover:bg-gray-50 transition-colors">
                Cancel
              </button>
            )}

            <div className="flex-1" />

            {step < 6 ? (
              <button type="button" onClick={next}
                className="flex items-center gap-1.5 px-6 py-3 rounded-xl bg-[#CA3433] text-white font-bold text-sm hover:bg-[#ac2d2c] transition-colors shadow-sm shadow-red-100">
                Next <ChevronRight size={16} />
              </button>
            ) : isEdit ? (
              <button type="submit" disabled={loading}
                className="flex items-center gap-2 px-6 py-3 rounded-xl bg-[#CA3433] text-white font-bold text-sm hover:bg-[#ac2d2c] transition-colors disabled:opacity-60">
                {loading ? 'Saving...' : 'Save Changes'}
              </button>
            ) : (
              <button type="button" onClick={handlePayToGoLive} disabled={loading}
                className="flex items-center gap-2 px-6 py-3 rounded-xl bg-gradient-to-r from-[#CA3433] to-[#E63946] text-white font-extrabold text-sm shadow-lg shadow-red-500/20 hover:shadow-red-500/40 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-60 disabled:scale-100">
                {loading ? (
                  <><svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/></svg> Processing...</>
                ) : (
                  <><Zap size={16} /> GO LIVE <span className="bg-white/20 px-1.5 py-0.5 rounded text-xs font-black">₹199</span></>
                )}
              </button>
            )}
          </div>
        </form>
      </div>
    </>
  )
}

import React, { useState, useEffect, useRef } from 'react'
import { Sparkles } from 'lucide-react'
import { useProperties } from '../../hooks/useProperties'
import { PropertyCard } from './PropertyCard'
import { cn } from '../../utils/helpers'

export const RecommendedSection = ({ viewMode = 'grid' }) => {
  const { getRecommendedProperties, loading } = useProperties()
  const [recommendations, setRecommendations] = useState([])
  const isLocked = useRef(false)

  // Lock recommendations once — prevents re-shuffle flicker on every re-render
  useEffect(() => {
    if (!loading && !isLocked.current) {
      const recs = getRecommendedProperties()
      if (recs.length > 0) {
        setRecommendations(recs)
        isLocked.current = true
      }
    }
  }, [loading, getRecommendedProperties])

  if (!recommendations.length) return null

  const handleResetQuiz = () => {
    isLocked.current = false
    setRecommendations([])
    window.dispatchEvent(new Event('goeazy_quiz_reset'))
  }

  return (
    <div className="mb-6">
      {/* Header */}
      <div className="flex items-center justify-between mb-4 px-1">
        <div className="flex items-center gap-2">
          <Sparkles size={16} className="text-[#CA3433]" />
          <h2 className="text-lg font-bold text-gray-900 tracking-tight">Recommended for You</h2>
        </div>
        <button
          onClick={handleResetQuiz}
          className="text-xs font-bold text-[#CA3433] hover:underline px-3 py-1.5 rounded-lg border border-red-100 bg-red-50/30 transition-all active:scale-95"
        >
          Reset
        </button>
      </div>

      {/* Horizontal Scroll with peeking cards */}
      <div className="flex gap-3 sm:gap-6 xl:gap-8 overflow-x-auto pb-4 px-1 no-scrollbar -mx-1 snap-x snap-mandatory pt-2">
        {recommendations.map(p => (
          <div
            key={`rec-${p.id}`}
            className={cn(
              "flex-none ring-1 ring-[#CA3433]/10 rounded-2xl group snap-start transition-all duration-300",
              viewMode === 'list'
                ? "w-[88%]"
                : "w-[40%] sm:w-[25%] lg:w-[20%] xl:w-[16%]"
            )}
          >
            <PropertyCard
              property={p}
              layout={viewMode}
              condensed={true}
              badge={
                <div className="flex items-center gap-1 px-2 py-0.5 bg-gradient-to-r from-[#CA3433] to-[#ff4d4d] text-white text-[7px] font-black rounded-full uppercase tracking-widest border border-white/20 shadow-md shadow-red-500/30">
                  <Sparkles size={8} className="fill-current" />
                  Match Found
                </div>
              }
            />
          </div>
        ))}
      </div>

      {/* Divider before All Results */}
      <div className="mt-2 pt-1 border-t border-gray-100">
        <h3 className="text-[13px] font-black text-gray-900 uppercase tracking-[0.2em]">All Results</h3>
      </div>
    </div>
  )
}

import { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { supabase } from '../lib/supabase'
import { setUser, setProfile, logout, setLoading } from '../store/authSlice'

export const useAuth = () => {
  const dispatch = useDispatch()
  const { user, profile, role, loading, authModalOpen, authModalTab } = useSelector(s => s.auth)

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session }, error }) => {

      if (error) console.error('Auth: Session error', error)
      
      dispatch(setUser(session?.user ?? null))
      if (session?.user) fetchProfile(session.user.id)
      else dispatch(setLoading(false))
    })

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {

      
      dispatch(setUser(session?.user ?? null))
      if (session?.user) {
        fetchProfile(session.user.id)
      } else if (event === 'SIGNED_OUT') {
        dispatch(logout())
      } else {
        dispatch(setLoading(false))
      }
    })

    return () => subscription.unsubscribe()
  }, [])

  const fetchProfile = async (userId) => {
    try {
      // First try to fetch
      let { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle()
      
      // If no profile exists (e.g., first-time OAuth), create one automatically
      if (!data && !error) {

        const { data: { user }, error: userError } = await supabase.auth.getUser()

        // ── GHOST SESSION GUARD ──
        // If the user no longer exists in Supabase (deleted from dashboard),
        // their JWT is orphaned. Force sign them out immediately.
        if (userError || !user) {
          console.warn('Auth: Ghost session detected — user deleted. Forcing sign-out.')
          await supabase.auth.signOut()
          dispatch(logout())
          return
        }

        const fullName = user?.user_metadata?.full_name || user?.email?.split('@')[0] || 'User'
        const userRole = user?.user_metadata?.role || null
        
        const { data: newProfile, error: upsertError } = await supabase
          .from('profiles')
          .upsert({
            id: userId,
            email: user?.email,
            full_name: fullName,
            role: userRole,
            avatar_url: user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${fullName}`,
            created_at: new Date().toISOString()
          })
          .select()
          .maybeSingle()

        if (upsertError) {
          // ── FK CONSTRAINT GUARD ──
          // code 23503 = foreign key violation (user deleted from auth.users)
          // status 403/401 = JWT is now invalid
          const isGhostUser = upsertError.code === '23503' || upsertError.status === 403 || upsertError.status === 401
          if (isGhostUser) {
            console.warn('Auth: Deleted account confirmed via FK/auth error. Forcing sign-out.')
            await supabase.auth.signOut()
            dispatch(logout())
            return
          }
          console.error('Auth: Profile creation failed', upsertError)
          throw upsertError
        }
        data = newProfile
      } else if (error) {
        // ── FETCH ERROR GUARD ──
        // 403/401 on profile fetch = stale/invalid token (user deleted)
        const isAuthError = error.status === 403 || error.status === 401
        if (isAuthError) {
          console.warn('Auth: Invalid token on profile fetch. Forcing sign-out.')
          await supabase.auth.signOut()
          dispatch(logout())
          return
        }
        console.error('Auth: Profile fetch error', error)
        throw error
      }


      dispatch(setProfile(data))
    } catch (err) {
      console.error('Auth: fetchProfile catch block', err)
      dispatch(setLoading(false))
    }
  }

  const signUp = async ({ email, password, name, role }) => {
    const { data, error } = await supabase.auth.signUp({
      email, password,
      options: { 
        data: { 
          full_name: name,
          role: role 
        } 
      },
    })
    if (error) throw error

    if (data.user) {
      await supabase.from('profiles').upsert({
        id: data.user.id,
        email,
        full_name: name,
        role,
        avatar_url: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`,
        created_at: new Date().toISOString(),
      })
    }
    return data
  }

  const signIn = async ({ email, password }) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) throw error
    return data
  }

  const signInWithGoogle = async () => {
    // Priority: Saved return path > Env variable > current origin
    const savedPath = localStorage.getItem('sb_return_to')
    const redirectUrl = savedPath 
      ? `${window.location.origin}${savedPath}`
      : (import.meta.env.VITE_REDIRECT_URL || `${window.location.origin}/search`)
    
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { 
        redirectTo: redirectUrl,
        queryParams: {
          prompt: 'select_account'
        }
      },
    })
    if (error) throw error
  }

  const signOut = async () => {
    await supabase.auth.signOut()
    dispatch(logout())
  }

  const updateProfile = async (updates) => {
    const { data, error } = await supabase
      .from('profiles')
      .update(updates)
      .eq('id', user.id)
      .select()
      .maybeSingle()
    if (error) throw error
    dispatch(setProfile(data))
    return data
  }

  return { user, profile, role, loading, authModalOpen, authModalTab, signUp, signIn, signInWithGoogle, signOut, updateProfile }
}

import { useCallback } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { supabase } from '../lib/supabase'
import { MOCK_PROPERTIES } from '../utils/constants'
import toast from 'react-hot-toast'
import {
  setListings, appendListings, setFeatured, setCurrentProperty,
  setFavorites, toggleFavorite as toggleFav,
  setRecentlyViewed, addRecentlyViewed,
  setLoading, setHasMore, setPage, setFilters, setTotalCount, resetFilters,
  setReviews, addReview, removeReview, setReviewsLoading
} from '../store/propertySlice'

const PAGE_SIZE = 12

const PUBLIC_PROPERTY_FIELDS = `
  id, landlord_id, type, title, description, price, city, area, pincode, 
  amenities, images, availability, views, created_at
`

const PUBLIC_PROFILE_FIELDS = 'full_name, avatar_url, bio'

export const useProperties = () => {
  const dispatch = useDispatch()
  const { 
    listings, featured, currentProperty, 
    favorites, recentlyViewed, filters, 
    loading, hasMore, page, totalCount,
    reviews, reviewsLoading 
  } = useSelector(s => s.property)
  const { user, profile } = useSelector(s => s.auth)

  const fetchProperties = useCallback(async (reset = false) => {
    dispatch(setLoading(true))
    try {
      let query = supabase
        .from('properties')
        .select(`${PUBLIC_PROPERTY_FIELDS}, profiles!properties_landlord_id_fkey(${PUBLIC_PROFILE_FIELDS})`, { count: 'exact' })
        .eq('availability', true)

      if (filters.type) query = query.eq('type', filters.type)
      if (filters.priceMin > 0) query = query.gte('price', filters.priceMin)
      if (filters.priceMax < 100000) query = query.lte('price', filters.priceMax)
      
      if (filters.amenities?.length > 0) {
        query = query.contains('amenities', filters.amenities)
      }

      if (filters.city) {
        query = query.ilike('city', `%${filters.city}%`)
      }

      if (filters.area) {
        const fuzzyPattern = '%' + filters.area.toLowerCase().split('').filter(c => c.trim()).join('%') + '%'
        query = query.ilike('area', fuzzyPattern)
      }

      const from = reset ? 0 : page * PAGE_SIZE
      const { data, error, count: dbCount } = await query
        .order(filters.sortBy || 'created_at', { ascending: filters.sortOrder === 'asc' })
        .range(from, from + PAGE_SIZE - 1)

      if (error) throw error

      if (reset) {
        dispatch(setListings(data || []))
        dispatch(setTotalCount(dbCount || 0))
      } else {
        dispatch(appendListings(data || []))
      }

      dispatch(setHasMore((data || []).length === PAGE_SIZE))
      dispatch(setPage(reset ? 1 : page + 1))
    } catch (err) {
      console.error('fetchProperties error:', err)
      dispatch(setListings([]))
    } finally {
      dispatch(setLoading(false))
    }
  }, [filters, page, dispatch])

  const fetchFeatured = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('properties')
        .select(`${PUBLIC_PROPERTY_FIELDS}, profiles!properties_landlord_id_fkey(${PUBLIC_PROFILE_FIELDS})`)
        .eq('availability', true)
        .order('views', { ascending: false })
        .limit(8)
      if (error) throw error
      dispatch(setFeatured(data?.length ? data : MOCK_PROPERTIES.sort((a, b) => b.views - a.views).slice(0, 8)))
    } catch {
      dispatch(setFeatured(MOCK_PROPERTIES.sort((a, b) => b.views - a.views).slice(0, 8)))
    }
  }, [dispatch])

  const fetchByType = useCallback(async (type) => {
    try {
      const { data, error } = await supabase
        .from('properties')
        .select(`${PUBLIC_PROPERTY_FIELDS}`)
        .eq('type', type)
        .eq('availability', true)
        .order('views', { ascending: false })
        .limit(10)
      if (error) throw error
      return data?.length ? data : MOCK_PROPERTIES.filter(p => p.type === type)
    } catch {
      return MOCK_PROPERTIES.filter(p => p.type === type)
    }
  }, [])

  const fetchPropertyById = useCallback(async (id) => {
    dispatch(setLoading(true))
    try {
      const { data, error } = await supabase
        .from('properties')
        .select(`${PUBLIC_PROPERTY_FIELDS}, profiles!properties_landlord_id_fkey(${PUBLIC_PROFILE_FIELDS})`)
        .eq('id', id)
        .maybeSingle()
      if (error) throw error
      dispatch(setCurrentProperty(data))
      
      if (user && data) {
        dispatch(addRecentlyViewed(id))
        await supabase.from('recently_viewed').upsert({ user_id: user.id, property_id: id, viewed_at: new Date().toISOString() })
      }
    } catch (err) {
      console.error('Error fetching property:', err)
    } finally {
      dispatch(setLoading(false))
    }
  }, [user, dispatch])

  const fetchGatedData = useCallback(async (id) => {
    if (!user) return null
    try {
      // 1. Try the RPC first
      const rpcResult = await supabase.rpc('get_unlocked_property_details', { prop_id: id })
      const rpcData = rpcResult.data?.[0] || {}

      // 2. ALWAYS also directly fetch contact_phone + contact_email from properties table
      //    (the RPC may not include these fields, and landlords can always read their own data)
      const { data: directData } = await supabase
        .from('properties')
        .select('contact_phone, contact_email, exact_location')
        .eq('id', id)
        .maybeSingle()

      // 3. Merge — RPC fields take priority, direct fields fill any gaps
      return {
        ...rpcData,
        contact_phone: rpcData?.contact_phone || directData?.contact_phone || null,
        contact_email: rpcData?.contact_email || directData?.contact_email || null,
        exact_location: rpcData?.exact_location || directData?.exact_location || null,
      }
    } catch (err) {
      console.error('Error fetching gated data:', err)
      return null
    }
  }, [user])

  const fetchReviews = useCallback(async (propertyId) => {
    dispatch(setReviewsLoading(true))
    try {
      const { data, error } = await supabase
        .from('property_reviews')
        .select('*, profiles(full_name, avatar_url)')
        .eq('property_id', propertyId)
        .order('created_at', { ascending: false })

      if (error) throw error
      dispatch(setReviews(data || []))
    } catch (err) {
      console.error('fetchReviews error:', err)
    } finally {
      dispatch(setReviewsLoading(false))
    }
  }, [dispatch])

  const submitReview = async (propertyId, rating, feedback) => {
    if (!user) throw new Error('Must be logged in to submit a review')

    const reviewData = {
      property_id: propertyId,
      reviewer_id: user.id,
      rating,
      feedback,
    }

    const { data, error } = await supabase
      .from('property_reviews')
      .upsert(reviewData, { onConflict: 'property_id,reviewer_id' })
      .select('*, profiles(full_name, avatar_url)')
      .maybeSingle()

    if (error) throw error
    dispatch(addReview(data))
    return data
  }

  const deleteReview = async (reviewId) => {
    if (!user) return
    const { error } = await supabase
      .from('property_reviews')
      .delete()
      .eq('id', reviewId)
      .eq('reviewer_id', user.id)

    if (error) throw error
    dispatch(removeReview(reviewId))
  }

  const createProperty = async (propertyData, images) => {
    const imageUrls = []
    for (const img of images) {
      const ext = img.name.split('.').pop()
      const path = `properties/${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${ext}`
      const { error: uploadError } = await supabase.storage.from('property-images').upload(path, img)
      if (uploadError) throw new Error(`Image upload failed: ${uploadError.message}`)
      const { data: { publicUrl } } = supabase.storage.from('property-images').getPublicUrl(path)
      imageUrls.push(publicUrl)
    }
    const { data, error } = await supabase.from('properties').insert({ ...propertyData, landlord_id: user.id, images: imageUrls, views: 0 }).select().maybeSingle()
    if (error) throw error
    return data
  }

  const updateProperty = async (id, updates, newImages) => {
    let imageUrls = updates.images || []
    if (newImages?.length) {
      for (const img of newImages) {
        const ext = img.name.split('.').pop()
        const path = `properties/${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${ext}`
        const { error: uploadError } = await supabase.storage.from('property-images').upload(path, img)
        if (uploadError) throw new Error(`Image upload failed: ${uploadError.message}`)
        const { data: { publicUrl } } = supabase.storage.from('property-images').getPublicUrl(path)
        imageUrls.push(publicUrl)
      }
    }
    const { data, error } = await supabase.from('properties').update({ ...updates, images: imageUrls }).eq('id', id).eq('landlord_id', user.id).select().maybeSingle()
    if (error) throw error
    return data
  }

  const deleteProperty = async (id) => {
    const { count, error } = await supabase.from('properties').delete({ count: 'exact' }).eq('id', id).eq('landlord_id', user.id)
    if (error) throw error
    return count > 0
  }

  const fetchFavorites = useCallback(async () => {
    if (!user) {
      try {
        const localFavs = JSON.parse(localStorage.getItem('favorite_property_ids') || '[]')
        dispatch(setFavorites(localFavs))
      } catch (err) {
        dispatch(setFavorites([]))
      }
      return
    }

    try {
      const { data, error } = await supabase.from('favorites').select('property_id').eq('user_id', user.id)
      if (error) throw error
      const dbFavs = data?.map(f => f.property_id) || []

      // Migrate guest favorites from localStorage
      let localFavs = []
      try {
        localFavs = JSON.parse(localStorage.getItem('favorite_property_ids') || '[]')
      } catch (err) {
        localFavs = []
      }

      if (localFavs.length > 0) {
        const mergedFavs = Array.from(new Set([...dbFavs, ...localFavs]))
        const toInsert = localFavs.filter(id => !dbFavs.includes(id))

        if (toInsert.length > 0) {
          const insertData = toInsert.map(propertyId => ({
            user_id: user.id,
            property_id: propertyId
          }))
          const { error: insertError } = await supabase.from('favorites').insert(insertData)
          if (!insertError) {
            dispatch(setFavorites(mergedFavs))
            toast.success('Synced your saved properties to your account! ❤️')
            localStorage.removeItem('favorite_property_ids')
          } else {
            console.error('Migration failed:', insertError)
            dispatch(setFavorites(dbFavs))
          }
        } else {
          dispatch(setFavorites(dbFavs))
          localStorage.removeItem('favorite_property_ids')
        }
      } else {
        dispatch(setFavorites(dbFavs))
      }
    } catch (err) {
      console.error('fetchFavorites error:', err)
    }
  }, [user, dispatch])

  const toggleFavorite = async (propertyId) => {
    const isFav = favorites.includes(propertyId)
    
    // Optimistic UI Update
    dispatch(toggleFav(propertyId))

    if (!user) {
      // Guest logic
      try {
        let localFavs = JSON.parse(localStorage.getItem('favorite_property_ids') || '[]')
        if (isFav) {
          localFavs = localFavs.filter(id => id !== propertyId)
          toast.success('Removed from Favorites')
        } else {
          if (!localFavs.includes(propertyId)) {
            localFavs.push(propertyId)
          }
          toast.success('Added to Favorites ❤️')
          toast('Please login to sync across devices', { icon: '🔑' })
        }
        localStorage.setItem('favorite_property_ids', JSON.stringify(localFavs))
      } catch (err) {
        console.error('Error modifying guest favorites:', err)
        // Rollback state if localStorage fails
        dispatch(toggleFav(propertyId))
      }
      return
    }

    // Authenticated logic
    try {
      if (isFav) {
        const { error } = await supabase.from('favorites').delete().eq('user_id', user.id).eq('property_id', propertyId)
        if (error) throw error
        toast.success('Removed from Favorites')
      } else {
        const { error } = await supabase.from('favorites').insert({ user_id: user.id, property_id: propertyId })
        if (error) {
          if (error.code === '23505') { // unique constraint violation
            toast.error('Already saved')
          } else {
            throw error
          }
        } else {
          toast.success('Added to Favorites ❤️')
        }
      }
    } catch (err) {
      console.error('toggleFavorite error:', err)
      // Rollback UI update on failure
      dispatch(toggleFav(propertyId))
      toast.error('Failed to update favorites')
    }
  }

  const fetchRecentlyViewed = useCallback(async () => {
    if (!user) return
    try {
      const seventyTwoHoursAgo = new Date(Date.now() - 72 * 60 * 60 * 1000).toISOString()
      const { data } = await supabase.from('recently_viewed').select('property_id').eq('user_id', user.id).gte('viewed_at', seventyTwoHoursAgo).order('viewed_at', { ascending: false }).limit(20)
      dispatch(setRecentlyViewed(data?.map(r => r.property_id) || []))
    } catch {}
  }, [user, dispatch])

  const getLandlordProperties = async () => {
    const { data, error } = await supabase.from('properties').select('*').eq('landlord_id', user.id).order('created_at', { ascending: false })
    if (error) throw error
    return data || []
  }

  const getRecommendedProperties = useCallback(() => {
    // If no listings or no quiz data, return empty
    if (!listings || listings.length === 0 || !profile?.onboarding_data) return []

    const prefs = profile.onboarding_data

    // If user explicitly skipped or haven't finished quiz
    if (prefs?.skipped || !prefs?.persona) return []

    let filtered = [...listings]

    // 1. Strict filtering (City + Type)
    if (prefs?.type) {
      filtered = filtered.filter(p => p.type === prefs.type)
    }
    
    if (prefs?.city) {
      filtered = filtered.filter(p => 
        p.city?.toLowerCase() === prefs.city.toLowerCase() || 
        p.address?.toLowerCase().includes(prefs.city.toLowerCase())
      )
    }

    // 2. Budget filtering
    if (prefs?.budget?.range) {
      const [min, max] = prefs.budget.range
      filtered = filtered.filter(p => p.price >= min && p.price <= max)
    }

    // 3. Fallback logic: if strictly filtered is empty, try type only
    if (filtered.length === 0 && prefs?.type) {
      filtered = listings.filter(p => p.type === prefs.type).slice(0, 10)
    }

    // Sort randomly and limit to 8 results for the section
    return filtered.sort(() => 0.5 - Math.random()).slice(0, 8)
  }, [listings, profile])

  return {
    listings, featured, currentProperty, favorites, recentlyViewed, filters,
    loading, hasMore, page, totalCount,
    fetchProperties, fetchFeatured, fetchByType, fetchPropertyById,
    createProperty, updateProperty, deleteProperty,
    fetchFavorites, toggleFavorite, fetchRecentlyViewed, getLandlordProperties,
    updateFilters: useCallback((f) => dispatch(setFilters(f)), [dispatch]),
    resetFilters: useCallback(() => dispatch(resetFilters()), [dispatch]),
    getRecommendedProperties,
    fetchGatedData,
    reviews, reviewsLoading,
    fetchReviews, submitReview, deleteReview
  }
}

import React, { useState, useEffect, useMemo, useCallback } from 'react'
