             <button
               type="button"
               onClick={() => findSimilar(property)}
               className="py-2 text-xs font-bold rounded-lg border border-gray-200 text-gray-700 hover:bg-gray-50 transition-colors"
               aria-label="Find similar properties"
             >
               Find Similar
