                           const seed = (p.id || '').split('').reduce((acc, char) => acc + char.charCodeAt(0), 0)
                           const top = 15 + ((seed * 13) % 70) // 15% to 85%
                           const left = 10 + ((seed * 17) % 80) // 10% to 90%

                           return (
                             <div 
                               key={`marker-${p.id}`}
                               className="absolute group cursor-pointer"
                               style={{ top: `${top}%`, left: `${left}%` }}
                               onClick={() => {
