                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Rent (Monthly)</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center font-bold text-gray-900">₹{Number(p.price).toLocaleString('en-IN')}</td>
                      ))}
                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Location</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center">{p.area || 'Central'}, {p.city}</td>
                      ))}
                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Estimated EMI</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center font-medium">₹{p.emi.toLocaleString('en-IN')}</td>
                      ))}
                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Investment Growth</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center text-emerald-600 font-bold">+{p.investment.growth}%</td>
                      ))}
                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Amenities</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center text-[10px] text-gray-400">
                          {p.amenities?.slice(0, 3).join(', ') || 'N/A'}
                        </td>
                      ))}
                    </tr>
                    <tr className="border-b border-gray-100">
                      <td className="py-3 px-4 font-semibold text-gray-500">Transit Distance</td>
                      {comparedProperties.map(p => (
                        <td key={p.id} className="py-3 px-4 text-center">{p.distances.metro} km</td>
                      ))}
                    </tr>
                  </tbody>
                </table>
              </div>

              <div className="p-6 bg-slate-50 border-t border-gray-200 flex justify-end gap-3">
                <Button variant="secondary" onClick={() => setShowComparison(false)}>Close View</Button>
                <Button variant="primary" className="bg-[#CA3433] hover:bg-[#b02c2b] text-white font-extrabold" onClick={() => { setShowComparison(false); handleDownloadPDF(); }}>Print Comparison</Button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

    </div>
  )
}

import React, { useState } from 'react'
import { useDispatch } from 'react-redux'
import { useNavigate } from 'react-router-dom'
import { Mail, Lock, User, Eye, EyeOff, Home, GraduationCap, Utensils, CheckCircle2, Sparkles, ArrowRight } from 'lucide-react'
import { Button } from '../components/ui/Button'
import { Input } from '../components/ui/Input'
import { useAuth } from '../hooks/useAuth'
import toast from 'react-hot-toast'
import { motion, AnimatePresence } from 'framer-motion'

const ROLE_OPTIONS = [
  { value: 'user',             label: 'Student / Professional', icon: <GraduationCap size={20} className="text-brand-500" />, desc: 'Find PGs, Hostels & Flats' },
  { value: 'landlord',         label: 'Landlord / Owner',        icon: <Home size={20} className="text-brand-500" />, desc: 'List & Manage Properties' },
  { value: 'service_provider', label: 'Service Provider 🍱',    icon: <Utensils size={20} className="text-brand-500" />, desc: 'Offer Tiffin or Laundry' },
]

export const AuthHome = () => {
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const { signIn, signUp, signInWithGoogle } = useAuth()

  const [tab, setTab] = useState('login')
  const [loading, setLoading] = useState(false)
  const [googleLoading, setGoogleLoading] = useState(false)
  const [showPass, setShowPass] = useState(false)
  const [selectedRole, setSelectedRole] = useState('user')
  const [form, setForm] = useState({ name: '', email: '', password: '' })
  const [errors, setErrors] = useState({})

  const validate = () => {
    const e = {}
    if (tab === 'signup' && !form.name.trim()) e.name = 'Name is required'
    if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) e.email = 'Valid email required'
    if (form.password.length < 8) e.password = 'Min 8 characters'
    setErrors(e)
    return !Object.keys(e).length
  }

  const handleSubmit = async (e) => {
    if (e) e.preventDefault()
    if (!validate()) return
    setLoading(true)
    try {
      if (tab === 'login') {
        await signIn({ email: form.email, password: form.password })
        toast.success('Welcome back!')
        navigate('/search')
      } else {
        await signUp({ email: form.email, password: form.password, name: form.name, role: selectedRole })
        toast.success('Account created!')
        if (selectedRole === 'landlord') navigate('/landlord')
        else if (selectedRole === 'service_provider') navigate('/service-provider')
        else navigate('/search')
      }
    } catch (err) {
      toast.error(err.message || 'Something went wrong')
    } finally {
      setLoading(false)
    }
  }

  const handleGoogle = async () => {
    setGoogleLoading(true)
    try {
      await signInWithGoogle()
    } catch (err) {
      toast.error(err.message || 'Google sign-in failed')
      setGoogleLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white relative overflow-hidden">
      
      {/* Decorative blobs */}
      <div className="absolute -top-24 -left-24 w-96 h-96 bg-red-50 rounded-full blur-3xl opacity-50 z-0 animate-pulse" />
      <div className="absolute -bottom-24 -right-24 w-[500px] h-[500px] bg-red-50 rounded-full blur-3xl opacity-30 z-0" />

      {/* Hero Content Section */}
      <div className="md:w-1/2 flex flex-col justify-center p-8 sm:p-12 lg:p-20 relative z-10">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="mb-12"
        >
          <div className="flex items-center gap-2 mb-8">
            <div className="w-10 h-10 bg-[#CA3433] rounded-xl flex items-center justify-center shadow-lg shadow-red-500/30">
              <Sparkles size={20} className="text-white fill-current" />
            </div>
            <span className="text-2xl font-black text-gray-900 tracking-tighter">GoEazy<span className="text-[#CA3433]">.</span></span>
          </div>

          <h1 className="text-5xl lg:text-7xl font-black text-gray-900 leading-[0.9] tracking-tighter mb-6">
            Everything you need for <span className="text-[#CA3433] italic">Easy</span> living.
          </h1>
          <p className="text-lg text-gray-500 font-medium max-w-md leading-relaxed">
            Simplifying your hunt for PGs, hostles, and service providers in your city. One account, endless ease.
          </p>
        </motion.div>

        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.4 }}
          className="space-y-4"
        >
          <div className="flex items-center gap-3 text-sm font-bold text-gray-700">
            <CheckCircle2 size={18} className="text-green-500" />
            Verified High-Quality Listings
          </div>
          <div className="flex items-center gap-3 text-sm font-bold text-gray-700">
            <CheckCircle2 size={18} className="text-green-500" />
            Direct Owner & Service Contact
          </div>
          <div className="flex items-center gap-3 text-sm font-bold text-gray-700">
            <CheckCircle2 size={18} className="text-green-500" />
            Zero Commission Architecture
          </div>
        </motion.div>
      </div>

      {/* Auth Form Section */}
      <div className="md:w-1/2 flex items-center justify-center p-6 sm:p-12 lg:p-20 bg-gray-50/30 relative z-10">
        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.5 }}
          className="w-full max-w-[480px] bg-white p-8 sm:p-10 rounded-[2.5rem] shadow-[0_24px_80px_rgba(0,0,0,0.06)] border border-gray-100"
        >
          {/* Form Tabs */}
          <div className="flex gap-2 p-1 bg-gray-100/80 rounded-2xl mb-10">
            {['login', 'signup'].map(t => (
              <button
                key={t}
                onClick={() => { setTab(t); setErrors({}) }}
                className={`flex-1 py-3.5 rounded-xl text-sm font-bold transition-all ${
                  tab === t ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:bg-white/50'
                }`}
              >
                {t === 'login' ? 'Sign In' : 'Join Now'}
              </button>
            ))}
          </div>

          <h2 className="text-3xl font-black text-gray-900 mb-2 tracking-tight">
            {tab === 'login' ? 'Welcome Back!' : 'Create your journey'}
          </h2>
          <p className="text-gray-400 font-medium mb-8">
            {tab === 'login' ? 'Continue with your credentials.' : 'Fill the details below to get started.'}
          </p>

          <form onSubmit={handleSubmit} className="space-y-6">
            <AnimatePresence mode="wait">
              <motion.div
                key={tab}
                initial={{ opacity: 0, x: 10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
                className="space-y-4"
              >
                {tab === 'signup' && (
                  <Input
                    label="Full Name"
                    placeholder="e.g. Priyanshu Negi"
                    leftIcon={<User size={18} />}
                    value={form.name}
                    onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                    error={errors.name}
                  />
                )}

                <Input
                  label="Email Address"
                  type="email"
                  placeholder="name@email.com"
                  leftIcon={<Mail size={18} />}
                  value={form.email}
                  onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                  error={errors.email}
                />

                <Input
                  label="Password"
                  type={showPass ? 'text' : 'password'}
                  placeholder="Min 8 characters"
                  leftIcon={<Lock size={18} />}
                  rightIcon={
                    <button type="button" onClick={() => setShowPass(!showPass)}>
                      {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>
                  }
                  value={form.password}
                  onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                  error={errors.password}
                />

                {tab === 'signup' && (
                  <div className="pt-2">
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3">Join GoEazy as</p>
                    <div className="grid grid-cols-1 gap-3">
                      {ROLE_OPTIONS.map(opt => (
                        <button
                          key={opt.value}
                          type="button"
                          onClick={() => setSelectedRole(opt.value)}
                          className={`flex items-center gap-4 p-4 rounded-2xl border-2 text-left transition-all ${
                            selectedRole === opt.value ? 'border-[#CA3433] bg-red-50/50' : 'border-gray-100 hover:border-gray-200'
                          }`}
                        >
                          <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${selectedRole === opt.value ? 'bg-[#CA3433] text-white' : 'bg-gray-50 text-gray-400'}`}>
                            {opt.icon}
                          </div>
                          <div>
                            <h4 className="font-bold text-sm text-gray-900">{opt.label}</h4>
                            <p className="text-[10px] text-gray-400 font-medium">{opt.desc}</p>
                          </div>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </motion.div>
            </AnimatePresence>

            <Button type="submit" variant="primary" size="lg" className="w-full py-6 rounded-2xl bg-[#CA3433] shadow-xl shadow-red-500/20 text-lg group" loading={loading}>
              <span className="flex items-center justify-center gap-2">
                {tab === 'login' ? 'Sign In' : 'Create Account'}
                <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
              </span>
            </Button>
          </form>

          <div className="relative flex items-center gap-4 my-8">
            <div className="flex-1 h-px bg-gray-100" />
            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">or</span>
            <div className="flex-1 h-px bg-gray-100" />
          </div>

          <Button 
            variant="secondary" 
            size="lg" 
            className="w-full py-4 rounded-2xl border-gray-100 hover:bg-gray-50 flex items-center justify-center gap-3 font-bold"
            loading={googleLoading}
            onClick={handleGoogle}
          >
            <svg width="22" height="22" viewBox="0 0 24 24">
              <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
              <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
              <path fill="#FBBC05" d="M5.84 14.1c-.22-.66-.35-1.36-.35-2.1s.13-1.44.35-2.1V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.83z"/>
              <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.83c.87-2.6 3.3-4.52 6.16-4.52z"/>
            </svg>
            Continue with Google
          </Button>
        </motion.div>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Plus, Home, Eye, Edit, Trash2, ArrowRight, ArrowLeft, List as ListIcon, Calendar, Check, X } from 'lucide-react'
import { useAuth } from '../hooks/useAuth'
import { useProperties } from '../hooks/useProperties'
import { Button } from '../components/ui/Button'
import { Badge, TypeBadge } from '../components/ui/Badge'
import { PropertyCard } from '../components/property/PropertyCard'
import { formatPriceShort, cn } from '../utils/helpers'
import toast from 'react-hot-toast'
import { Skeleton } from '../components/ui/Skeleton'
import { supabase } from '../lib/supabase'

export const LandlordDashboard = () => {
  const { user, profile } = useAuth()
  const { getLandlordProperties, deleteProperty } = useProperties()
  const navigate = useNavigate()
  
  const [properties, setProperties] = useState([])
  const [loading, setLoading] = useState(true)
  const [showAll, setShowAll] = useState(false)
  const [siteVisits, setSiteVisits] = useState([])
  const [loadingVisits, setLoadingVisits] = useState(true)
  const [actioningVisitId, setActioningVisitId] = useState(null)

  const loadProperties = async () => {
    try {
      const data = await getLandlordProperties()
      setProperties(data)
    } catch (err) {
      console.error('Failed to load properties:', err)
      toast.error('Failed to load listings')
    } finally {
      setLoading(false)
    }
  }

  const loadSiteVisits = async () => {
    try {
      const { data, error } = await supabase
        .from('site_visits')
        .select(`
          *,
          property:properties(id, title),
          renter:profiles!user_id(full_name)
        `)
        .eq('landlord_id', user.id)
        .eq('status', 'pending')
        .order('created_at', { ascending: false })
      
      if (error) throw error
      setSiteVisits(data || [])
    } catch (err) {
      console.error('Failed to load visits:', err)
    } finally {
      setLoadingVisits(false)
    }
  }

  useEffect(() => {
    if (user) {
      loadProperties()
      loadSiteVisits()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user])

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this listing?')) return
    const toastId = toast.loading('Deleting property...')
    try {
      await deleteProperty(id)
      setProperties(prev => prev.filter(p => p.id !== id))
      toast.success('Property deleted permanently', { id: toastId })
    } catch (err) {
      console.error('Delete failed:', err)
      toast.error(err.message || 'Failed to delete property', { id: toastId })
    }
  }

  const handleVisitAction = async (visitId, userId, propertyTitle, action) => {
    setActioningVisitId(visitId)
    try {
      const { error } = await supabase
        .from('site_visits')
        .update({ status: action })
        .eq('id', visitId)
      if (error) throw error

      const msg = `Your site visit request for "${propertyTitle || 'Property'}" has been ${action}.`
      await supabase.from('notifications').insert({
        user_id: userId,
        message: msg
      })

      toast.success(`Visit ${action} successfully`)
      setSiteVisits(prev => prev.filter(v => v.id !== visitId))
    } catch (err) {
      console.error(err)
      toast.error('Failed to update visit status')
    } finally {
      setActioningVisitId(null)
    }
  }

  const totalListings = properties.length
  const totalViews = properties.reduce((sum, p) => sum + (p.views || 0), 0)

  // First 2 for preview, all for "view all" mode
  const previewProperties = properties.slice(0, 2)
  const displayProperties = showAll ? properties : previewProperties

  return (
    <div className="pt-12 lg:pt-0 pb-20 bg-gray-50 min-h-screen">
      <div className="w-full mx-auto px-4 sm:px-6 lg:px-8">
        
        {/* Top Actions */}
        <div className="flex items-center justify-between mb-4">
          <button 
            onClick={() => navigate('/')}
            className="flex items-center gap-1.5 text-sm font-bold text-gray-400 hover:text-[#CA3433] transition-colors group"
          >
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> 
            <span>Back to Home</span>
          </button>
        </div>

        {/* Header Section */}
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mb-8">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-full overflow-hidden border-2 border-[#ffc9c9] bg-gray-200">
               {profile ? (
                 <img src={profile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.email}`} alt="Avatar" className="w-full h-full object-cover"/>
               ) : (
                 <Skeleton variant="circle" className="w-full h-full" />
               )}
            </div>
            <div>
              <h1 className="text-2xl font-bold text-gray-900 font-display">
                {profile ? `Welcome, ${profile?.full_name?.split(' ')[0] || 'Landlord'}!` : <Skeleton className="h-8 w-40" />}
              </h1>
              <p className="text-gray-500">Manage your properties and track views.</p>
            </div>
          </div>
          <Button onClick={() => navigate('/landlord/properties/new')} variant="primary" leftIcon={<Plus size={18} />}>
            New Listing
          </Button>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-10">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center gap-5">
            <div className="text-[#CA3433] shrink-0">
              <Home size={32} />
            </div>
            <div className="flex-1">
              <p className="text-gray-500 text-sm font-medium">Total Listings</p>
              {loading ? <Skeleton className="h-8 w-12 mt-1" /> : <h3 className="text-3xl font-bold text-gray-900">{totalListings}</h3>}
            </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center gap-5">
            <div className="text-green-600 shrink-0">
              <Eye size={32} />
            </div>
            <div className="flex-1">
              <p className="text-gray-500 text-sm font-medium">Total Profile Views</p>
              {loading ? <Skeleton className="h-8 w-12 mt-1" /> : <h3 className="text-3xl font-bold text-gray-900">{totalViews}</h3>}
            </div>
          </div>
        </div>

        {/* Site Visit Requests */}
        {!loadingVisits && siteVisits.length > 0 && (
          <div className="mb-10">
            <h2 className="text-xl font-bold text-gray-900 font-display mb-4 flex items-center gap-2">
              <Calendar size={20} className="text-[#CA3433]" />
              Visit Requests
              <span className="bg-red-100 text-red-600 text-xs px-2 py-0.5 rounded-full font-bold">{siteVisits.length}</span>
            </h2>
            <div className="grid gap-3">
              {siteVisits.map(visit => (
                <div key={visit.id} className="bg-white border border-gray-200 rounded-xl p-4 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 shadow-sm hover:shadow-md transition-all">
                  <div className="min-w-0 flex-1">
                    <h4 className="font-bold text-gray-900 truncate">{visit.property?.title || 'Property'}</h4>
                    <p className="text-sm text-gray-500 mt-0.5">
                      Requested by <span className="font-semibold text-gray-700">{visit.renter?.full_name || 'User'}</span> for <span className="font-semibold text-[#CA3433]">{new Date(visit.visit_date).toLocaleDateString()}</span>
                    </p>
                  </div>
                  <div className="flex items-center gap-2 w-full sm:w-auto mt-2 sm:mt-0 flex-shrink-0">
                    <Button 
                      variant="primary" 
                      size="sm" 
                      onClick={() => handleVisitAction(visit.id, visit.user_id, visit.property?.title, 'approved')}
                      disabled={actioningVisitId === visit.id}
                      className="flex-1 sm:flex-none bg-green-600 hover:bg-green-700 shadow-md shadow-green-600/20"
                    >
                      <Check size={16} className="mr-1" /> Approve
                    </Button>
                    <Button 
                      variant="secondary" 
                      size="sm" 
                      onClick={() => handleVisitAction(visit.id, visit.user_id, visit.property?.title, 'declined')}
                      disabled={actioningVisitId === visit.id}
                      className="flex-1 sm:flex-none text-red-600 hover:bg-red-50 border-red-100"
                    >
                      <X size={16} className="mr-1" /> Decline
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Listings Header */}
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-gray-900 font-display">
            {showAll ? 'All Listings' : 'Your Listings'}
            {!loading && properties.length > 0 && (
              <span className="ml-2 text-sm font-normal text-gray-400">
                {showAll ? `(${properties.length})` : `(${Math.min(2, properties.length)} of ${properties.length})`}
              </span>
            )}
          </h2>
          {!loading && properties.length > 2 && (
            <button
              onClick={() => setShowAll(v => !v)}
              className="flex items-center gap-1.5 text-sm font-bold text-[#CA3433] hover:text-[#a52a2a] transition-colors"
            >
              {showAll ? (
                <><Home size={15} /> Show Less</>
              ) : (
                <>View All <ArrowRight size={15} /></>
              )}
            </button>
          )}
        </div>

        {/* Loading State */}
        {loading ? (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3 sm:gap-6">
            {[1, 2].map(i => (
              <div key={i} className="bg-white rounded-2xl border border-gray-100 p-4 space-y-4 shadow-sm">
                <Skeleton className="aspect-[4/3] w-full rounded-xl" />
                <div className="space-y-3 px-1">
                  <div className="flex justify-between">
                    <Skeleton className="h-5 w-1/3" />
                    <Skeleton className="h-5 w-1/4" />
                  </div>
                  <Skeleton className="h-4 w-3/4" />
                </div>
              </div>
            ))}
          </div>
        ) : properties.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-300">
            <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300">
              <Home size={40} />
            </div>
            <h3 className="text-xl font-bold text-gray-900 mb-2">No listings yet</h3>
            <p className="text-gray-500 max-w-sm mx-auto mb-8">
              Start adding your properties to reach thousands of potential renters.
            </p>
            <Button size="lg" className="rounded-2xl px-8 shadow-xl shadow-brand-500/10" onClick={() => navigate('/landlord/properties/new')}>
              List Your First Property
            </Button>
          </div>

        ) : !showAll ? (
          /* ── PREVIEW: standard PropertyCards in responsive grid ── */
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3 sm:gap-6">
            {previewProperties.map(p => (
              <div key={p.id} className="relative">
                <PropertyCard property={p} layout="grid" />
                {/* Management Action Bar */}
                <div className="mt-2 flex items-center justify-between px-1">
                  <div className="flex items-center gap-3">
                    <button 
                      onClick={() => navigate(`/landlord/properties/${p.id}/edit`)}
                      className="text-blue-500 hover:text-blue-700 transition-colors flex items-center gap-1.5 text-xs font-bold"
                    >
                      <Edit size={14} /> Edit
                    </button>
                    <button
                      onClick={() => handleDelete(p.id)}
                      className="text-red-500 hover:text-red-700 transition-colors flex items-center gap-1.5 text-xs font-bold"
                    >
                      <Trash2 size={14} /> Delete
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

        ) : (
          /* ── VIEW ALL: Full list view with management controls ── */
          <div className="grid grid-cols-1 gap-4">
            {displayProperties.map(p => (
              <div 
                key={p.id} 
                className="group bg-white rounded-2xl border border-gray-100 flex gap-4 cursor-pointer shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden"
              >
                {/* Image Section - Auto-fitting Height */}
                <div className="relative w-32 sm:w-40 self-stretch flex-shrink-0 overflow-hidden bg-gray-50 rounded-r-2xl shadow-sm">
                  <img 
                    src={p.images?.[0] || ''} 
                    alt={p.title} 
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" 
                  />
                  <div className="absolute top-2 left-2">
                    <TypeBadge type={p.type} />
                  </div>
                </div>
                
                {/* Info & Actions Section */}
                <div className="flex-1 py-3 flex flex-col justify-between min-w-0 pr-4">
                  <div className="flex flex-col md:flex-row md:items-start justify-between gap-1 md:gap-4">
                    <div className="min-w-0">
                      <h3 className="font-extrabold text-gray-900 text-base sm:text-lg leading-tight line-clamp-1 mb-1">
                        {p.title}
                      </h3>
                      <div className="flex items-center gap-2 flex-wrap">
                        <p className="text-xs text-gray-500 font-medium truncate">
                          {p.area}, {p.city}
                        </p>
                        <Badge variant={p.availability ? 'success' : 'danger'} className="uppercase text-[7px] tracking-widest px-1 py-0.5 font-bold leading-none">
                          {p.availability ? 'Available' : 'Rented'}
                        </Badge>
                      </div>
                    </div>
                    <div className="shrink-0">
                      <span className="font-black text-lg text-[#CA3433] leading-none">
                        {formatPriceShort(p.price)}
                      </span>
                    </div>
                  </div>

                  <div className="flex items-end justify-between mt-auto">
                    <div className="flex items-center gap-4 text-xs text-gray-400">
                      <span className="flex items-center gap-1.5 font-bold">
                        <Eye size={12} className="text-gray-400"/>
                        <span className="text-gray-700">{p.views || 0}</span>
                      </span>
                    </div>

                    <div className="flex items-center gap-4">
                      <button 
                        onClick={(e) => { e.stopPropagation(); navigate(`/property/${p.id}`) }}
                        className="text-gray-500 hover:text-gray-900 transition-colors text-xs font-bold flex items-center gap-1.5"
                        title="View"
                      >
                        <Eye size={16} /> <span className="hidden sm:inline">View</span>
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); navigate(`/landlord/properties/${p.id}/edit`) }}
                        className="text-blue-500 hover:text-blue-700 transition-colors text-xs font-bold flex items-center gap-1.5"
                        title="Edit"
                      >
                        <Edit size={16} /> <span className="hidden sm:inline">Edit</span>
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDelete(p.id) }}
                        className="text-red-500 hover:text-red-700 transition-colors"
                        title="Delete"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* View All CTA below cards when in preview mode */}

      </div>
    </div>
  )
}

import React, { useEffect, useState, useMemo } from 'react'
import { useDispatch } from 'react-redux'
import { useSearchParams } from 'react-router-dom'
import { Search, Filter, ChevronDown, Grid, List as ListIcon, RefreshCw, MapPin, ArrowLeft } from 'lucide-react'
import { useNavigate } from 'react-router-dom'
import { useServices } from '../hooks/useServices'
import { ServiceCard } from '../components/services/ServiceCard'
import { Button } from '../components/ui/Button'
import { Skeleton } from '../components/ui/Skeleton'
import { resetServiceFilters } from '../store/serviceSlice'
import { useTranslation } from 'react-i18next'

const UK_CITIES = [
  'Dehradun', 'Srinagar', 'Rishikesh', 'Haldwani', 'Nainital', 'Haridwar', 'Roorkee', 'Rudrapur'
]

export const NearbyServices = () => {
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const { t } = useTranslation()
  const [searchParams] = useSearchParams()
  const { services, filters, loading, hasMore, fetchServices, updateFilters } = useServices()

  const [viewMode, setViewMode] = useState('grid')
  const [searchInput, setSearchInput] = useState('')
  const [showCityDropdown, setShowCityDropdown] = useState(false)
  const [showFilters, setShowFilters] = useState(false)
  const [localFilters, setLocalFilters] = useState({
    city: filters.city || '', 
    area: filters.area || '', 
    category: filters.category || '',
    sortBy: filters.sortBy || 'created_at', 
    sortOrder: filters.sortOrder || 'desc'
  })

  // Dynamic categories and sort options to support language switching
  const CATEGORIES = useMemo(() => [
    { value: '',         label: t('nearby.categories.all'), emoji: '✨' },
    { value: 'tiffin',  label: t('nearby.categories.tiffin'), emoji: '🍱' },
    { value: 'laundry', label: t('nearby.categories.laundry'), emoji: '🧺' },
    { value: 'cleaning',label: t('nearby.categories.cleaning'), emoji: '🧹' },
  ], [t])

  const serviceSortOptions = useMemo(() => [
    { value: 'created_at:desc', label: t('nearby.sort.newest') },
    { value: 'created_at:asc',  label: t('nearby.sort.oldest') },
    { value: 'views:desc',       label: t('nearby.sort.popular') },
  ], [t])

  // Read ?category= from URL
  useEffect(() => {
    const cat = searchParams.get('category')
    if (cat && ['tiffin', 'laundry', 'cleaning'].includes(cat) && filters.category !== cat) {
      updateFilters({ category: cat })
    }
  }, [searchParams])

  // Fetch whenever filters change
  useEffect(() => {
    fetchServices(true)
  }, [filters, fetchServices])

  useEffect(() => {
    // eslint-disable-next-line
    setLocalFilters({
      city: filters.city || '', 
      area: filters.area || '', 
      category: filters.category || '',
      sortBy: filters.sortBy || 'created_at', 
      sortOrder: filters.sortOrder || 'desc'
    })
  }, [filters])

  const applyFilters = () => {
    updateFilters(localFilters)
    setShowFilters(false)
  }

  const renderFilterContent = () => (
    <div className="space-y-6">
      {/* Location Selection */}
      <div>
        <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">{t('nearby.locationSel')}</h4>
        <div className="grid grid-cols-2 gap-3">
           <div className="flex flex-col gap-1.5">
             <div className="flex bg-gray-50 rounded-xl overflow-hidden border border-gray-200 focus-within:border-[#CA3433]/50 transition-colors pr-2">
               <input 
                 type="text" 
                 placeholder={t('nearby.cityPlaceholder')} 
                 className="w-full bg-transparent border-none text-sm py-2.5 px-3 focus:ring-0 outline-none" 
                 value={localFilters.city} 
                 onChange={e => setLocalFilters(prev => ({...prev, city: e.target.value}))} 
               />
             </div>
           </div>
           <div className="flex flex-col gap-1.5">
             <div className="flex bg-gray-50 rounded-xl overflow-hidden border border-gray-200 focus-within:border-[#CA3433]/50 transition-colors pr-2">
               <input 
                 type="text" 
                 placeholder={t('nearby.areaPlaceholder')} 
                 className="w-full bg-transparent border-none text-sm py-2.5 px-3 focus:ring-0 outline-none" 
                 value={localFilters.area} 
                 onChange={e => setLocalFilters(prev => ({...prev, area: e.target.value}))} 
               />
             </div>
           </div>
        </div>
      </div>

      {/* Sort By */}
      <div>
        <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">{t('nearby.sortBy')}</h4>
        <div className="grid grid-cols-3 gap-2">
          {serviceSortOptions.map(opt => (
            <button
              key={opt.value}
              onClick={() => {
                const [by, ord] = opt.value.split(':');
                setLocalFilters(prev => ({ ...prev, sortBy: by, sortOrder: ord }));
              }}
              className={`px-2 py-2 rounded-xl text-[10px] font-bold transition-all border ${localFilters.sortBy + ':' + localFilters.sortOrder === opt.value ? 'bg-red-50 text-[#CA3433] border-[#CA3433]/30 shadow-sm' : 'border-gray-100 text-gray-600 hover:bg-gray-50'}`}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      {/* Service Type */}
      <div>
        <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block">{t('nearby.category')}</h4>
        <div className="flex flex-wrap gap-2">
          {CATEGORIES.map(cat => (
            <button
              key={cat.value}
              onClick={() => setLocalFilters(prev => ({ ...prev, category: cat.value }))}
              className={`px-4 py-2 rounded-xl text-[12px] font-bold transition-all border ${localFilters.category === cat.value ? 'bg-[#fdf2f2] text-[#CA3433] border-[#CA3433]/30 shadow-sm' : 'border-gray-100 text-gray-600 hover:bg-gray-50'}`}
            >
              {cat.emoji} {cat.label}
            </button>
          ))}
        </div>
      </div>

      <div className="pt-4 flex gap-3 border-t border-gray-100">
        <Button variant="secondary" className="flex-1 bg-white hover:bg-gray-50 border border-gray-100 rounded-xl font-bold py-2.5 text-xs" onClick={() => { dispatch(resetServiceFilters()); setShowFilters(false); }}>{t('nearby.reset')}</Button>
        <Button variant="primary" className="flex-1 rounded-xl shadow-lg shadow-[#CA3433]/10 font-bold py-2.5 text-xs" onClick={applyFilters}>{t('nearby.showResults')}</Button>
      </div>
    </div>
  )
  // eslint-disable-next-line
  const filterContent = useMemo(() => renderFilterContent(), [localFilters, showFilters, dispatch, t, CATEGORIES, serviceSortOptions])

  // Live search handler
  const handleSearch = (e) => {
    const val = e.target.value
    setSearchInput(val)
    updateFilters({ query: val })
  }

  return (
    <div className="pt-6 pb-16 min-h-screen bg-gray-50/50">
      <div className="w-full px-0 sm:px-0 md:px-0 lg:px-0">

        {/* ── Back Button ──────────────────────────────────── */}
        <div className="px-2 sm:px-4 mb-4">
          <button 
            onClick={() => navigate('/')} 
            className="flex items-center gap-2 text-sm font-bold text-gray-500 hover:text-gray-900 transition-colors"
          >
            <ArrowLeft size={16} /> {t('nearby.backHome')}
          </button>
        </div>

        {/* ── Page Header (Centered) ──────────────────────────────────── */}
        <div className="mb-4 px-2 sm:px-4 text-center">
          <h1 className="text-3xl sm:text-4xl md:text-5xl font-black text-gray-900 tracking-tighter font-display uppercase">
            {t('nearby.header')} <span className="text-[#CA3433]">{t('nearby.services')}</span>
          </h1>
        </div>

        {/* ── Search Bar + State Filter Row ────────────────── */}
        {/* ── Search + Filter Section (Synced with Search Page padding) ────────────────────── */}
        <div className="mb-4 px-2 sm:px-4 flex flex-col gap-4">
          <div className="flex flex-row gap-3 items-center w-full">
            {/* City selector (Compact on mobile, height-matched with search bar) */}
            <div className="relative shrink-0 flex items-center">
              <button
                onClick={() => setShowCityDropdown(v => !v)}
                className={`flex items-center gap-2 sm:gap-3 px-2 sm:px-4 py-1.5 sm:py-2 bg-white border border-[#CA3433] sm:border-gray-200 rounded-full sm:rounded-2xl transition-all shadow-sm group h-[46px] ${showCityDropdown ? 'border-[#CA3433] ring-4 ring-[#CA3433]/5' : 'hover:border-[#CA3433]'}`}
              >
                <div className="w-7 h-7 sm:w-8 sm:h-8 rounded-full border border-[#CA3433] overflow-hidden bg-gray-50 flex items-center justify-center shrink-0 group-hover:scale-105 transition-transform">
                  <img src="/1.webp" alt="Map" className="w-full h-full object-cover" />
                </div>
                <div className="hidden sm:flex flex-col items-start pr-1 -space-y-0.5">
                  <span className="text-sm font-bold text-gray-950 leading-tight">{t(`cities.${filters.city}`) || t('nearby.allCities')}</span>
                  <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest leading-none">{t('nav.state')}</span>
                </div>
                <ChevronDown size={14} className={`text-gray-400 transition-transform duration-300 ${showCityDropdown ? 'rotate-180 text-[#CA3433]' : ''}`} />
              </button>
              
              {showCityDropdown && (
                <>
                  <div className="fixed inset-0 z-10" onClick={() => setShowCityDropdown(false)} />
                  <div className="absolute left-0 top-full mt-3 w-64 bg-white rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] border border-gray-100 z-50 max-h-[400px] overflow-hidden flex flex-col animate-in fade-in zoom-in-95 duration-200">
                    <div className="p-4 border-b border-gray-50 bg-gray-50/50">
                      <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{t('nearby.selectCity')}</h4>
                    </div>
                    <div className="overflow-y-auto scrollbar-hide py-1">
                      <button
                        onClick={() => { updateFilters({ city: '' }); setShowCityDropdown(false) }}
                        className={`w-full px-5 py-3 text-left text-sm font-bold transition-colors ${!filters.city ? 'text-[#CA3433] bg-red-50' : 'text-gray-700 hover:bg-gray-50'}`}
                      >
                        {t('nearby.allCities')}
                      </button>
                      {UK_CITIES.map(c => (
                        <button
                          key={c}
                          onClick={() => { updateFilters({ city: c }); setShowCityDropdown(false) }}
                          className={`w-full px-5 py-2.5 text-left text-sm font-semibold transition-colors ${filters.city === c ? 'font-bold text-[#CA3433] bg-red-50' : 'text-gray-600 hover:bg-gray-50'}`}
                        >
                          {t(`cities.${c}`)}
                        </button>
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>

            {/* Search Input */}
            <div className="relative flex-1">
              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                id="service-search"
                type="text"
                placeholder={t('nearby.searchPlaceholder')}
                value={searchInput}
                onChange={handleSearch}
                className="w-full pl-11 pr-4 py-3 bg-white border border-[#CA3433] sm:border-gray-200 rounded-full sm:rounded-2xl text-sm focus:outline-none focus:border-[#CA3433] focus:ring-4 focus:ring-[#CA3433]/5 transition-all shadow-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3 w-full">
            {/* Area input (Full width to match row above) */}
            <div className="relative flex-1">
              <MapPin size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
              <input
                type="text"
                placeholder={t('nearby.areaSearchPlaceholder')}
                value={filters.area || ''}
                onChange={e => updateFilters({ area: e.target.value })}
                className="w-full pl-11 pr-4 py-3 bg-white border border-[#CA3433] sm:border-gray-200 rounded-full sm:rounded-2xl text-sm focus:outline-none focus:border-[#CA3433] focus:ring-4 focus:ring-[#CA3433]/5 transition-all shadow-sm"
              />
            </div>

            {/* Advanced Filters Toggle */}
            <div className="relative">
              <button 
                onClick={() => setShowFilters(!showFilters)} 
                className={`flex items-center gap-2 px-6 py-3 bg-white border rounded-full sm:rounded-2xl text-sm font-bold transition-all ${showFilters ? 'border-[#CA3433] text-[#CA3433] shadow-md ring-4 ring-red-50' : 'border-[#CA3433] sm:border-gray-200 text-gray-700 hover:shadow-sm'}`}
              >
                <Filter size={16} />
                <span className="hidden sm:inline">{t('nearby.filters')}</span>
                <ChevronDown size={14} className={`transition-transform duration-300 ${showFilters ? 'rotate-180 text-[#CA3433]' : 'text-gray-400'}`} />
              </button>
              
              {showFilters && (
                <>
                  <div className="fixed inset-0 z-[40] bg-black/5 backdrop-blur-[1px]" onClick={() => setShowFilters(false)}></div>
                  <div className="absolute right-0 top-full mt-3 w-[calc(100vw-2rem)] sm:w-[460px] bg-white rounded-3xl shadow-[0_20px_60px_rgba(0,0,0,0.15)] border border-gray-100 p-6 z-[50] cursor-default overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                    {filterContent}
                  </div>
                </>
              )}
            </div>
          </div>
        </div>

        {/* ── Category Tabs (Full width 0-margin) */}
        <div className="w-full border-t border-b border-gray-100 bg-white flex relative mb-4">
          <div className="absolute right-0 top-0 bottom-0 w-12 bg-gradient-to-l from-white to-transparent z-10 pointer-events-none md:hidden" />
          
          <div className="flex items-center h-16 md:h-16 px-0 gap-4 md:gap-6 overflow-x-auto scrollbar-hide flex-1 scroll-smooth bg-white">
            <button 
              onClick={() => updateFilters({ category: '' })}
              className={`flex items-center gap-2 px-6 h-full font-semibold transition-all shrink-0 ${filters.category === '' ? 'bg-gradient-to-r from-[#E63946] to-[#CA3433] text-white rounded-tr-3xl shadow-[4px_0_15px_rgb(202,52,51,0.2)]' : 'bg-transparent text-gray-600 hover:text-gray-900 border-r border-gray-100'}`}
            >
              <Grid size={18} /> {t('nearby.categories.all')}
            </button>

            <div className="flex items-center gap-8 px-4 font-bold text-sm flex-1 whitespace-nowrap min-w-max">
              {CATEGORIES.slice(1).map(cat => (
                <button 
                  key={cat.value}
                  onClick={() => updateFilters({ category: cat.value })}
                  className={`flex items-center gap-2 h-16 border-b-[3px] transition-all px-2 group/tab ${filters.category === cat.value ? "border-[#CA3433] text-[#CA3433] bg-[#fff5f5]" : "border-transparent text-gray-500 hover:text-gray-900"}`}
                >
                  <span className="group-hover/tab:scale-110 transition-transform duration-200">
                    {cat.emoji}
                  </span>
                  {cat.label}
                </button>
              ))}
            </div>
          </div>
          
          {/* View toggles (desktop) */}
          <div className="hidden md:flex items-center gap-2 ml-auto h-16 bg-white px-4 border-l border-gray-100">
            <button onClick={() => setViewMode('grid')} className={`p-2 rounded-lg border transition-all ${viewMode === 'grid' ? 'border-[#CA3433] text-[#CA3433] bg-[#fff5f5]' : 'border-transparent text-gray-400 hover:text-gray-900'}`}>
              <Grid size={18} />
            </button>
            <button onClick={() => setViewMode('list')} className={`p-2 rounded-lg border transition-all ${viewMode === 'list' ? 'border-[#CA3433] text-[#CA3433] bg-[#fff5f5]' : 'border-transparent text-gray-400 hover:text-gray-900'}`}>
              <ListIcon size={18} />
            </button>
          </div>
        </div>

        {/* ── Results Count & Layout Switch (Synced with Search Page padding) ─────────────────────────────────── */}
        <div className="px-2 sm:px-4 mb-4 flex items-center justify-between gap-4">
          <p className="text-[10px] sm:text-sm text-gray-400 font-bold uppercase tracking-widest leading-none">
            {loading ? t('nearby.searching') : t('nearby.providersFound', { count: services.length })}
          </p>

          {/* Mobile view switchers */}
          <div className="md:hidden flex items-center gap-1.5 p-1 bg-white border border-gray-100 rounded-xl shadow-sm">
            <button 
              onClick={() => setViewMode('grid')} 
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-red-50 text-[#CA3433]' : 'text-gray-400'}`}
              aria-label="Grid View"
            >
              <Grid size={16} />
            </button>
            <button 
              onClick={() => setViewMode('list')} 
              className={`p-1.5 rounded-lg transition-all ${viewMode === 'list' ? 'bg-red-50 text-[#CA3433]' : 'text-gray-400'}`}
              aria-label="List View"
            >
              <ListIcon size={16} />
            </button>
          </div>
        </div>

        {/* ── Results Grid (Synced with Search Page padding) ─────────────────────────────────── */}
        <div className="px-2 sm:px-4">
          {loading && services.length === 0 ? (
          <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-3 sm:gap-5">
            {[1,2,3,4,5,6].map(i => (
              <div key={i} className="bg-white rounded-2xl border border-gray-100 overflow-hidden">
                <Skeleton className="h-1.5 w-full" />
                <div className="p-4 space-y-3">
                  <div className="flex justify-between">
                    <Skeleton className="h-5 w-20 rounded-full" />
                    <Skeleton className="h-5 w-14 rounded-full" />
                  </div>
                  <Skeleton className="h-5 w-3/4" />
                  <Skeleton className="h-4 w-1/2" />
                  <Skeleton className="h-3 w-full" />
                  <Skeleton className="h-3 w-2/3" />
                </div>
              </div>
            ))}
          </div>
        ) : services.length > 0 ? (
          <>
            <div className={`grid gap-3 sm:gap-5 ${viewMode === 'grid' ? 'grid-cols-2 lg:grid-cols-3 xl:grid-cols-5' : 'grid-cols-1'}`}>
              {services.map(s => (
                <ServiceCard key={s.id} service={s} layout={viewMode} />
              ))}
            </div>
            {hasMore && (
              <div className="mt-12 text-center pb-10">
                <Button variant="secondary" onClick={() => fetchServices(false)} loading={loading} className="px-10 rounded-2xl border-gray-200">
                  {t('nearby.loadMore')}
                </Button>
              </div>
            )}
          </>
        ) : (
          <div className="bg-white rounded-3xl p-16 md:p-24 text-center border border-dashed border-gray-200 shadow-sm mx-4 sm:mx-10 md:mx-16 lg:mx-20">
            <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6">
               <Search className="text-gray-300" size={32} />
            </div>
            <h3 className="text-xl font-bold text-gray-900 mb-2">{t('nearby.noFound')}</h3>
            <p className="text-gray-500 max-w-xs mx-auto mb-8">{t('nearby.noFoundDesc')}</p>
            <Button variant="secondary" onClick={() => { dispatch(resetServiceFilters()); setSearchInput('') }} className="rounded-xl border-gray-200">
              {t('nearby.reset')}
            </Button>
          </div>
        )}
      </div>
     </div>
    </div>
  )
}

import React, { useEffect, useState, useRef } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { 
  MapPin, Heart, Share2, Phone, Mail, ArrowLeft, 
  CheckCircle2, ChevronDown, ChevronUp, Lock, EyeOff, X, 
  Star, Trash2, Sparkles, Calendar 
} from 'lucide-react'
import { Swiper, SwiperSlide } from 'swiper/react'
import { Autoplay, Pagination, Navigation } from 'swiper/modules'
import 'swiper/css'
import 'swiper/css/pagination'
import 'swiper/css/navigation'
import { useSelector, useDispatch } from 'react-redux'
import { openAuthModal } from '../store/authSlice'
import { useProperties } from '../hooks/useProperties'
import { TypeBadge } from '../components/ui/Badge'
import { Button } from '../components/ui/Button'
import { formatPrice, AMENITY_ICONS } from '../utils/helpers'
import { supabase } from '../lib/supabase'
import toast from 'react-hot-toast'
import { useTranslation } from 'react-i18next'
import { Skeleton } from '../components/ui/Skeleton'
import { LocationViewer } from '../components/map/LocationViewer'

const StarRating = ({ value, onChange, readonly = false }) => (
  <div className="flex gap-1">
    {[1, 2, 3, 4, 5].map(n => (
      <button
        key={n}
        type="button"
        disabled={readonly}
        onClick={() => onChange && onChange(n)}
        className={`transition-transform ${!readonly ? 'hover:scale-125 cursor-pointer' : 'cursor-default'}`}
      >
        <Star
          size={readonly ? 14 : 22}
          className={n <= value ? 'text-amber-400 fill-amber-400' : 'text-gray-300'}
        />
      </button>
    ))}
  </div>
)

export const PropertyDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const dispatch = useDispatch()
  const { t } = useTranslation()
  const { user } = useSelector(s => s.auth)
  
  const { 
    currentProperty, fetchPropertyById, fetchGatedData, 
    favorites, toggleFavorite, loading,
    reviews, fetchReviews, submitReview, deleteReview
  } = useProperties()

  const [showScrollToTop, setShowScrollToTop] = useState(false)
  const [gatedData, setGatedData] = useState(null)
  
  const [reviewRating, setReviewRating] = useState(0)
  const [reviewText, setReviewText] = useState('')
  const [submittingReview, setSubmittingReview] = useState(false)

  const [visitDate, setVisitDate] = useState('')
  const [bookingVisit, setBookingVisit] = useState(false)
  const [pulseUnlock, setPulseUnlock] = useState(false)
  const visitDateRef = useRef('')

  const [hasUnlocked, setHasUnlocked] = useState(false)
  const [unlocking, setUnlocking] = useState(false)
  const [isGalleryOpen, setIsGalleryOpen] = useState(false)
  const [initialSlideIndex, setInitialSlideIndex] = useState(0)
  
  // State for gallery navigation elements
  const [galleryPrevEl, setGalleryPrevEl] = useState(null)
  const [galleryNextEl, setGalleryNextEl] = useState(null)

  useEffect(() => {
    visitDateRef.current = visitDate
  }, [visitDate])

  useEffect(() => {
    const handleScroll = () => {
      setShowScrollToTop(window.scrollY > 800)
    }
    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  const checkUnlockStatus = async () => {
    if (!user || !id) return
    const { data } = await supabase
      .from('unlocked_properties')
      .select('id')
      .eq('user_id', user.id)
      .eq('property_id', id)
      .maybeSingle()
    if (data) {
      setHasUnlocked(true)
      const gated = await fetchGatedData(id)
      setGatedData(gated)
    }
  }

  useEffect(() => {
    fetchPropertyById(id)
    fetchReviews(id)
    checkUnlockStatus()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id, user, fetchPropertyById, fetchReviews])

  // Also fetch gated data if current user is the landlord
  useEffect(() => {
    const isLandlord = currentProperty && user && currentProperty.landlord_id === user.id
    if (isLandlord && !gatedData) {
      fetchGatedData(id).then(setGatedData)
    }
  }, [currentProperty, user, id, fetchGatedData, gatedData])

  const openGallery = (index) => {
    setInitialSlideIndex(index)
    setIsGalleryOpen(true)
  }

  if (loading || !currentProperty) {
    return (
      <div className="pt-8 pb-20 bg-[#F9F8F6] min-h-screen">
        <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8">
          <Skeleton className="h-6 w-24 mb-6" />
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8 h-[400px] sm:h-[550px]">
             <Skeleton className="md:col-span-2 md:row-span-2 rounded-lg sm:rounded-xl h-full" />
             <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-lg sm:rounded-xl h-full" />
             <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-lg sm:rounded-xl h-full" />
             <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-lg sm:rounded-xl h-full" />
             <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-lg sm:rounded-xl h-full" />
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
              <Skeleton className="h-48 w-full rounded-lg sm:rounded-xl" />
              <Skeleton className="h-64 w-full rounded-lg sm:rounded-xl" />
            </div>
            <div className="lg:col-span-1">
              <Skeleton className="h-96 w-full rounded-lg sm:rounded-xl" />
            </div>
          </div>
        </div>
      </div>
    )
  }

  const p = currentProperty
  const isFav = favorites.includes(p.id)
  const isAvailable = p.availability !== false

  const avgRating = reviews.length > 0
    ? (reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length).toFixed(1)
    : '0.0'

  const myReview = reviews.find(r => r.reviewer_id === user?.id)

  const handleFav = () => {
    if (!user) { dispatch(openAuthModal('signup')); return }
    toggleFavorite(p.id)
  }

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href)
    toast.success(t('property.sections.linkCopied'))
  }

  const submitSiteVisit = async () => {
    if (!user) { dispatch(openAuthModal('login')); return }
    if (p.landlord_id === user.id) { toast.error('You cannot book a visit for your own property'); return }
    if (!visitDate) { toast.error('Please select a date for the visit'); return }
    
    if (!hasUnlocked) {
       setPulseUnlock(true)
       const unlockBtn = document.getElementById('unlock-button')
       if (unlockBtn) unlockBtn.scrollIntoView({ behavior: 'smooth', block: 'center' })
       toast.error('Please unlock contact details to confirm your visit')
       setTimeout(() => setPulseUnlock(false), 2000)
       return
    }
    
    setBookingVisit(true)
    try {
      const { error } = await supabase.from('site_visits').insert({
        property_id: p.id,
        user_id: user.id,
        landlord_id: p.landlord_id,
        visit_date: visitDate,
        status: 'pending'
      })
      if (error) throw error
      toast.success('Visit Request Sent! Track it in your dashboard.')
      setVisitDate('')
    } catch (err) {
      console.error(err)
      toast.error('Failed to book visit.')
    } finally {
      setBookingVisit(false)
    }
  }

  const handleUnlock = async () => {
    if (!user) { dispatch(openAuthModal('login')); return }
    if (unlocking) return
    setUnlocking(true)
    try {
      const { data: { session } } = await supabase.auth.getSession()
      const token = session?.access_token
      
      const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-razorpay-order`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
          'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY
        },
        body: JSON.stringify({ property_id: p.id })
      })

      if (response.status === 409) {
        setHasUnlocked(true)
        await checkUnlockStatus()
        setUnlocking(false)
        return
      }

      const orderData = await response.json()
      const loadRazorpay = () => {
        return new Promise((resolve) => {
          if (window.Razorpay) return resolve(true)
          const script = document.createElement('script')
          script.src = 'https://checkout.razorpay.com/v1/checkout.js'
          script.onload = () => resolve(true)
          script.onerror = () => resolve(false)
          document.body.appendChild(script)
        })
      }

      if (!(await loadRazorpay())) throw new Error('Razorpay SDK failed to load')

      const options = {
        key: import.meta.env.VITE_RAZORPAY_KEY_ID,
        order_id: orderData.id,
        currency: 'INR',
        name: 'GOEAZY',
        description: `Unlock contact details for ${p.title}`,
        handler: async function (response) {
          try {
            setUnlocking(true)
            const verifyResp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/verify-razorpay-payment`, {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`,
                'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY
              },
              body: JSON.stringify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                property_id: p.id
              })
            })
            if (!verifyResp.ok) throw new Error('Payment verification failed')
            toast.success('Payment verified! Contact details unlocked.')
            setHasUnlocked(true)
            checkUnlockStatus() 
            if (visitDateRef.current) {
              const { error: visitErr } = await supabase.from('site_visits').insert({
                 property_id: p.id,
                 user_id: user.id,
                 landlord_id: p.landlord_id,
                 visit_date: visitDateRef.current,
                 status: 'pending'
              });
              if (!visitErr) {
                 toast.success('Visit Request Sent! Track it in your dashboard.')
                 setVisitDate('')
              }
            }
          } catch (vErr) {
            toast.error('Payment verification failed')
          } finally {
            setUnlocking(false)
          }
        },
        prefill: {
          name: user?.user_metadata?.full_name || 'Customer',
          email: user?.email || '',
          contact: user?.user_metadata?.phone || '9999999999'
        },
        theme: { color: '#CA3433' },
        modal: {
          ondismiss: function() {
            setUnlocking(false)
          }
        }
      }
      new window.Razorpay(options).open()
    } catch (err) {
      console.error('Payment initiation error:', err)
      toast.error('Could not initiate payment')
    } finally {
      setUnlocking(false)
    }
  }

  const images = p.images || []
  const otherImages = images.slice(1, 5)

  const renderSlider = (prefix) => (
    <div className="relative w-full aspect-square md:aspect-[4/3] bg-gray-100 rounded-xl sm:rounded-2xl overflow-hidden shadow-md group border border-gray-200/50">
      <Swiper
        key={`${p.id}-${prefix}`}
        modules={[Autoplay, Pagination, Navigation]}
        spaceBetween={0}
        slidesPerView={1}
        navigation={{
          prevEl: `.prev-btn-${prefix}`,
          nextEl: `.next-btn-${prefix}`,
        }}
        pagination={{ clickable: true, dynamicBullets: true }}
        autoplay={{ delay: 4000, disableOnInteraction: false }}
        className="w-full h-full"
      >
        {images.map((img, i) => (
          <SwiperSlide key={i}>
            <div 
              className="w-full h-full cursor-pointer flex items-center justify-center bg-gray-100"
              onClick={() => openGallery(i)}
            >
              <img 
                src={img} 
                alt={`${p.title} - View ${i + 1}`} 
                className="w-full h-full object-contain" 
              />
            </div>
          </SwiperSlide>
        ))}
      </Swiper>

      <button className={`prev-btn-${prefix} absolute left-1 top-1/2 -translate-y-1/2 z-20 p-2 cursor-pointer active:scale-95 transition-all outline-none border-none bg-transparent text-white`}>
        <img src="/swipe-left.svg" alt="Previous" className="w-12 h-12 drop-shadow-[0_2px_4px_rgba(0,0,0,0.3)]" />
      </button>
      <button className={`next-btn-${prefix} absolute right-1 top-1/2 -translate-y-1/2 z-20 p-2 cursor-pointer active:scale-95 transition-all outline-none border-none bg-transparent text-white`}>
        <img src="/swipe-right.svg" alt="Next" className="w-12 h-12 drop-shadow-[0_2px_4px_rgba(0,0,0,0.3)]" />
      </button>
      
      <div className="absolute top-4 right-4 flex gap-2 z-10">
        <button className="bg-white/90 backdrop-blur-sm border-0 rounded-full w-10 h-10 p-0 flex items-center justify-center hover:bg-white text-gray-900 transition-colors shadow-sm cursor-pointer" onClick={handleShare}>
          <Share2 size={18} />
        </button>
        <button className={`bg-white/90 backdrop-blur-sm border-0 rounded-full w-10 h-10 p-0 flex items-center justify-center hover:bg-white transition-colors shadow-sm cursor-pointer ${isFav ? 'text-red-500' : 'text-gray-900'}`} onClick={handleFav}>
          <Heart size={18} fill={isFav ? 'currentColor' : 'none'} />
        </button>
      </div>
    </div>
  )

  return (
    <div className="pt-8 pb-20 bg-[#F9F8F6] min-h-screen">
      <div className="w-full px-4 sm:px-10 md:px-16 lg:px-20">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 mb-6 transition-colors">
          <ArrowLeft size={16} /> {t('property.labels.back')}
        </button>

        {/* MOBILE SLIDER - Top of page */}
        <div className="block lg:hidden w-full mb-6">
          {renderSlider('mobile')}
        </div>

        {/* MAIN CONTENT COLUMNS */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 items-start lg:mt-6">
          
          {/* LEFT COLUMN - CONTENT GRID */}
          <div className="lg:col-span-7 xl:col-span-8 flex flex-col gap-6">
            
            {/* Header Card */}
            <div className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
              <div className="flex justify-between items-start mb-4">
                 <div className="flex flex-col gap-1">
                   <h1 className="text-4xl sm:text-5xl font-extrabold text-gray-900 tracking-tight flex items-center gap-2 font-display">
                     {formatPrice(p.price)}
                   </h1>
                   <div className="flex items-center gap-2 mt-1">
                     <div className="flex items-center gap-1 bg-amber-50 px-2 py-0.5 rounded-lg border border-amber-100">
                       <Star size={14} className="text-amber-500 fill-amber-500" />
                       <span className="text-sm font-bold text-amber-900">{avgRating}</span>
                     </div>
                     <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">• {reviews.length} {t('property.labels.reviews')}</span>
                   </div>
                 </div>
                 <div className="bg-[#E6FF80] px-4 py-1.5 rounded-full text-[#1A1C14] font-bold text-sm tracking-wide">
                   {isAvailable ? t('property.labels.active') : t('property.labels.inactive')}
                 </div>
              </div>
              <div className="flex items-center gap-2 text-sm font-semibold text-gray-800 mb-2 whitespace-nowrap overflow-x-auto scrollbar-hide py-1">
                <span>{t(`property.types.${p.type}`) || p.type}</span>
                <span className="text-gray-300">•</span>
                <span>{p.area}</span>
                <span className="text-gray-300">•</span>
                <span>{t(`cities.${p.city}`) || p.city}</span>
              </div>
              <p className="text-gray-500 text-sm">
                {(hasUnlocked || p.landlord_id === user?.id) ? (gatedData?.exact_location || `${p.area}, ${p.city}`) : `${p.area}, ${p.city} • ${p.pincode}`}
              </p>
            </div>

            {/* Amenities Card */}
            {p.amenities && p.amenities.length > 0 && (
              <div className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                <h2 className="text-2xl font-bold text-gray-900 mb-6 tracking-tight font-display">{t('property.sections.amenities')}</h2>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                  {p.amenities.map(a => (
                    <div key={a} className="flex gap-3 items-center">
                       <div className="w-10 h-10 rounded-full bg-[#F9F8F6] flex items-center justify-center text-gray-600">
                         {(() => {
                           const Icon = AMENITY_ICONS[a];
                           return Icon ? <Icon size={20} /> : null;
                         })()}
                       </div>
                       <span className="font-semibold text-gray-700 capitalize text-[15px]">{a}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* About & Nearby */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {p.description && (
                <div className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                  <h2 className="text-2xl font-bold text-gray-900 mb-4 tracking-tight font-display">{t('property.sections.about')}</h2>
                  <div className="text-gray-600 leading-relaxed whitespace-pre-wrap text-[15px]">{p.description}</div>
                </div>
              )}
              {p.nearby_landmarks && (
                <div className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                   <h2 className="text-2xl font-bold text-gray-900 mb-6 tracking-tight font-display">{t('property.sections.nearby')}</h2>
                   <div className="flex items-start gap-4 p-5 rounded-xl bg-[#F9F8F6]">
                     <MapPin className="text-gray-400 mt-1 flex-shrink-0" size={20} />
                     <p className="text-gray-700 font-medium leading-relaxed">{p.nearby_landmarks}</p>
                   </div>
                </div>
              )}
            </div>

            {/* Location on Map */}
            {gatedData?.latitude && gatedData?.longitude ? (
              <LocationViewer
                latitude={gatedData.latitude}
                longitude={gatedData.longitude}
                title={p.title}
                address={gatedData.exact_location || `${p.area}, ${p.city}`}
              />
            ) : (
              <div className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                <div className="flex items-center justify-between mb-4">
                  <h2 className="text-2xl font-bold text-gray-900 tracking-tight font-display flex items-center gap-2">
                    <MapPin size={22} className="text-gray-300" />
                    {t('property.sections.locationMap')}
                  </h2>
                </div>
                <div className="relative h-[260px] overflow-hidden rounded-xl border border-black/5 bg-slate-50/20 flex items-center justify-center">
                  <div className="absolute inset-0 bg-gray-50 bg-cover opacity-20 grayscale pointer-events-none" style={{ filter: 'blur(4px)' }} />
                  <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#fff5f5]/20 backdrop-blur-[12px] border border-[#CA3433]/20">
                    <div className="w-14 h-14 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center mx-auto mb-3 border border-red-100 shadow-sm text-[#CA3433]">
                      <Lock size={28} />
                    </div>
                    <p className="text-[#CA3433] font-bold tracking-widest text-[12px] uppercase">{t('property.sections.locationLocked')}</p>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* RIGHT COLUMN - SIDEBAR */}
          <div className="lg:col-span-5 xl:col-span-4 flex flex-col gap-6">
            <div className="hidden lg:block w-full">
              {renderSlider('desktop')}
            </div>

            <div id="contact-section" className="bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_24px_rgb(0,0,0,0.04)] border border-gray-100/50">
              <h3 className="text-xl font-bold text-gray-900 mb-6 tracking-tight font-display">{t('property.sections.requestContact')}</h3>
              
              <div className="mb-8 p-6 bg-[#FEF2F2] rounded-2xl border border-red-100 shadow-sm relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-[#CA3433]"></div>
                <h4 className="font-extrabold text-[#CA3433] mb-4 text-[13px] uppercase tracking-wider flex items-center gap-2">
                  <Calendar size={16} />
                  {t('property.sections.bookVisit')}
                </h4>
                <div className="flex flex-col gap-4">
                  <div className="relative w-full">
                    {!visitDate && (
                      <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400 text-sm font-bold flex items-center gap-2">
                         <Calendar size={14} />
                         <span>dd / mm / yyyy</span>
                      </div>
                    )}
                    <input 
                      type="date" 
                      min={new Date().toISOString().split('T')[0]}
                      value={visitDate}
                      onChange={(e) => setVisitDate(e.target.value)}
                      className={`w-full bg-white border border-red-100 rounded-xl px-4 py-3.5 text-sm focus:ring-4 focus:ring-[#CA3433]/10 focus:border-[#CA3433] outline-none transition-all cursor-pointer font-bold shadow-sm appearance-none min-h-[50px] ${visitDate ? 'text-gray-900' : 'text-transparent'}`}
                      style={{ colorScheme: 'light' }}
                    />
                  </div>
                  <Button 
                    variant="primary" 
                    className="w-full rounded-xl py-4 bg-[#CA3433] shadow-lg shadow-[#CA3433]/20 hover:shadow-[#CA3433]/30 transition-all active:scale-[0.97] font-bold text-sm"
                    onClick={submitSiteVisit}
                    disabled={bookingVisit}
                  >
                    {bookingVisit ? (
                      <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : t('property.sections.book')}
                  </Button>
                </div>
                <p className="mt-4 text-[11px] text-gray-500 font-medium">
                  * Direct visit coordinate sharing is available for verified users.
                </p>
              </div>

              <div className="space-y-4 mb-8">
                <div className="p-4 bg-[#F9F8F6] rounded-xl border border-gray-100">
                   <p className="text-xs text-gray-500 font-bold mb-1 uppercase tracking-wider">{t('property.sections.owner')}</p>
                   <p className="font-semibold text-gray-900">{p.profiles?.full_name || 'Listing Owner'}</p>
                </div>

                {user ? (
                    (hasUnlocked || p.landlord_id === user.id) ? (
                      <div className="space-y-3">
                        <a
                          href={`tel:${gatedData?.contact_phone || ''}`}
                          className="flex items-center justify-center gap-3 w-full px-5 py-3.5 rounded-full bg-[#CA3433] text-white font-bold hover:bg-[#ac2d2c] transition-colors text-[15px]"
                        >
                          <Phone size={18} />
                          <span className="tracking-wide">
                            {gatedData?.contact_phone
                              ? gatedData.contact_phone
                              : t('property.sections.callNow')}
                          </span>
                        </a>
                        <a href={`mailto:${gatedData?.contact_email || ''}`} className="flex items-center justify-center gap-2 w-full px-5 py-3.5 rounded-full bg-white border border-gray-200 text-gray-900 font-bold hover:bg-gray-50 transition-colors shadow-sm text-[15px]">
                          <Mail size={18} /> {t('property.sections.sendEmail')}
                        </a>
                      </div>
                    ) : (
                      <div className="border border-red-50 rounded-xl p-6 text-center bg-red-50/10 relative overflow-hidden h-48 flex flex-col items-center justify-center shadow-sm">
                        <div className="absolute inset-0 backdrop-blur-[15px]" />
                        <div className="relative z-10 flex flex-col items-center">
                          <div className="w-12 h-12 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center mx-auto mb-3 border border-red-100 shadow-sm text-[#CA3433]">
                            <EyeOff size={24} />
                          </div>
                          <p className="font-bold text-gray-900 mb-2 font-display text-lg">{t('property.sections.detailsLocked')}</p>
                          <p className="text-[13px] text-gray-500 leading-relaxed max-w-xs mx-auto px-4">{t('property.sections.lockDesc')}</p>
                        </div>
                      </div>
                    )
                  ) : (
                    <div className="border border-gray-100 rounded-xl p-6 text-center bg-[#fcfbf9]">
                      <p className="text-sm text-gray-600 mb-4 font-medium">{t('property.sections.signinPrompt')}</p>
                      <Button variant="secondary" className="w-full rounded-full font-bold bg-white" onClick={() => dispatch(openAuthModal('login'))}>
                        {t('nav.login')}
                      </Button>
                    </div>
                  )}
              </div>

              {((user && !(hasUnlocked || p.landlord_id === user.id)) || !user) && (
                <button 
                  id="unlock-button"
                  onClick={handleUnlock} 
                  disabled={unlocking}
                  className={`w-full bg-gray-900 text-white font-bold text-[15px] py-4 rounded-full hover:bg-black transition-all flex items-center justify-center gap-2 shadow-lg shadow-gray-900/20 active:scale-[0.98] disabled:opacity-70 disabled:cursor-not-allowed ${pulseUnlock ? 'ring-4 ring-[#CA3433] bg-[#CA3433] scale-105 transition-all duration-300' : ''}`}
                >
                  {unlocking ? (
                    <span className="flex items-center gap-2">
                       <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                       {t('property.sections.processing')}
                    </span>
                  ) : (
                    <>
                      <Lock size={18} />
                      <span>{t('property.labels.pay')}</span>
                      <span className="bg-white/20 px-2 py-0.5 rounded-md text-[13px] font-black">₹9</span>
                      <span>{t('property.labels.toUnlock')}</span>
                    </>
                  )}
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Reviews Section */}
        <div className="mt-12 bg-white rounded-lg sm:rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight font-display">{t('property.sections.reviews')}</h2>
              <p className="text-sm text-gray-500 font-medium mt-1">{t('property.sections.authenticFeedback')}</p>
            </div>
            <div className="text-right">
              <p className="text-3xl font-black text-gray-900">{avgRating}</p>
              <div className="flex justify-end gap-0.5 mt-1">
                {[1,2,3,4,5].map(n => (
                  <Star key={n} size={12} className={n <= Math.round(avgRating) ? 'text-amber-400 fill-amber-400' : 'text-gray-200'} />
                ))}
              </div>
            </div>
          </div>

          {user && !myReview && (
            <div className="mb-10 p-6 rounded-2xl bg-[#F9F8F6] border border-gray-100">
              <h4 className="font-bold text-gray-900 mb-4">{t('property.sections.postReview')}</h4>
              <div className="mb-4">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">{t('property.sections.yourRating')}</p>
                <StarRating value={reviewRating} onChange={setReviewRating} />
              </div>
              <div className="mb-4">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">{t('property.sections.yourFeedback')}</p>
                <textarea
                  value={reviewText}
                  onChange={(e) => setReviewText(e.target.value)}
                  placeholder={t('property.sections.reviewPlaceholder')}
                  className="w-full bg-white rounded-xl border border-gray-200 p-4 text-sm focus:ring-2 focus:ring-[#CA3433]/20 focus:border-[#CA3433] outline-none transition-all min-h-[100px]"
                />
              </div>
              <Button
                variant="primary"
                className="w-full sm:w-auto rounded-full px-8 bg-[#CA3433]"
                disabled={submittingReview || !reviewRating || !reviewText.trim()}
                onClick={async () => {
                  setSubmittingReview(true)
                  try {
                    await submitReview(p.id, reviewRating, reviewText)
                    setReviewRating(0)
                    setReviewText('')
                    toast.success(t('property.sections.reviewSuccess'))
                  } catch {
                    toast.error(t('property.sections.reviewError'))
                  } finally {
                    setSubmittingReview(false)
                  }
                }}
              >
                {submittingReview ? t('property.sections.posting') : t('property.sections.postReview')}
              </Button>
            </div>
          )}

          <div className="space-y-6">
            {reviews.length === 0 ? (
              <div className="py-12 text-center bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                <p className="text-sm font-bold text-gray-400 uppercase tracking-widest">{t('property.sections.noReviews')}</p>
              </div>
            ) : (
              reviews.map(review => (
                <div key={review.id} className="pb-6 border-b border-gray-100 last:border-0 last:pb-0">
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex items-center gap-3">
                      <img
                        src={review.profiles?.avatar_url || `https://ui-avatars.com/api/?name=${encodeURIComponent(review.profiles?.full_name || 'User')}`}
                        alt="Reviewer"
                        className="w-10 h-10 rounded-full bg-gray-100 object-cover"
                      />
                      <div>
                        <h5 className="font-bold text-gray-900 text-[15px]">{review.profiles?.full_name || t('property.sections.anonymous')}</h5>
                        <StarRating value={review.rating} readonly />
                      </div>
                    </div>
                    {user && user.id === review.reviewer_id && (
                      <button onClick={() => deleteReview(review.id)} className="text-gray-300 hover:text-red-500 transition-colors">
                        <Trash2 size={14} />
                      </button>
                    )}
                  </div>
                  <p className="text-gray-600 text-sm leading-relaxed pl-13">{review.feedback}</p>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* Mobile Jump Feature */}
      <div className="fixed bottom-6 right-4 sm:hidden z-40">
        <button 
          onClick={() => {
            if (showScrollToTop) window.scrollTo({ top: 0, behavior: 'smooth' });
            else {
              const section = document.getElementById('contact-section');
              if (section) {
                const top = section.getBoundingClientRect().top + window.scrollY - 80;
                window.scrollTo({ top, behavior: 'smooth' });
              }
            }
          }}
          className="flex items-center justify-center w-12 h-12 bg-gray-900 text-white rounded-xl shadow-lg active:scale-95 transition-transform"
        >
          {showScrollToTop ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
        </button>
      </div>

      {/* Gallery Modal */}
      {isGalleryOpen && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex items-center justify-center">
          <button onClick={() => setIsGalleryOpen(false)} className="absolute top-6 right-6 z-[110] text-white/70 hover:text-white transition-colors">
            <X size={32} />
          </button>
          <div className="w-full h-full flex items-center justify-center p-4">
            <Swiper
              modules={[Navigation, Pagination]}
              initialSlide={initialSlideIndex}
              navigation={{ prevEl: galleryPrevEl, nextEl: galleryNextEl }}
              pagination={{ type: 'fraction' }}
              className="w-full h-full"
            >
              {images.map((img, i) => (
                <SwiperSlide key={i} className="flex items-center justify-center">
                  <img src={img} className="max-w-full max-h-full object-contain" alt="" />
                </SwiperSlide>
              ))}
              <button ref={setGalleryPrevEl} className="absolute left-6 top-1/2 -translate-y-1/2 z-50 p-4 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-md text-white">
                <ArrowLeft size={24} />
              </button>
              <button ref={setGalleryNextEl} className="absolute right-6 top-1/2 -translate-y-1/2 z-50 p-4 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-md text-white">
                <Share2 size={24} className="rotate-90" />
              </button>
            </Swiper>
          </div>
        </div>
      )}
    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { PropertyForm } from '../components/property/PropertyForm'
import { ArrowLeft } from 'lucide-react'
import { useProperties } from '../hooks/useProperties'

export const PropertyEdit = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const { fetchPropertyById, currentProperty } = useProperties()
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchPropertyById(id).then(() => setLoading(false))
  }, [id])

  if (loading) {
    return (
      <div className="pt-32 pb-20 bg-gray-50 min-h-screen flex items-center justify-center">
        <div className="skeleton w-32 h-32 rounded-full" />
      </div>
    )
  }

  if (!currentProperty) {
    return (
      <div className="pt-32 pb-20 bg-gray-50 min-h-screen text-center">
        <h1 className="text-2xl font-bold mb-4">Property not found</h1>
        <button className="text-brand-600 hover:underline" onClick={() => navigate('/landlord')}>Return to Dashboard</button>
      </div>
    )
  }

  return (
    <div className="pt-4 pb-20 bg-gray-50 min-h-screen">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 mb-6 transition-colors">
          <ArrowLeft size={16} /> Back to Dashboard
        </button>
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 font-display">Edit Property</h1>
          <p className="text-gray-500 mt-2">Update information for "{currentProperty.title}"</p>
        </div>
        <PropertyForm initialData={currentProperty} isEdit={true} />
      </div>
    </div>
  )
}

import React, { useEffect, useState, useMemo } from 'react'
import { useNavigate } from 'react-router-dom'
import { ChevronLeft, Heart, Search, SlidersHorizontal, ArrowUpDown, X, AlertCircle } from 'lucide-react'
import { useAuth } from '../hooks/useAuth'
import { useProperties } from '../hooks/useProperties'
import { PropertyCard } from '../components/property/PropertyCard'
import { supabase } from '../lib/supabase'
import { MOCK_PROPERTIES, CITIES, PROPERTY_TYPES } from '../utils/constants'
import { Skeleton } from '../components/ui/Skeleton'

