)

export const ServiceDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const dispatch = useDispatch()
  const { user, profile } = useSelector(s => s.auth)

  const { 
    currentService, reviews, reviewsLoading, 
    fetchServiceById, fetchReviews, submitReview, deleteReview,
    fetchServiceGatedData 
  } = useServices()
  const { t } = useTranslation()

  const [contactUnlocked, setContactUnlocked] = useState(false)
  const [gatedData, setGatedData] = useState(null)
  const [reviewRating, setReviewRating] = useState(0)
  const [reviewText, setReviewText] = useState('')
  const [submittingReview, setSubmittingReview] = useState(false)
  const [loading, setLoading] = useState(true)

  const [isGalleryOpen, setIsGalleryOpen] = useState(false)
  const [initialSlideIndex, setInitialSlideIndex] = useState(0)
  const [galleryPrevEl, setGalleryPrevEl] = useState(null)
  const [galleryNextEl, setGalleryNextEl] = useState(null)
  const [showScrollToTop, setShowScrollToTop] = useState(false)

  const service = currentService
  const categoryConfig = getCategoryConfig(t)
  const cat = service ? (categoryConfig[service.category] || {}) : {}
  const images = service?.images || []

  useEffect(() => {
    const handleScroll = () => {
      setShowScrollToTop(window.scrollY > 800)
    }
    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  useEffect(() => {
    const load = async () => {
      setLoading(true)
      await fetchServiceById(id)
      await fetchReviews(id)
      setLoading(false)
    }
    load()
    // eslint-disable-next-line
  }, [id])

  // Check if current user is the provider or has unlocked (if we have unlock records for services)
  useEffect(() => {
    const checkStatus = async () => {
      if (!user || !service || !id) return
      
      const isProvider = service?.provider_id === user.id
      if (isProvider) {
        setContactUnlocked(true)
        const gated = await fetchServiceGatedData(id)
        setGatedData(gated)
      }
    }
    checkStatus()
  }, [service, user, id, fetchServiceGatedData])

  // Check if current user has already reviewed
  const myReview = reviews.find(r => r.reviewer_id === user?.id)

  const avgRating = reviews.length > 0
    ? (reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length).toFixed(1)
    : '0.0'

  const handleUnlockContact = () => {
    if (!user) {
      dispatch(openAuthModal('login'))
      return
    }
    setContactUnlocked(true)
    fetchServiceGatedData(id).then(setGatedData)
    toast.success(t('services.reviews.contactUnlocked'))
  }

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href)
    toast.success(t('property.sections.linkCopied'))
  }

  const handleSubmitReview = async () => {
    if (!user) { dispatch(openAuthModal('login')); return }
    if (reviewRating === 0) { toast.error(t('property.sections.yourRating')) || toast.error('Please select a rating'); return }
    if (!reviewText.trim()) { toast.error(t('property.sections.yourFeedback')) || toast.error('Please write some feedback'); return }

    setSubmittingReview(true)
    try {
      await submitReview(id, reviewRating, reviewText.trim())
      setReviewRating(0); setReviewText('')
      toast.success(myReview ? t('services.reviews.reviewUpdated') : t('services.reviews.reviewSubmitted'))
    } catch (err) {
      toast.error(err.message || t('property.sections.reviewError'))
    } finally {
      setSubmittingReview(false)
    }
  }

  const handleDeleteReview = async (reviewId) => {
    try {
      await deleteReview(reviewId)
      toast.success(t('services.reviews.reviewDeleted'))
    } catch { toast.error(t('property.sections.reviewError')) }
  }

  const openGallery = (index) => {
    setInitialSlideIndex(index)
    setIsGalleryOpen(true)
  }

  const renderSlider = (prefix) => (
    <div className="relative w-full aspect-square md:aspect-[4/3] bg-gray-100 rounded-xl sm:rounded-2xl overflow-hidden shadow-md group border border-gray-200/50">
      <Swiper
        key={`${service?.id}-${prefix}`}
        modules={[Autoplay, Pagination, Navigation]}
        spaceBetween={0}
        slidesPerView={1}
        navigation={{
          prevEl: `.prev-btn-${prefix}`,
          nextEl: `.next-btn-${prefix}`,
        }}
        pagination={{ clickable: true, dynamicBullets: true }}
        autoplay={{ delay: 4000, disableOnInteraction: false }}
        className="w-full h-full"
      >
        {images.length > 0 ? images.map((img, i) => (
          <SwiperSlide key={i}>
            <div className="w-full h-full cursor-pointer flex items-center justify-center bg-gray-100" onClick={() => openGallery(i)}>
              <img src={img} alt={`${service?.name} - View ${i + 1}`} className="w-full h-full object-cover" />
            </div>
          </SwiperSlide>
        )) : (
          <SwiperSlide>
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-50 text-gray-300">
              <span className="text-8xl opacity-30">{cat.emoji}</span>
            </div>
          </SwiperSlide>
        )}
      </Swiper>

      {images.length > 1 && (
        <>
          <button className={`prev-btn-${prefix} absolute left-1 top-1/2 -translate-y-1/2 z-20 p-2 cursor-pointer active:scale-95 transition-all outline-none border-none bg-transparent text-white`}>
            <img src="/swipe-left.svg" alt="Previous" className="w-12 h-12 drop-shadow-[0_2px_4px_rgba(0,0,0,0.3)]" />
          </button>
          <button className={`next-btn-${prefix} absolute right-1 top-1/2 -translate-y-1/2 z-20 p-2 cursor-pointer active:scale-95 transition-all outline-none border-none bg-transparent text-white`}>
            <img src="/swipe-right.svg" alt="Next" className="w-12 h-12 drop-shadow-[0_2px_4px_rgba(0,0,0,0.3)]" />
          </button>
        </>
      )}

      <div className="absolute top-4 right-4 flex gap-2 z-10">
        <button className="bg-white/90 backdrop-blur-sm border-0 rounded-full w-10 h-10 flex items-center justify-center hover:bg-white text-gray-900 transition-colors shadow-sm" onClick={handleShare}>
          <Share2 size={18} />
        </button>
      </div>
    </div>
  )

  if (loading) return (
    <div className="pt-8 pb-20 bg-[#F9F8F6] min-h-screen">
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8">
        <Skeleton className="h-6 w-24 mb-6" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8 h-[400px] sm:h-[550px]">
          <Skeleton className="md:col-span-2 md:row-span-2 rounded-xl h-full" />
          <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-xl h-full" />
          <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-xl h-full" />
          <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-xl h-full" />
          <Skeleton className="hidden md:block col-span-1 row-span-1 rounded-xl h-full" />
        </div>
      </div>
    </div>
  )

  if (!service && !loading) return (
    <div className="pt-20 pb-20 min-h-screen bg-[#F9F8F6] flex flex-col items-center justify-center">
      <div className="text-center max-w-sm mx-auto px-4">
        <div className="text-6xl mb-4">😕</div>
        <h2 className="text-2xl font-extrabold text-gray-900 mb-2">Service Not Found</h2>
        <p className="text-gray-500 text-sm mb-6">This listing may have been removed or is not available yet.</p>
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 mx-auto text-sm font-semibold text-[#CA3433] hover:underline">
          <ArrowLeft size={16} /> Go Back
        </button>
      </div>
    </div>
  )

  return (
    <div className="pt-8 pb-20 bg-[#F9F8F6] min-h-screen">
      <div className="w-full px-4 sm:px-10 md:px-16 lg:px-20">

        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 mb-6 transition-colors">
          <ArrowLeft size={16} /> {t('services.labels.back')}
        </button>

        {/* MOBILE SLIDER */}
        <div className="block lg:hidden w-full mb-6">
          {renderSlider('mobile')}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 items-start lg:mt-6">

          {/* LEFT COLUMN */}
          <div className="lg:col-span-7 xl:col-span-8 flex flex-col gap-6">

            {/* Header Card */}
            <div className="bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
              <div className="flex justify-between items-start mb-4">
                <div className="flex flex-col gap-1">
                  <h1 className="text-2xl sm:text-4xl font-extrabold text-gray-900 tracking-tight font-display">
                    {service.name}
                  </h1>
                  <div className="flex items-center gap-2 text-sm font-semibold text-gray-500">
                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${cat.color} ${cat.border} border`}>
                      {cat.emoji} {cat.label}
                    </span>
                    <span>{service.area}, {t(`cities.${service.city}`) || service.city}</span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-4 mt-6 pt-6 border-t border-gray-50">
                <div className="flex items-center gap-1.5">
                  <div className="flex">
                    <StarRating value={Math.round(parseFloat(avgRating))} readonly />
                  </div>
                  <span className="font-black text-sm text-gray-900">{avgRating}</span>
                  <span className="text-gray-400 text-xs">({reviews.length} {t('property.labels.reviews')})</span>
                </div>
                {service.verification_status === 'verified' && (
                  <span className="flex items-center gap-1 text-xs text-green-600 font-bold bg-green-50 px-2.5 py-1 rounded-full border border-green-100">
                    <CheckCircle2 size={14} /> {t('services.labels.verifiedProvider')}
                  </span>
                )}
              </div>
            </div>

            {/* About & Provider Info (Combined) */}
            <div className="bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
              <h2 className="text-xl font-bold text-gray-900 mb-6 font-display">{t('services.labels.aboutProvider')}</h2>
              <p className="text-sm text-gray-600 leading-relaxed mb-8">
                {service.description || t('services.labels.aboutFallback')}
              </p>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="flex items-start gap-3 p-4 rounded-xl bg-gray-50 border border-gray-100">
                  <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-[#CA3433] shadow-sm border border-red-50">
                    <Briefcase size={18} />
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('services.labels.experience')}</p>
                    <p className="text-sm font-bold text-gray-900">{service.experience || t('services.labels.experienceFallback')}</p>
                  </div>
                </div>
                <div className="flex items-start gap-3 p-4 rounded-xl bg-gray-50 border border-gray-100">
                  <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-[#CA3433] shadow-sm border border-red-50">
                    <Award size={18} />
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('services.labels.speciality')}</p>
                    <p className="text-sm font-bold text-gray-900">{service.speciality || t('services.labels.specialityFallback')}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Service & Pricing Box */}
            {service.service_listings?.length > 0 && (
              <div className="bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                <h2 className="text-xl font-bold text-gray-900 mb-6 font-display">{t('services.labels.pricing')}</h2>
                <div className="space-y-4">
                  {service.service_listings?.map(item => (
                    <div key={item.id} className="flex justify-between items-center p-4 rounded-xl bg-gray-50 border border-gray-100 hover:border-brand-200 transition-colors">
                      <div>
                        <p className="font-bold text-gray-900">{item.service_name}</p>
                        {item.description && <p className="text-xs text-gray-500 mt-0.5">{item.description}</p>}
                      </div>
                      <div className="text-right">
                        <p className="text-lg font-black text-[#CA3433]">₹{item.price?.toLocaleString()}</p>
                        <p className="text-[10px] font-bold text-gray-400 uppercase">{item.unit}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Subscription Plans Box */}
            {service.service_plans?.length > 0 && (
              <div className="bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
                <h2 className="text-xl font-bold text-gray-900 mb-6 font-display">{t('services.labels.plans')}</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {service.service_plans.map(plan => (
                    <div key={plan.id} className="p-5 rounded-xl border border-gray-100 bg-white hover:shadow-md transition-shadow">
                      <div className="flex justify-between items-start mb-2">
                        <p className="font-bold text-gray-900">{plan.plan_name}</p>
                        <div className="w-8 h-8 rounded-full bg-red-50 flex items-center justify-center text-[#CA3433]">
                          <IndianRupee size={16} />
                        </div>
                      </div>
                      <p className="text-2xl font-black text-[#CA3433]">₹{plan.price?.toLocaleString()}</p>
                      {plan.description && <p className="text-xs text-gray-500 mt-2 line-clamp-2">{plan.description}</p>}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Location on Map */}
            {service.latitude && service.longitude && (
              <LocationViewer
                latitude={gatedData?.latitude || service.latitude}
                longitude={gatedData?.longitude || service.longitude}
                title={service.name}
                address={gatedData?.address || service.map_address || service.address || `${service.area}, ${t(`cities.${service.city}`) || service.city}`}
              />
            )}
          </div>

          {/* RIGHT COLUMN */}
          <div className="lg:col-span-5 xl:col-span-4 flex flex-col gap-6">

            {/* DESKTOP SLIDER */}
            <div className="hidden lg:block w-full">
              {renderSlider('desktop')}
            </div>

            {/* CONTACT SIDEBAR (NO WORKING HOURS) */}
            <div id="contact-section" className="bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_24px_rgb(0,0,0,0.04)] border border-gray-100/50 sticky top-24">
              <h3 className="text-xl font-bold text-gray-900 mb-6 font-display">{t('services.labels.contact')}</h3>

              <div className="space-y-4 mb-8">
                <div className="p-4 bg-[#F9F8F6] rounded-xl border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1 uppercase tracking-widest leading-none">{t('services.labels.businessOwner')}</p>
                  <p className="font-bold text-gray-900 text-base">{service.profiles?.full_name || service.name}</p>
                </div>
              </div>

              <div className="mb-8 pt-6 border-t border-gray-50">
                <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2">{t('services.labels.locationDetail')}</h4>
                <div className="flex items-start gap-2">
                  <MapPin size={16} className="text-gray-400 mt-1 shrink-0" />
                  <p className="text-xs text-gray-600 font-medium leading-relaxed">
                    {gatedData?.address || service.address || `${service.area}, ${t(`cities.${service.city}`) || service.city}, ${t('nav.state')}`}
                    {service.landmark && <span className="block mt-1 text-gray-400">{t('services.labels.near')} {service.landmark}</span>}
                  </p>
                </div>
              </div>

              {/* CONTACT SECTION AT BOTTOM */}
              <div className="pt-6 border-t border-gray-50">
                {!contactUnlocked ? (
                  <div className="space-y-4">
                    <div className="border border-[#CA3433]/20 rounded-xl p-6 text-center bg-red-50/10 relative overflow-hidden h-40 flex flex-col items-center justify-center">
                      <div className="absolute inset-0 backdrop-blur-[10px]" />
                      <div className="relative z-10">
                        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-3 shadow-sm border border-red-50 text-[#CA3433]">
                          <EyeOff size={24} />
                        </div>
                        <p className="font-black text-gray-900 text-sm uppercase tracking-widest">{t('services.labels.locked')}</p>
                      </div>
                    </div>
                    <button
                      onClick={handleUnlockContact}
                      className="w-full bg-gray-900 text-white font-bold py-4 rounded-full hover:bg-black transition-all flex items-center justify-center gap-2 shadow-lg active:scale-[0.98]"
                    >
                      {user ? (
                        <>
                          <Lock size={18} />
                          <span>{t('property.labels.pay')}</span>
                          <span className="bg-white/20 px-2 py-0.5 rounded-md text-[13px] font-black">₹9</span>
                          <span>{t('property.labels.toUnlock')}</span>
                        </>
                      ) : t('services.labels.loginPrompt')}
                    </button>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {service.contact_phone && (
                      <a href={`tel:${gatedData?.contact_phone || service.contact_phone}`} className="flex items-center justify-center gap-2 w-full px-5 py-3.5 rounded-full bg-brand-500 text-white font-bold hover:bg-brand-600 transition-colors text-[15px]">
                        <Phone size={18} /> {gatedData?.contact_phone || service.contact_phone}
                      </a>
                    )}
                    {service.contact_email && (
                      <a href={`mailto:${gatedData?.contact_email || service.contact_email}`} className="flex items-center justify-center gap-2 w-full px-5 py-3.5 rounded-full bg-white border border-gray-200 text-gray-900 font-bold hover:bg-gray-50 transition-colors shadow-sm text-[15px]">
                        <Mail size={18} /> {gatedData?.contact_email || t('property.sections.sendEmail')}
                      </a>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Customer Reviews (Moved to Bottom for Mobile Parity) */}
        <div className="mt-8 lg:mt-12 bg-white rounded-xl p-6 sm:p-8 shadow-[0_2px_12px_rgb(0,0,0,0.03)] border border-gray-100/50">
          <h2 className="text-2xl font-bold text-gray-900 mb-6 font-display">{t('services.reviews.header')}</h2>

          {/* Post Review */}
          {user && (profile?.role === 'user' || !profile?.role) && (
            <div className="mb-8 p-6 bg-[#F9F8F6] rounded-2xl border border-gray-100">
              <p className="font-bold text-gray-900 mb-4">{myReview ? t('services.reviews.updateFeedback') : t('services.reviews.shareExperience')}</p>
              <div className="mb-4">
                <StarRating value={reviewRating || myReview?.rating || 0} onChange={setReviewRating} />
              </div>
              <textarea
                className="w-full bg-white border border-gray-100 rounded-xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-[#CA3433]/10 resize-none"
                rows={3}
                placeholder={t('services.reviews.sharePrompt')}
                value={reviewText}
                onChange={e => setReviewText(e.target.value)}
              />
              <div className="flex justify-end mt-3">
                <Button size="sm" className="bg-[#CA3433] hover:bg-[#ac2d2c] rounded-full gap-2 px-6" loading={submittingReview} onClick={handleSubmitReview}>
                  <Send size={14} /> {myReview ? t('services.reviews.updateFeedback') : t('services.reviews.shareExperience')}
                </Button>
              </div>
            </div>
          )}

          {/* Reviews List / Slider */}
          <div className="space-y-6">
            {reviews.length > 0 ? (
              reviews.length > 1 ? (
                <Swiper
                  modules={[Autoplay, Pagination]}
                  spaceBetween={30}
                  slidesPerView={1}
                  autoplay={{ delay: 3000, disableOnInteraction: false }}
                  loop={true}
                  pagination={{ clickable: true }}
                  className="w-full pb-10"
                >
                  {reviews.map(r => (
                    <SwiperSlide key={r.id}>
                      <div className="pb-6">
                        <div className="flex justify-between items-start mb-2">
                          <div className="flex gap-3">
                            <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center font-bold text-gray-600">
                              {r.profiles?.full_name?.[0]?.toUpperCase() || 'U'}
                            </div>
                            <div>
                              <p className="font-bold text-gray-900 text-sm">{r.profiles?.full_name || t('services.reviews.anonymousUser')}</p>
                              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{new Date(r.created_at).toLocaleDateString()}</p>
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <StarRating value={r.rating} readonly />
                            {user?.id === r.reviewer_id && (
                              <button onClick={() => handleDeleteReview(r.id)} className="text-gray-300 hover:text-red-500 transition-colors">
                                <Trash2 size={14} />
                              </button>
                            )}
                          </div>
                        </div>
                        <p className="text-sm text-gray-600 leading-relaxed pl-[52px]">
                          {r.feedback}
                        </p>
                      </div>
                    </SwiperSlide>
                  ))}
                </Swiper>
              ) : (
                reviews.map(r => (
                  <div key={r.id} className="pb-6 border-b border-gray-50 last:border-0">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex gap-3">
                        <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center font-bold text-gray-600">
                          {r.profiles?.full_name?.[0]?.toUpperCase() || 'U'}
                        </div>
                        <div>
                          <p className="font-bold text-gray-900 text-sm">{r.profiles?.full_name || t('services.reviews.anonymousUser')}</p>
                          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{new Date(r.created_at).toLocaleDateString()}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <StarRating value={r.rating} readonly />
                        {user?.id === r.reviewer_id && (
                          <button onClick={() => handleDeleteReview(r.id)} className="text-gray-300 hover:text-red-500 transition-colors">
                            <Trash2 size={14} />
                          </button>
                        )}
                      </div>
                    </div>
                    <p className="text-sm text-gray-600 leading-relaxed pl-[52px]">
                      {r.feedback}
                    </p>
                  </div>
                ))
              )
            ) : (
              <div className="text-center py-10">
                <p className="text-gray-400 text-sm">{t('services.reviews.noReviewsYet')}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Gallery Modal */}
      {isGalleryOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-md">
          <button onClick={() => setIsGalleryOpen(false)} className="absolute top-6 right-6 z-50 w-12 h-12 bg-white/10 hover:bg-white/25 text-white rounded-full flex items-center justify-center transition-all">
            <X size={24} />
          </button>
          <div className="w-full h-full sm:h-[90%] max-w-6xl mx-auto flex items-center justify-center">
            <Swiper
              key={`gallery-${service.id}`}
              modules={[Navigation, Pagination]}
              initialSlide={initialSlideIndex}
              spaceBetween={20}
              slidesPerView={1}
              navigation={{ prevEl: galleryPrevEl, nextEl: galleryNextEl }}
              pagination={{ type: 'fraction', el: '.gallery-pagination' }}
              className="w-full h-full"
            >
              {images.map((img, i) => (
                <SwiperSlide key={i}>
                  <div className="w-full h-full flex items-center justify-center p-4">
                    <img src={img} alt={`Gallery view ${i + 1}`} className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" />
                  </div>
                </SwiperSlide>
              ))}
              <button ref={setGalleryPrevEl} className="absolute left-6 top-1/2 -translate-y-1/2 z-50 w-12 h-12 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-md flex items-center justify-center transition-all">
                <img src="/swipe-left.svg" alt="Prev" className="w-8 h-8 brightness-0 invert" />
              </button>
              <button ref={setGalleryNextEl} className="absolute right-6 top-1/2 -translate-y-1/2 z-50 w-12 h-12 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-md flex items-center justify-center transition-all">
                <img src="/swipe-right.svg" alt="Next" className="w-8 h-8 brightness-0 invert" />
              </button>
              <div className="gallery-pagination absolute bottom-6 left-1/2 -translate-x-1/2 z-10 text-white bg-black/50 px-4 py-1.5 rounded-full font-semibold text-sm backdrop-blur-md"></div>
            </Swiper>
          </div>
        </div>
      )}

      <div className="fixed bottom-6 right-4 sm:hidden z-40">
        <button
          onClick={() => {
            if (showScrollToTop) {
              window.scrollTo({ top: 0, behavior: 'smooth' });
            } else {
              const section = document.getElementById('contact-section');
              if (section) section.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
          }}
          className="flex flex-col items-center justify-center p-2.5 bg-gray-900 text-white rounded-xl shadow-lg border border-gray-800 active:scale-95 transition-transform"
        >
          {showScrollToTop ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
        </button>
      </div>

    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useSelector } from 'react-redux'
import {
  Plus, Trash2, Eye, CheckCircle, AlertCircle,
  Clock, Package, ArrowLeft, Zap
} from 'lucide-react'
import { useServices } from '../hooks/useServices'
import { Button } from '../components/ui/Button'
import { Skeleton } from '../components/ui/Skeleton'
import { supabase } from '../lib/supabase'
import toast from 'react-hot-toast'

const CATEGORY_CONFIG = {
  tiffin:   { label: 'Tiffin',   emoji: '🍱', color: 'bg-amber-100 text-amber-700' },
  laundry:  { label: 'Laundry',  emoji: '🧺', color: 'bg-blue-100 text-blue-700'  },
  cleaning: { label: 'Cleaning', emoji: '🧹', color: 'bg-green-100 text-green-700' },
}

const StatusBadge = ({ status }) => {
  const map = {
    verified: { icon: CheckCircle, text: 'Verified', cls: 'text-green-700 bg-green-50' },
    pending:  { icon: AlertCircle, text: 'Pending Verification', cls: 'text-amber-700 bg-amber-50' },
    rejected: { icon: Clock,       text: 'Rejected', cls: 'text-red-700 bg-red-50' },
  }
  const conf = map[status] || map.pending
  const Icon = conf.icon
  return (
    <span className={`inline-flex items-center gap-1.5 text-xs font-bold px-2.5 py-1 rounded-full ${conf.cls}`}>
      <Icon size={11} /> {conf.text}
    </span>
  )
}

export const ServiceProviderDashboard = () => {
  const navigate = useNavigate()
  const { profile } = useSelector(s => s.auth)
  const { getMyServices, deleteService, payServiceListing } = useServices()

  const [myServices, setMyServices] = useState([])
  const [loading, setLoading] = useState(true)

  const loadMyServices = async () => {
    setLoading(true)
    try {
      const data = await getMyServices()
      setMyServices(data)
    } catch {
      toast.error('Could not load your listings')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { loadMyServices() }, [])

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this listing?')) return
    try {
      await deleteService(id)
      setMyServices(v => v.filter(s => s.id !== id))
      toast.success('Listing deleted')
    } catch (err) {
      toast.error('Failed to delete listing')
    }
  }

  // ── Pay to Go Live ─────────────────────────────────────────────
  const [payingId, setPayingId] = useState(null)

  const handlePayToGoLive = async (serviceId) => {
    if (payingId) return
    setPayingId(serviceId)
    try {
      const { data: { session } } = await supabase.auth.getSession()
      const token = session?.access_token
      if (!token) { toast.error('Session expired — please log in again'); setPayingId(null); return }

      // Load Razorpay SDK dynamically
      const loadRazorpay = () => new Promise(resolve => {
        if (window.Razorpay) return resolve(true)
        const s = document.createElement('script')
        s.src = 'https://checkout.razorpay.com/v1/checkout.js'
        s.onload = () => resolve(true); s.onerror = () => resolve(false)
        document.body.appendChild(s)
      })
      if (!await loadRazorpay()) throw new Error('Razorpay SDK failed to load')

      // Create order via Edge Function
      const orderResp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-listing-order`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
          'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY
        }
      })
      if (!orderResp.ok) {
        const errJson = await orderResp.json().catch(() => ({}))
        throw new Error(errJson.error || `Order creation failed (HTTP ${orderResp.status})`)
      }
      const orderData = await orderResp.json()

      const rzp = new window.Razorpay({
        key: import.meta.env.VITE_RAZORPAY_KEY_ID,
        order_id: orderData.id,
        currency: 'INR',
        name: 'GoEazy',
        description: 'Service Listing — Go Live',
        image: '/favicon.svg',
        handler: async function(response) {
          try {
            // Mark payment as paid in DB
            await payServiceListing(serviceId)
            // Refresh the service in UI
            setMyServices(prev => prev.map(s =>
              s.id === serviceId ? { ...s, payment_status: 'paid' } : s
            ))
            toast.success('🎉 Payment successful! Your listing is now LIVE on GoEazy.')
          } catch (err) {
            toast.error('Payment recorded but DB update failed. Contact support.')
          } finally { setPayingId(null) }
        },
        prefill: { name: profile?.full_name || '', email: '' },
        theme: { color: '#CA3433' },
        modal: { ondismiss: () => setPayingId(null) }
      })
      rzp.on('payment.failed', resp => {
        toast.error('Payment failed: ' + (resp.error?.description || 'Unknown error'))
        setPayingId(null)
      })
      rzp.open()
    } catch (err) {
      toast.error(err.message || 'Could not initiate payment')
      setPayingId(null)
    }
  }

  // Stats
  const totalViews = myServices.reduce((sum, s) => sum + (s.views || 0), 0)
  const verified = myServices.filter(s => s.verification_status === 'verified').length

  return (
    <div className="pt-6 pb-20 min-h-screen bg-gray-50/50">
      <div className="w-full mx-auto px-4 sm:px-6 lg:px-8">

        {/* Back Button */}
        <button 
          onClick={() => navigate('/')} 
          className="flex items-center gap-2 text-sm text-gray-500 hover:text-gray-900 mb-6 font-medium transition-colors"
        >
          <ArrowLeft size={16} /> Back to Home
        </button>

        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8">
          <div>
            <h1 className="text-2xl font-extrabold text-gray-900">
              Service Provider Dashboard
            </h1>
            <p className="text-sm text-gray-500 mt-1">
              Welcome back, <span className="font-semibold text-gray-700">{profile?.full_name || 'Provider'}</span>
            </p>
          </div>
          <Button
            variant="primary"
            className="bg-[#CA3433] hover:bg-[#ac2d2c] rounded-xl gap-2 shadow-lg shadow-[#CA3433]/20 shrink-0"
            onClick={() => navigate('/service-provider/new')}
          >
            <Plus size={16} /> Add New Listing
          </Button>
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          {[
            { label: 'Total Listings', value: myServices.length, icon: Package, color: 'text-[#CA3433]' },
            { label: 'Total Views',    value: totalViews,         icon: Eye,     color: 'text-blue-500' },
            { label: 'Verified',       value: verified,           icon: CheckCircle, color: 'text-green-500' },
          ].map(stat => (
            <div key={stat.label} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 text-center">
              <stat.icon size={20} className={`mx-auto mb-2 ${stat.color}`} />
              <p className="text-2xl font-extrabold text-gray-900">{stat.value}</p>
              <p className="text-xs text-gray-400 font-medium mt-0.5">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* Listings */}
        {loading ? (
          <div className="space-y-4">
            {[1,2,3].map(i => <Skeleton key={i} className="h-32 w-full rounded-2xl" />)}
          </div>
        ) : myServices.length > 0 ? (
          <div className="space-y-4">
            {myServices.map(service => {
              const cat = CATEGORY_CONFIG[service.category] || {}
              return (
                <div key={service.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 flex flex-col sm:flex-row sm:items-center gap-4 hover:shadow-md transition-all">
                  {/* Category Icon */}
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-2xl shrink-0 ${cat.color || 'bg-gray-100'} border border-gray-100`}>
                    {cat.emoji}
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex flex-wrap items-center gap-2 mb-1.5">
                      <h3 className="font-bold text-gray-900 text-base leading-tight">{service.name}</h3>
                      <StatusBadge status={service.verification_status} />
                      <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${service.is_open ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-500'}`}>
                        {service.is_open ? 'Open' : 'Closed'}
                      </span>
                    </div>
                    <p className="text-sm text-gray-500">
                      {service.area}{service.city ? `, ${service.city}` : ''}{service.state ? ` · ${service.state}` : ''}
                    </p>
                    <div className="flex items-center gap-4 mt-2 text-xs text-gray-400">
                      <span className="flex items-center gap-1"><Eye size={11} /> {service.views || 0} views</span>
                      <span className="flex items-center gap-1"><Package size={11} /> {service.service_listings?.length || 0} items</span>
                      {/* LIVE = admin verified AND provider paid */}
                      {service.verification_status === 'verified' && service.payment_status === 'paid' && (
                        <span className="flex items-center gap-1 text-green-600 font-bold ml-2">
                          <CheckCircle size={11} /> LIVE
                        </span>
                      )}
                      {/* Awaiting payment after admin approval */}
                      {service.verification_status === 'verified' && service.payment_status !== 'paid' && (
                        <span className="flex items-center gap-1 text-amber-600 font-bold ml-2">
                          <AlertCircle size={11} /> Payment Pending
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-2 shrink-0">
                    {/* Pay to Go Live — shown only when verified but not yet paid */}
                    {service.verification_status === 'verified' && service.payment_status !== 'paid' && (
                      <button
                        onClick={() => handlePayToGoLive(service.id)}
                        disabled={payingId === service.id}
                        className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-gradient-to-r from-[#CA3433] to-[#E63946] text-white text-xs font-extrabold shadow-md shadow-red-200 hover:shadow-red-300 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-60 disabled:scale-100"
                        title="Pay to publish your listing"
                      >
                        {payingId === service.id ? (
                          <><svg className="animate-spin w-3.5 h-3.5" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/></svg> Processing…</>
                        ) : (
                          <><Zap size={13} /> Pay ₹199 to Go Live</>
                        )}
                      </button>
                    )}
                    <button
                      onClick={() => navigate(`/services/${service.id}`)}
                      className="p-2.5 rounded-xl border border-gray-200 text-gray-500 hover:text-[#CA3433] hover:border-[#CA3433]/30 transition-all"
                      title="Preview"
                    >
                      <Eye size={16} />
                    </button>
                    <button
                      onClick={() => handleDelete(service.id)}
                      className="p-2.5 rounded-xl border border-gray-200 text-gray-500 hover:text-red-500 hover:border-red-200 transition-all"
                      title="Delete"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              )
            })}
          </div>
        ) : (
          <div className="text-center py-24 bg-white rounded-2xl border border-gray-100">
            <div className="text-5xl mb-4">📋</div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">No listings yet</h3>
            <p className="text-sm text-gray-500 max-w-xs mx-auto">
              Create your first service listing using the button above and start connecting with customers!
            </p>
          </div>
        )}
      </div>
    </div>
  )
}

import React, { useState, useEffect } from 'react'
import { useAuth } from '../hooks/useAuth'
import { supabase } from '../lib/supabase'
import { User, Lock, Save, AlertCircle, CheckCircle2 } from 'lucide-react'

export const Settings = () => {
  const { user, profile } = useAuth()
  
  // Profile State
  const [fullName, setFullName] = useState('')
  const [phone, setPhone] = useState('')
  const [profileLoading, setProfileLoading] = useState(false)
  const [profileMessage, setProfileMessage] = useState({ type: '', text: '' })

  // Security State
  const [currentPassword, setCurrentPassword] = useState('')
  const [newPassword, setNewPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [securityLoading, setSecurityLoading] = useState(false)
  const [securityMessage, setSecurityMessage] = useState({ type: '', text: '' })

  // Populate profile info on load
  useEffect(() => {
    if (profile) {
      setFullName(profile.full_name || '')
      setPhone(profile.phone || '')
    }
  }, [profile])

  const handleProfileUpdate = async (e) => {
    e.preventDefault()
    setProfileLoading(true)
    setProfileMessage({ type: '', text: '' })

    try {
      const { error } = await supabase
        .from('profiles')
        .update({ full_name: fullName, phone: phone })
        .eq('id', user.id)

      if (error) throw error

      setProfileMessage({ type: 'success', text: 'Profile updated successfully!' })
      setTimeout(() => setProfileMessage({ type: '', text: '' }), 4000)
    } catch (error) {
      console.error('Error updating profile:', error.message)
      setProfileMessage({ type: 'error', text: 'Failed to update profile. Please try again.' })
    } finally {
      setProfileLoading(false)
    }
  }

  const handlePasswordUpdate = async (e) => {
    e.preventDefault()
    setSecurityLoading(true)
    setSecurityMessage({ type: '', text: '' })

    if (newPassword !== confirmPassword) {
      setSecurityMessage({ type: 'error', text: 'New passwords do not match' })
      setSecurityLoading(false)
      return
    }

    if (newPassword.length < 8) {
      setSecurityMessage({ type: 'error', text: 'Password must be at least 8 characters' })
      setSecurityLoading(false)
      return
    }

    try {
      // First re-authenticate to verify current password since "Require current password" might be on
      // Note: Supabase doesn't have a direct "update with current password" passing old pass via updateUser.
      // If 'Require current password' is on, we authenticate first to get a fresh session or use the signInWithPassword
      const { error: signInError } = await supabase.auth.signInWithPassword({
        email: user.email,
        password: currentPassword
      })

      if (signInError) {
        throw new Error('Incorrect current password')
      }

      // Now update the password
      const { error: updateError } = await supabase.auth.updateUser({
        password: newPassword
      })

      if (updateError) throw updateError

      setSecurityMessage({ type: 'success', text: 'Password updated successfully!' })
      setCurrentPassword('')
      setNewPassword('')
      setConfirmPassword('')
      setTimeout(() => setSecurityMessage({ type: '', text: '' }), 4000)
      
    } catch (error) {
      console.error('Error updating password:', error.message)
      setSecurityMessage({ type: 'error', text: error.message || 'Failed to update password' })
    } finally {
      setSecurityLoading(false)
    }
  }

  return (
    <div className="pt-4 pb-20 bg-gray-50 min-h-screen">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        
        <div className="mb-8">
          <h1 className="text-3xl font-display font-bold text-gray-900">Account Settings</h1>
          <p className="text-gray-500 mt-2">Manage your personal information and security preferences.</p>
        </div>

        <div className="grid gap-8">
          
          {/* Profile Section */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="px-6 py-5 border-b border-gray-100 flex items-center gap-3 bg-gray-50/50">
              <div className="w-10 h-10 rounded-xl bg-[#fff5f5] flex flex-center text-[#CA3433] justify-center items-center">
                <User size={20} />
              </div>
              <div>
                <h2 className="text-lg font-bold text-gray-900 font-display">Profile Details</h2>
                <p className="text-sm text-gray-500">Update your public facing information</p>
              </div>
            </div>
            
            <form onSubmit={handleProfileUpdate} className="p-6">
              {profileMessage.text && (
                <div className={`p-4 rounded-xl mb-6 flex gap-3 text-sm font-medium ${profileMessage.type === 'error' ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                  {profileMessage.type === 'error' ? <AlertCircle size={20} /> : <CheckCircle2 size={20} />}
                  {profileMessage.text}
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-1.5">Email Address</label>
                  <input 
                    type="email" 
                    id="email"
                    name="email"
                    autoComplete="email"
                    value={user?.email || ''} 
                    disabled 
                    className="w-full px-4 py-3 bg-gray-100 border border-transparent rounded-xl text-gray-500 font-medium cursor-not-allowed"
                  />
                  <p className="text-xs text-gray-400 mt-1.5">Email address cannot be changed currently.</p>
                </div>
                
                <div>
                  <label htmlFor="fullName" className="block text-sm font-semibold text-gray-700 mb-1.5">Full Name</label>
                  <input 
                    type="text" 
                    id="fullName"
                    name="fullName"
                    autoComplete="name"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    required
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#CA3433]/20 focus:border-[#CA3433] transition-all font-medium"
                    placeholder="E.g. John Doe"
                  />
                </div>

                <div>
                  <label htmlFor="phone" className="block text-sm font-semibold text-gray-700 mb-1.5">Phone Number</label>
                  <input 
                    type="tel" 
                    id="phone"
                    name="phone"
                    autoComplete="tel"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#CA3433]/20 focus:border-[#CA3433] transition-all font-medium"
                    placeholder="+91 XXXXX XXXXX"
                  />
                </div>
              </div>

              <div className="mt-8 flex justify-end">
                <button 
                  type="submit" 
                  disabled={profileLoading}
                  className="bg-[#CA3433] hover:bg-[#ac2d2c] disabled:bg-[#ffc9c9] text-white px-6 py-3 rounded-xl font-semibold flex items-center gap-2 transition-all active:scale-95 shadow-sm shadow-[#CA3433]/20"
                >
                  {profileLoading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Save size={18} />}
                  Save Profile
                </button>
              </div>
            </form>
          </div>

          {/* Security Section */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="px-6 py-5 border-b border-gray-100 flex items-center gap-3 bg-gray-50/50">
              <div className="w-10 h-10 rounded-xl bg-[#fff5f5] flex flex-center text-[#CA3433] justify-center items-center">
                <Lock size={20} />
              </div>
              <div>
                <h2 className="text-lg font-bold text-gray-900 font-display">Security Settings</h2>
                <p className="text-sm text-gray-500">Ensure your account is using a secure password</p>
              </div>
            </div>
            
            <form onSubmit={handlePasswordUpdate} className="p-6">
              {securityMessage.text && (
                <div className={`p-4 rounded-xl mb-6 flex gap-3 text-sm font-medium ${securityMessage.type === 'error' ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                  {securityMessage.type === 'error' ? <AlertCircle size={20} /> : <CheckCircle2 size={20} />}
                  {securityMessage.text}
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label htmlFor="currentPassword" className="block text-sm font-semibold text-gray-700 mb-1.5">Current Password</label>
                  <input 
                    type="password" 
                    id="currentPassword"
                    name="currentPassword"
                    autoComplete="current-password"
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    required
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 transition-all font-medium"
                    placeholder="Enter current password"
                  />
                  <p className="text-xs text-gray-400 mt-1.5">Required to set a new password.</p>
                </div>
                
                <div>
                  <label htmlFor="newPassword" className="block text-sm font-semibold text-gray-700 mb-1.5">New Password</label>
                  <input 
                    type="password" 
                    id="newPassword"
                    name="newPassword"
                    autoComplete="new-password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    required
                    minLength={8}
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 transition-all font-medium"
                    placeholder="At least 8 characters"
                  />
                </div>

                <div>
                  <label htmlFor="confirmPassword" className="block text-sm font-semibold text-gray-700 mb-1.5">Confirm New Password</label>
                  <input 
                    type="password" 
                    id="confirmPassword"
                    name="confirmPassword"
                    autoComplete="new-password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    required
                    minLength={8}
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-brand-500/20 focus:border-brand-500 transition-all font-medium"
                    placeholder="Enter new password again"
                  />
                </div>
              </div>

              <div className="mt-8 flex justify-end">
                <button 
                  type="submit" 
                  disabled={securityLoading}
                  className="bg-gray-900 hover:bg-gray-800 disabled:bg-gray-600 text-white px-6 py-3 rounded-xl font-semibold flex items-center gap-2 transition-all active:scale-95 shadow-sm"
                >
                  {securityLoading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Lock size={18} />}
                  Update Password
                </button>
              </div>
            </form>
          </div>

        </div>
      </div>
    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../hooks/useAuth'
import { useServices } from '../hooks/useServices'
import { LogOut, ShieldAlert, ShieldCheck, Activity, Users, Building, AlertTriangle, FileText, CheckCircle, XCircle, Eye } from 'lucide-react'
import { supabase } from '../lib/supabase'
import { Modal } from '../components/ui/Modal'
import { Button } from '../components/ui/Button'
import toast from 'react-hot-toast'

export const SystemAdmin = () => {
  const { user, role, loading, signInWithGoogle, signOut } = useAuth()
  const { getAdminPendingServices, updateServiceStatus } = useServices()
  const navigate = useNavigate()
  
  const [stats, setStats] = useState({ users: 0, properties: 0, services: 0 })
  const [loadingStats, setLoadingStats] = useState(true)

  // Service Approvals State
  const [providers, setProviders] = useState([])
  const [loadingProviders, setLoadingProviders] = useState(true)
  const [selectedDoc, setSelectedDoc] = useState(null)
  const [showApprovals, setShowApprovals] = useState(false)


  const loadStats = async () => {
    try {
      const [uRes, pRes, sRes] = await Promise.all([
        supabase.from('profiles').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('service_providers').select('*', { count: 'exact', head: true })
      ])
      
      setStats({
        users: uRes.count || 0,
        properties: pRes.count || 0,
        services: sRes.count || 0
      })
    } catch (e) {
      console.error('Error loading admin stats:', e)
    } finally {
      setLoadingStats(false)
    }
  }

  const loadProviders = async () => {
    try {
      const data = await getAdminPendingServices()
      setProviders(data)
    } catch (e) {
      console.error('Failed to load pending services', e)
    } finally {
      setLoadingProviders(false)
    }
  }

  useEffect(() => {
    // Only load stats if authorized
    if (user && role === 'admin') {
      loadStats()
      loadProviders()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, role])

  const handleAction = async (id, newStatus) => {
    const toastId = toast.loading(`Marking as ${newStatus}...`)
    try {
      await updateServiceStatus(id, newStatus)
      setProviders(prev => prev.map(p => p.id === id ? { ...p, verification_status: newStatus } : p))
      toast.success(`Service Provider ${newStatus}`, { id: toastId })
    } catch {
      toast.error('Failed to update status', { id: toastId })
    }
  }

  const handleGoogleLogin = async () => {
    // Set the return path so they land back here after Google auth
    localStorage.setItem('sb_return_to', '/systemadmin')
    await signInWithGoogle()
  }

  // Still checking session loading from auth slice
  if (loading) {
    return (
      <div className="min-h-screen bg-[#F9F8F6] flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-[#CA3433] border-t-transparent rounded-full animate-spin"></div>
      </div>
    )
  }

  // 1. Not Logged In -> Show Admin Google Login
  if (!user) {
    return (
      <div className="min-h-screen bg-[#F9F8F6] flex flex-col items-center justify-center p-4">
        <div className="max-w-md w-full bg-white border border-gray-100 rounded-3xl p-10 shadow-[0_8px_30px_rgb(0,0,0,0.04)] text-center">
          <div className="w-20 h-20 bg-red-50 rounded-full border border-red-100 flex items-center justify-center mx-auto mb-6">
            <ShieldCheck size={40} className="text-[#CA3433]" />
          </div>
          <h1 className="text-3xl font-extrabold text-gray-900 mb-3 tracking-tight font-display">System Admin</h1>
          <p className="text-gray-500 text-sm mb-8 leading-relaxed">Authorized personnel only. Please sign in with the master administrator account to view the dashboard.</p>
          
          <button 
            onClick={handleGoogleLogin}
            className="w-full flex items-center justify-center gap-3 bg-white border border-gray-200 text-gray-900 font-bold py-3.5 px-4 rounded-xl hover:bg-gray-50 transition-all shadow-sm active:scale-95"
          >
            <img src="https://www.svgrepo.com/show/475656/google-color.svg" className="w-5 h-5" alt="Google" />
            Continue with Google
          </button>
        </div>
      </div>
    )
  }

  // 2. Logged in, but WRONG EMAIL -> Access Denied!
  if (role !== 'admin') {
    return (
      <div className="min-h-screen bg-[#F9F8F6] flex flex-col items-center justify-center p-4 relative overflow-hidden">
        {/* Warning Background */}
        <div className="absolute inset-0 flex items-center justify-center opacity-5 pointer-events-none">
          <ShieldAlert size={800} className="text-red-600" />
        </div>
        
        <div className="max-w-md w-full bg-white border border-red-100 rounded-3xl p-8 relative z-10 text-center shadow-[0_8px_30px_rgb(202,52,51,0.08)]">
          <div className="w-20 h-20 bg-red-50 rounded-full border border-red-100 flex items-center justify-center mx-auto mb-6 animate-pulse">
            <AlertTriangle size={40} className="text-red-500" />
          </div>
          <h1 className="text-3xl font-extrabold text-red-600 mb-3 font-display">ACCESS DENIED</h1>
          <p className="text-gray-600 mb-8 text-sm leading-relaxed">
            The account <strong className="text-gray-900 bg-gray-100 px-2 py-1 rounded mx-1">{user.email}</strong> does not have administrator privileges.
          </p>
          
          <button
            onClick={async () => { await signOut(); navigate('/systemadmin'); }}
            className="w-full py-3.5 rounded-xl bg-gray-900 hover:bg-black text-white font-bold transition-all flex items-center justify-center gap-2 shadow-md active:scale-95"
          >
            <LogOut size={18} /> Sign Out
          </button>
          
          <button
            onClick={() => navigate('/')}
            className="w-full mt-3 py-3.5 rounded-xl border border-gray-200 text-gray-500 hover:text-gray-900 hover:bg-gray-50 font-bold transition-all active:scale-95"
          >
            Return to Homepage
          </button>
        </div>
      </div>
    )
  }

  // 3. SECURE ADMIN DASHBOARD (SUCCESS)
  return (
    <div className="min-h-screen bg-[#F9F8F6] text-gray-900">
      {/* Top Navbar */}
      <nav className="h-16 border-b border-gray-100 flex items-center justify-between px-6 bg-white/80 sticky top-0 backdrop-blur-xl z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <ShieldCheck className="text-[#CA3433]" size={24} />
          <span className="font-bold tracking-widest uppercase text-sm text-gray-900">GoEazy<span className="text-[#CA3433]">_Admin</span></span>
        </div>
        <div className="flex items-center gap-4">
          <div className="text-right hidden sm:block">
            <p className="text-xs text-gray-500 font-medium tracking-wide">Secure Session</p>
            <p className="text-sm font-bold text-gray-900">{user.email}</p>
          </div>
          <button 
            onClick={async () => { await signOut(); navigate('/'); }}
            className="w-10 h-10 rounded-full bg-red-50 hover:bg-red-100 text-red-500 flex items-center justify-center transition-all"
            title="Secure Logout"
          >
            <LogOut size={18} />
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto p-6 lg:p-10 space-y-10">
        
        {/* Welcome & Stats Section (Hidden when managing list) */}
        {!showApprovals && (
          <>
            <div>
              <h1 className="text-3xl font-extrabold font-display">System Overview</h1>
              <p className="text-gray-500 mt-1 flex items-center gap-2 font-medium">
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse outline outline-2 outline-green-100"></span>
                All systems nominal. You have database access.
              </p>
            </div>

            <div className="grid grid-cols-3 gap-3 md:gap-6">
              <div className="bg-white border border-gray-100 rounded-xl md:rounded-2xl p-3 md:p-6 relative overflow-hidden group hover:border-[#CA3433]/30 transition-colors shadow-sm flex flex-col items-center md:items-start text-center md:text-left">
                <div className="hidden md:block absolute top-0 right-0 p-6 opacity-[0.03] group-hover:opacity-10 transition-opacity">
                  <Users size={80} className="text-gray-900" />
                </div>
                <div className="w-8 h-8 md:w-12 md:h-12 rounded-lg md:rounded-xl bg-blue-50 border border-blue-100 text-blue-600 flex items-center justify-center mb-2 md:mb-4">
                  <Users className="w-4 h-4 md:w-5 md:h-5" />
                </div>
                <p className="text-[9px] md:text-xs font-bold text-gray-500 uppercase tracking-widest mb-0.5 md:mb-1">Total Users</p>
                {loadingStats ? <div className="h-6 md:h-10 w-12 md:w-24 bg-gray-100 rounded animate-pulse" /> : 
                  <p className="text-xl md:text-4xl font-black text-gray-900">{stats.users}</p>}
              </div>

              <div className="bg-white border border-gray-100 rounded-xl md:rounded-2xl p-3 md:p-6 relative overflow-hidden group hover:border-[#CA3433]/30 transition-colors shadow-sm flex flex-col items-center md:items-start text-center md:text-left">
                <div className="hidden md:block absolute top-0 right-0 p-6 opacity-[0.03] group-hover:opacity-10 transition-opacity">
                  <Building size={80} className="text-gray-900" />
                </div>
                <div className="w-8 h-8 md:w-12 md:h-12 rounded-lg md:rounded-xl bg-emerald-50 border border-emerald-100 text-emerald-600 flex items-center justify-center mb-2 md:mb-4">
                  <Building className="w-4 h-4 md:w-5 md:h-5" />
                </div>
                <p className="text-[9px] md:text-xs font-bold text-gray-500 uppercase tracking-widest mb-0.5 md:mb-1">Properties</p>
                {loadingStats ? <div className="h-6 md:h-10 w-12 md:w-24 bg-gray-100 rounded animate-pulse" /> : 
                  <p className="text-xl md:text-4xl font-black text-gray-900">{stats.properties}</p>}
              </div>

              <div className="bg-white border border-gray-100 rounded-xl md:rounded-2xl p-3 md:p-6 relative overflow-hidden group hover:border-[#CA3433]/30 transition-colors shadow-sm flex flex-col items-center md:items-start text-center md:text-left">
                <div className="hidden md:block absolute top-0 right-0 p-6 opacity-[0.03] group-hover:opacity-10 transition-opacity">
                  <Activity size={80} className="text-gray-900" />
                </div>
                <div className="w-8 h-8 md:w-12 md:h-12 rounded-lg md:rounded-xl bg-amber-50 border border-amber-100 text-amber-600 flex items-center justify-center mb-2 md:mb-4">
                  <Activity className="w-4 h-4 md:w-5 md:h-5" />
                </div>
                <p className="text-[9px] md:text-xs font-bold text-gray-500 uppercase tracking-widest mb-0.5 md:mb-1">Providers</p>
                {loadingStats ? <div className="h-6 md:h-10 w-12 md:w-24 bg-gray-100 rounded animate-pulse" /> : 
                  <p className="text-xl md:text-4xl font-black text-gray-900">{stats.services}</p>}
              </div>
            </div>
          </>
        )}

        {/* ── APPROVAL WORKFLOW ── */}
        <div>
          {!showApprovals ? (
            <div 
              className="bg-white border border-gray-100 rounded-2xl p-6 shadow-sm hover:shadow-md hover:border-[#CA3433]/30 transition-all cursor-pointer flex flex-col sm:flex-row sm:items-center justify-between gap-4 group"
              onClick={() => setShowApprovals(true)}
            >
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-red-50 text-[#CA3433] rounded-xl flex items-center justify-center shrink-0">
                  <CheckCircle size={28} />
                </div>
                <div>
                  <h2 className="text-2xl font-bold font-display text-gray-900">Provider Approvals</h2>
                  <p className="text-gray-500 text-sm mt-0.5">
                     {loadingProviders ? 'Loading pending requests...' : `Manage ${providers.length} service provider listings`}
                  </p>
                </div>
              </div>
              <Button variant="primary" className="shrink-0 bg-gray-900 hover:bg-black group-hover:bg-[#CA3433] transition-colors border-none">
                Open Management <span className="ml-1 opacity-50 group-hover:opacity-100 group-hover:translate-x-1 transition-all">→</span>
              </Button>
            </div>
          ) : (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="flex items-center justify-between mb-6 border-b border-gray-100 pb-4">
                <h2 className="text-2xl font-bold font-display text-gray-900">Provider Approvals <span className="text-[#CA3433] text-lg ml-2">({providers.length})</span></h2>
                <button onClick={() => setShowApprovals(false)} className="text-sm font-bold text-gray-500 hover:text-gray-900 px-4 py-2 rounded-xl hover:bg-gray-100 transition-colors flex items-center gap-1.5 active:scale-95">
                  <XCircle size={16} /> Close
                </button>
              </div>
              
              {loadingProviders ? (
                <div className="space-y-4">
                  {[1,2,3].map(i => <div key={i} className="h-40 bg-white border border-gray-100 shadow-sm animate-pulse rounded-2xl" />)}
                </div>
              ) : providers.length === 0 ? (
                <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-gray-300">
                  <CheckCircle className="mx-auto text-gray-300 mb-3" size={40} />
                  <p className="text-gray-500 font-medium">All caught up! No service providers waiting for approval.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {providers.map(p => (
                    <div key={p.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden hover:shadow-md transition-all duration-300 flex flex-col md:flex-row group relative">
                      
                      {/* Left: Icon/Status */}
                      <div className="p-4 md:w-48 bg-gray-50 flex flex-col items-center justify-center border-b md:border-b-0 md:border-r border-gray-100 shrink-0">
                        <div className="w-16 h-16 bg-white rounded-2xl shadow-sm border border-gray-100 flex items-center justify-center text-3xl mb-3 group-hover:scale-110 transition-transform">
                          {p.category === 'tiffin' ? '🍱' : p.category === 'laundry' ? '🧺' : '🧹'}
                        </div>
                        <span className={`px-2.5 py-1 rounded-md text-[10px] font-black uppercase tracking-wider
                          ${p.verification_status === 'pending' ? 'bg-amber-100 text-amber-700' : ''}
                          ${p.verification_status === 'verified' ? 'bg-green-100 text-green-700' : ''}
                          ${p.verification_status === 'rejected' ? 'bg-red-100 text-red-700' : ''}
                        `}>
                          {p.verification_status}
                        </span>
                      </div>

                      {/* Middle: Details */}
                      <div className="p-5 flex-1 md:pl-8">
                        <div className="flex flex-col md:flex-row md:justify-between items-start mb-2 gap-2">
                           <div>
                             <h3 className="font-bold text-xl text-gray-900 leading-tight">{p.name}</h3>
                             <p className="text-sm text-gray-500 font-medium mt-1">{p.area}, {p.city}</p>
                           </div>
                           <div className="md:text-right bg-gray-50 md:bg-transparent p-2 md:p-0 rounded-lg w-full md:w-auto mt-2 md:mt-0">
                              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest hidden md:block">Fee Status</p>
                              <p className={`text-sm ${p.payment_status === 'paid' ? 'text-green-600 font-bold' : 'text-amber-500 font-bold'}`}>
                                {p.payment_status?.toUpperCase() || 'UNPAID'} LISTING
                              </p>
                           </div>
                        </div>

                        <div className="flex flex-col md:flex-row flex-wrap gap-x-8 gap-y-2 text-sm text-gray-600 md:mt-6 mb-2">
                           <p className="flex flex-col shrink-0"><span className="text-[10px] font-bold uppercase tracking-wider text-gray-400">Owner</span> <strong className="text-gray-900">{p.profiles?.full_name}</strong></p>
                           <p className="flex flex-col min-w-0"><span className="text-[10px] font-bold uppercase tracking-wider text-gray-400">Email</span> <strong className="text-gray-900 truncate">{p.profiles?.email}</strong></p>
                           <p className="flex flex-col shrink-0"><span className="text-[10px] font-bold uppercase tracking-wider text-gray-400">Category</span> <strong className="text-gray-900 capitalize">{p.category}</strong></p>
                        </div>
                      </div>

                      {/* Right: Actions */}
                      <div className="p-4 bg-gray-50/50 border-t md:border-t-0 md:border-l border-gray-100 flex flex-row md:flex-col gap-2 shrink-0 md:w-44 items-center justify-center">
                        <button 
                          onClick={() => handleAction(p.id, 'verified')} disabled={p.verification_status === 'verified'}
                          className="flex-1 md:flex-none w-full py-2.5 px-4 text-xs font-bold tracking-wider uppercase bg-green-500 text-white rounded-xl hover:bg-green-600 disabled:opacity-50 transition-colors shadow-[0_2px_10px_rgb(34,197,94,0.2)] hover:shadow-[0_4px_12px_rgb(34,197,94,0.3)]"
                        >
                          Approve
                        </button>
                        <button 
                          onClick={() => handleAction(p.id, 'rejected')} disabled={p.verification_status === 'rejected'}
                          className="flex-1 md:flex-none w-full py-2.5 px-4 text-xs font-bold tracking-wider uppercase bg-red-50 text-red-600 rounded-xl hover:bg-red-100 hover:text-red-700 disabled:opacity-50 transition-colors"
                        >
                          Reject
                        </button>
                        {p.documents?.length > 0 && (
                          <button onClick={() => setSelectedDoc(p.documents[0])} className="flex-none basis-[30%] md:w-full py-2.5 px-2 md:px-4 text-xs font-bold text-gray-700 bg-white border border-gray-200 rounded-xl hover:bg-gray-50 flex items-center justify-center gap-1.5 transition-colors shadow-sm">
                            <FileText size={14} className="md:mr-1 shrink-0" /> <span className="hidden md:inline">Docs</span>
                          </button>
                        )}
                      </div>
                      
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Document Modal */}
        <Modal open={!!selectedDoc} onClose={() => setSelectedDoc(null)} size="lg" className="bg-white">
          <div className="p-2">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold text-gray-900 font-display">Document Viewer</h3>
            </div>
            {selectedDoc && (
              <div className="rounded-xl overflow-hidden bg-gray-50 border border-gray-200 flex items-center justify-center min-h-[400px]">
                {selectedDoc.toLowerCase().endsWith('.pdf') ? (
                  <iframe src={selectedDoc} className="w-full h-[60vh] rounded-xl" title="Document" />
                ) : (
                  <img src={selectedDoc} alt="Document" className="max-w-full max-h-[70vh] object-contain" />
                )}
              </div>
            )}
            <div className="mt-4 flex justify-end">
              <Button onClick={() => setSelectedDoc(null)} variant="secondary" className="font-bold">Close Viewer</Button>
            </div>
          </div>
        </Modal>

        {/* Database Warning */}
        <div className="bg-red-50 border border-red-100 rounded-2xl p-6 shadow-sm">
          <div className="flex items-start gap-4">
            <div className="w-10 h-10 rounded-full bg-red-100 flex flex-shrink-0 items-center justify-center">
              <ShieldAlert className="text-red-600" size={20} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-gray-900 mb-1">Restricted Root Zone</h3>
              <p className="text-gray-600 text-sm leading-relaxed max-w-3xl">
                You are viewing real production data. Direct database modifications from this panel are logged. 
                For deeper manipulation like adding new tables or managing strict security roles, kindly use the direct Supabase Admin Dashboard.
              </p>
            </div>
          </div>
        </div>

      </main>
    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { Heart, Clock, User as UserIcon, ChevronLeft, Bell, Calendar, MapPin } from 'lucide-react'
import { useAuth } from '../hooks/useAuth'
import { useProperties } from '../hooks/useProperties'
import { PropertyCard } from '../components/property/PropertyCard'
import { supabase } from '../lib/supabase'
import { MOCK_PROPERTIES } from '../utils/constants'
import { Skeleton } from '../components/ui/Skeleton'

const LoadingRow = () => (
  <div className="flex gap-5 overflow-x-auto pb-4 scrollbar-hide">
    {[1, 2, 3, 4].map(i => (
      <div key={i} className="flex-shrink-0 w-64 rounded-xl bg-white border border-gray-100 p-3 space-y-3">
        <Skeleton className="h-44 w-full rounded-xl" />
        <div className="space-y-2 px-1">
          <Skeleton className="h-5 w-4/5" />
          <Skeleton className="h-4 w-3/5" />
          <div className="pt-1 flex gap-2">
            <Skeleton className="h-3 w-1/4 rounded-full" />
            <Skeleton className="h-3 w-1/4 rounded-full" />
          </div>
        </div>
      </div>
    ))}
  </div>
)

export const UserDashboard = () => {
  const navigate = useNavigate()
  const { user, profile } = useAuth()
  const { favorites, recentlyViewed } = useProperties()
  const [favProps, setFavProps] = useState([])
  const [recentProps, setRecentProps] = useState([])
  const [loading, setLoading] = useState(true)

  const [notifications, setNotifications] = useState([])
  const [showNotifications, setShowNotifications] = useState(false)
  const [myVisits, setMyVisits] = useState([])
  const [loadingData, setLoadingData] = useState(true)

  const loadUserData = async () => {
    if (!user) return
    try {
      setLoadingData(true)
      const [notifRes, visitRes] = await Promise.all([
        supabase.from('notifications').select('*').eq('user_id', user.id).order('created_at', { ascending: false }),
        supabase.from('site_visits').select('*, property:properties(title, city)').eq('user_id', user.id).order('created_at', { ascending: false })
      ])
      
      if (!notifRes.error) setNotifications(notifRes.data || [])
      if (!visitRes.error) setMyVisits(visitRes.data || [])
    } catch (err) {
      console.error(err)
    } finally {
      setLoadingData(false)
    }
  }

  const loadProperties = async () => {
    if (!user) return
    
    // Only set loading if we don't have any data yet
    if (favProps.length === 0 && recentProps.length === 0) {
      setLoading(true)
    }

    try {
      // Fetch details for favorited ids
      if (favorites.length > 0) {
        const { data } = await supabase.from('properties').select('*').in('id', favorites)
        if (data) {
           // preserve order based on favorites array
           const ordered = favorites.map(id => data.find(p => p.id === id)).filter(Boolean)
           setFavProps(ordered)
        }
      } else {
        setFavProps([])
      }

      // Fetch details for recently viewed ids
      if (recentlyViewed.length > 0) {
        const { data } = await supabase.from('properties').select('*').in('id', recentlyViewed)
        if (data) {
          // preserve order based on recentlyViewed array
          const ordered = recentlyViewed.map(id => data.find(p => p.id === id)).filter(Boolean)
          setRecentProps(ordered)
        }
      } else {
        setRecentProps([])
      }
    } catch (err) {
      console.error('[UserDashboard] Load error:', err)
      // Fallback
      setFavProps(MOCK_PROPERTIES.filter(p => favorites.includes(p.id)))
      setRecentProps(recentlyViewed.map(id => MOCK_PROPERTIES.find(p => p.id === id)).filter(Boolean))
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (user) {
      loadProperties()
      loadUserData()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, favorites, recentlyViewed]) // React to changes in the Redux IDs

  const markAsRead = async () => {
    try {
      await supabase.from('notifications').update({ is_read: true }).eq('user_id', user.id).eq('is_read', false)
      setNotifications(prev => prev.map(n => ({...n, is_read: true})))
    } catch (err) {
      console.error(err)
    }
  }
  
  const unreadCount = notifications.filter(n => !n.is_read).length

  return (
    <div className="pt-4 pb-20 bg-gray-50 min-h-screen">
      <div className="w-full mx-auto px-4 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="flex items-center justify-between gap-4 mb-10 w-full relative">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 sm:w-16 sm:h-16 rounded-full overflow-hidden border-2 border-brand-200 bg-gray-200 shadow-sm flex-shrink-0">
              {profile ? (
                <img src={profile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.email}`} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                <Skeleton variant="circle" className="w-full h-full" />
              )}
            </div>
            <div>
              <h1 className="text-xl sm:text-2xl font-black text-gray-900 font-display leading-tight">
                {profile ? `Hi, ${profile?.full_name?.split(' ')[0] || 'User'}!` : <Skeleton className="h-8 w-32" />}
              </h1>
              <p className="text-xs sm:text-sm text-gray-500 font-medium">Pick up exactly where you left off.</p>
            </div>
          </div>

          {/* Notifications Bell */}
          <div className="relative">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className={`p-2 text-yellow-500 hover:text-yellow-600 transition-all relative cursor-pointer active:scale-95`}
            >
              <Bell size={24} className="fill-current" />
              {unreadCount > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white shadow-sm ring-2 ring-red-500/20 animate-pulse">
                  {unreadCount}
                </span>
              )}
            </button>

            {/* Notification Dropdown */}
            {showNotifications && (
               <div className="absolute top-full right-0 mt-3 w-80 sm:w-96 bg-white rounded-2xl shadow-[0_10px_40px_rgb(0,0,0,0.1)] border border-gray-100 p-4 z-50">
                 <div className="flex items-center justify-between mb-3 border-b border-gray-50 pb-2">
                   <h3 className="font-bold text-gray-900">Notifications</h3>
                   {unreadCount > 0 && <button onClick={markAsRead} className="text-xs font-bold text-[#CA3433] hover:underline px-2 py-1 rounded-md hover:bg-red-50 transition-colors">Mark all read</button>}
                 </div>
                 <div className="space-y-3 max-h-80 overflow-y-auto pr-1 customize-scrollbar">
                   {notifications.length === 0 ? (
                     <div className="text-center py-6">
                       <Bell size={24} className="mx-auto text-gray-300 mb-2" />
                       <p className="text-sm text-gray-500 font-medium">No notifications yet</p>
                     </div>
                   ) : (
                     notifications.map(n => (
                       <div key={n.id} className={`p-3 rounded-xl border transition-colors ${n.is_read ? 'bg-white border-gray-100 text-gray-500' : 'bg-[#fffcf0] border-yellow-200 text-gray-900'}`}>
                         <p className={`text-[13px] leading-relaxed ${n.is_read ? 'font-medium' : 'font-semibold'}`}>{n.message}</p>
                         <p className="text-[10px] mt-2 text-gray-400 font-bold uppercase tracking-wider">{new Date(n.created_at).toLocaleDateString()}</p>
                       </div>
                     ))
                   )}
                 </div>
               </div>
            )}
          </div>
        </div>

        {/* Saved Properties */}
        <div className="mb-12">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <Heart size={24} className="text-[#CA3433]" fill="currentColor" />
              <div>
                <h2 className="text-xl font-black text-gray-900 font-display leading-none">Saved Properties</h2>
                {!loading && <span className="text-xs font-bold text-gray-400 mt-1 block uppercase tracking-wider">{favProps.length} Items</span>}
              </div>
            </div>
            
            {favProps.length > 0 && (
              <Link 
                to="/dashboard/saved" 
                className="text-sm font-extrabold text-[#CA3433] hover:underline flex items-center gap-1 group"
              >
                View all
                <ChevronLeft size={16} className="rotate-180 group-hover:translate-x-0.5 transition-transform" />
              </Link>
            )}
          </div>

          {loading ? (
            <LoadingRow />
          ) : favProps.length === 0 ? (
            <div className="bg-white p-10 rounded-3xl border border-gray-100 text-center shadow-sm">
              <p className="text-gray-500 font-medium mb-4">You haven't saved any properties yet.</p>
              <Link to="/search" className="bg-[#fdf2f2] text-[#CA3433] px-6 py-2.5 rounded-xl font-bold hover:bg-[#fbe1e1] transition-colors inline-block">Explore listings</Link>
            </div>
          ) : (
            <div className="scroll-row px-1 -mx-1">
              {favProps.slice(0, 3).map(p => (
                <div key={p.id} className="flex-shrink-0">
                  <PropertyCard property={p} compact />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recently Viewed */}
        <div className="mb-12">
          <div className="flex items-center gap-3 mb-6">
            <Clock size={24} className="text-[#CA3433]" />
            <div>
              <h2 className="text-xl font-black text-gray-900 font-display leading-none">Recently Viewed</h2>
              <p className="text-[10px] text-gray-400 mt-1 font-medium bg-gray-50 px-2 py-0.5 rounded-md inline-block">
                Auto-clears after 72 hours
              </p>
            </div>
          </div>

          {loading ? (
            <LoadingRow />
          ) : recentProps.length === 0 ? (
            <div className="bg-white p-10 rounded-3xl border border-gray-100 text-center shadow-sm">
              <p className="text-gray-500 font-medium">No recently viewed properties.</p>
            </div>
          ) : (
            <div className="scroll-row px-1 -mx-1">
              {recentProps.map(p => (
                <div key={p.id} className="flex-shrink-0">
                  <PropertyCard property={p} compact />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* My Site Visits */}
        <div className="mb-12">
          <div className="flex items-center gap-3 mb-6">
            <Calendar size={24} className="text-orange-500" />
            <div>
              <h2 className="text-xl font-black text-gray-900 font-display leading-none">My Site Visits</h2>
              {!loadingData && <span className="text-[10px] text-gray-400 mt-1 font-medium bg-gray-50 px-2 py-0.5 rounded-md inline-block uppercase tracking-wider">
                {myVisits.length} Requests
              </span>}
            </div>
          </div>

          {loadingData ? (
             <LoadingRow />
          ) : myVisits.length === 0 ? (
             <div className="bg-white p-10 rounded-3xl border border-gray-100 text-center shadow-sm">
               <Calendar size={32} className="mx-auto text-gray-300 mb-3" />
               <p className="text-gray-500 font-medium font-display">You haven't requested any site visits.</p>
             </div>
          ) : (
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
               {myVisits.map(visit => (
                 <div key={visit.id} className="bg-white border border-gray-100 rounded-xl p-4 flex flex-col gap-3 shadow-[0_2px_10px_rgb(0,0,0,0.02)] hover:shadow-[0_4px_16px_rgb(0,0,0,0.05)] transition-all cursor-pointer" onClick={() => navigate(`/property/${visit.property_id}`)}>
                   <div className="flex justify-between items-start">
                     <div className="pr-2">
                       <h3 className="font-bold text-gray-900 line-clamp-1 text-[15px] hover:text-[#CA3433] transition-colors">{visit.property?.title || 'Property Unavaliable'}</h3>
                       <p className="text-[13px] text-gray-500 mt-1 flex items-center gap-1"><MapPin size={12} className="text-gray-400"/>{visit.property?.city || 'Unknown'}</p>
                     </div>
                     <span className={`text-[10px] font-black px-2.5 py-1 rounded-md uppercase tracking-widest border ${visit.status === 'approved' ? 'bg-green-50 text-green-700 border-green-200' : visit.status === 'declined' ? 'bg-red-50 text-red-700 border-red-200' : 'bg-yellow-50 text-yellow-700 border-yellow-200'}`}>
                       {visit.status}
                     </span>
                   </div>
                   <div className="pt-3 border-t border-gray-50 flex items-center gap-2 text-sm text-gray-700 font-semibold bg-gray-50/50 rounded-lg p-2">
                     <Calendar size={14} className="text-gray-400" />
                     {new Date(visit.visit_date).toLocaleDateString(undefined, { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' })}
                   </div>
                 </div>
               ))}
             </div>
          )}
        </div>

      </div>
    </div>
  )
}
